const COURSE_DATA = {"modules":[{"id":"m1","number":"Module 1","title":"Industry Overview and Structure"},{"id":"m2","number":"Module 2","title":"Structure of the Investment Industry"},{"id":"m3","number":"Module 3","title":"Introduction to Investment Services"},{"id":"m4","number":"Module 4","title":"Financial Planning Services and Introduction to Fintech"},{"id":"m5","number":"Module 5","title":"Investment Professionalism and Regulations"}],"sections":[{"id":"m1-overview","moduleId":"m1","label":"Overview","title":"Module overview","pages":[{"page":4,"text":"Module 1: Industry Overview and Structure\nHave you ever wondered why the financial services industry exists and how it operates?\nAt its best, the industry efficiently matches those who need money with those who have\nsavings to invest while minimizing the costs to each and facilitating financial support for\nthe most productive businesses and projects.\nIn this module, you will be introduced to the structure of the financial services industry at\nlarge, the investment industry in particular, and the types and functions of industry\nparticipants.\nBy the end of this module, you will be able to:\n• Describe the financial services industry\n• Explain how economies benefit from the existence of the investment industry\n• Explain how investors benefit from the existence of the investment industry\n• Describe the types of institutions, services, and functions of participants in the\ninvestment industry\nLet’s get started!"}]},{"id":"m1-l1","moduleId":"m1","label":"Lesson 1","title":"What Is the Financial Services Industry?","pages":[{"page":5,"text":"Lesson 1: What Is the Financial Services Industry?\nWelcome to Lesson 1 of Module 1!\nIn this lesson, you will explore the meaning and function of “savers” and “spenders” in\nthe financial services industry, as well as different forms of assets.\nBy the end of this lesson, you will be able to describe the financial services industry.\nLet’s get started!\nThe Financial Services Industry\nThe financial system links savers, who have money, to spenders, who need money.\nWithin the financial system, the financial services industry offers products and\nservices to savers and spenders and channels funds between them.\n“Savers” include individuals, households, companies, and governments that have\nmoney to invest. “Spenders” also include individuals, companies, and governments. For\nexample, individuals borrow to pay for houses, education, and other expenses.\nCompanies borrow to invest in land, buildings, and machinery. Governments borrow\nwhen their tax receipts are below their spending plans.\nTerminology\nTypically, the term “saver” characterizes those who have accumulated savings, which\nare often invested.\nWhen savers make investments, they are typically called investors and they become\nproviders of capital.\nIf their investment is a loan—that is, money that is expected to be repaid with interest—\ninvestors are often referred to as lenders.\nSimilarly, the term “spender” characterizes those who need money. When spenders\nhave received the money they need and start using it, they become users of financial\ncapital. If they are recipients of a loan, they are typically called borrowers.\nNote: There are times when the terms savers, investors, lenders, and providers of\ncapital; spenders, borrowers, and users of capital; or money, cash, funds, capital, and\nfinancial capital are used interchangeably."},{"page":6,"text":"Real and Financial Assets\nSavings can be invested in a wide range of assets. Assets are items that have value\nand include real assets and financial assets.\nReal assets are physical assets, such as land, buildings, machinery, cattle, and gold. A\ncompany’s production may depend on them, and they are sometimes referred to as\nphysical capital.\nIn contrast, financial assets\nare claims on real assets\nor possibly other financial\nassets, and they frequently\ncome in the form of a\ncertificate or legal contract.\nFor example, a share of\nstock represents ownership\nin a company. This share\ngives its owner, who is\ncalled a shareholder, a\nclaim to some portion of\nthe company’s assets and\nearnings. An investor’s\ntotal holdings of financial assets is usually called a portfolio or investment portfolio.\nFinancial assets that can be traded are called securities. The two largest categories of\nsecurities are debt and equity."},{"page":7,"text":"Learn more about debt and equity securities in Exhibit 1.\nExhibit 1: Debt and Equity Securities\nDebt Securities\nEquity Securities\nDebt securities are loans that lenders make to\nborrowers. Lenders expect the borrowers to\nrepay these loans and to make interest\npayments until the loans are repaid.\nEquity securities are also called stocks or\nshares. Shareholders (also known as\nstockholders) have ownership in a company.\nYou may already be familiar with this concept\nin personal finance because many people use\ndebt to pay for big expenses, such as cars\nand homes. Because interest payments on\nmany loans are fixed, debt securities are also\ncalled fixed-income securities.\nThe company has no obligation to repay the\nmoney that shareholders paid for their shares or\nto make regular payments to them, which are\ncalled dividends. But investors who buy shares\nexpect to earn a return by selling their shares at\na higher price than they bought them, and\npossibly by receiving dividends.\nThey are also known as bonds, and investors\nin bonds are referred to as bondholders. More\ninformation about debt securities is provided\nin Course 3, Investment Instruments.\nEquity securities are discussed further in Course\n3, Investment Instruments.\nMarkets are places where buyers meet sellers to trade. Buyers and sellers trade\nsecurities in securities markets or financial markets. How securities are issued, bought,\nand sold is explained in Course 2, Types and Functioning of Markets."},{"page":8,"text":"Overview of the Financial Services Industry\nExhibit 2: The Financial Services Industry\n\nExhibit 2 shows how the financial services industry channels funds between those who\nhave money to invest (the savers that become providers of capital) and those who need\nmoney (the spenders that become users of capital).\nWhen providers and users of capital interact, the providers usually have a direct claim\non the users. For example, if the provider owns a share of Nestlé, that gives them a right\nto certain assets and earnings generated by Nestlé, the user. This is direct finance.\nProviders and users of capital often rely on financial intermediaries to find each other\nand to channel funds between each other. This process is indirect finance because\nfinancial intermediaries sit between savers and spenders; the former do not have direct\nclaims on the latter. Financial intermediaries may also create new products and\nsecurities that depend on other assets.\nFinancial intermediaries play an important role in the financial services industry. Many\nsavers do not have the time or the expertise to identify and select individuals,\ncompanies, and governments to lend to or invest in.\nOnce savers have loaned money, they have to monitor borrowers’ behavior and\nfinancial health to ensure that they will get their money back, a task that is time-"},{"page":9,"text":"consuming and costly. Matching savers and borrowers and monitoring borrowers’\nbehavior and financial health are functions financial intermediaries can perform better\nand more cheaply than most investors can do on their own.\nLesson 1 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nGlobalBank credits Krause’s account for USD100,000 and makes a USD50,000 loan to\na new customer. This means that GlobalBank is a:\na. provider of capital\nb. user of capital\nc. both"},{"page":10,"text":"Up Next\nYou have completed Lesson 1! We hope that this lesson has helped you to expand your\nknowledge of the financial services industry, its participants, and how it works.\nYou should now be able to describe the financial services industry.\nIn the next lesson, you will explore how economies benefit from the existence of the\ninvestment industry."}]},{"id":"m1-l2","moduleId":"m1","label":"Lesson 2","title":"How Economies Benefit from the Existence of the Investment Industry","pages":[{"page":11,"text":"Lesson 2: How Economies Benefit from the Existence of the\nInvestment Industry\nWelcome to Lesson 2 of Module 1!\nIn this lesson, you will explore the way the investment industry operates within economic\nsystems, how resources are allocated in economic systems, and how the investment\nindustry fosters economic growth.\nBy the end of this lesson, you will be able to explain how economies benefit from the\nexistence of the investment industry.\nLet’s get started!\nHow Economies Benefit from the Existence of the Investment Industry\nThe investment industry is a subset of the financial services industry. It contains the\nparticipants who help savers invest their money and the participants who help spenders\nraise capital in financial markets.\nEconomic Systems\nThe investment industry and its participants do not exist in isolation; they operate within\neconomic systems that vary from country to country. Economic systems can take many\nforms, from pure capitalism with free markets to planned economies with centralized\nauthorities. A goal of most economic systems is the efficient allocation of scarce\nresources to the most productive uses.\nResources, such as labor, real assets, and financial capital, are necessary to produce\ngoods and services. Desire for goods and services is not limited, but resources are\nlimited.\nConsider this concept of scarcity by picturing individuals that have a limited budget; in\nother words, their financial capital is scarce. Should they spend their money buying food,\npaying their mortgage, purchasing a new car, or going on holiday?\nSimilarly, should a company focus its resources on an existing product or on a new one\nthat might produce a higher profit? And should governments spend money on\nhealthcare, education, defense, or infrastructure?\nBecause resources are scarce, decisions must be made regarding the allocation of\nthese resources. Participants in economic systems must address three questions:"},{"page":12,"text":"1. Which goods and services should be produced?\n2. How should the goods and services be produced?\n3. Who should receive the goods and services that are produced?\nEconomic planners prefer that scarce resources are applied to produce goods and\nservices in a way that satisfies the needs of consumers.\nCapitalism promotes private ownership and markets. Private owners produce goods and\nservices, and markets allocate them based on scarcity.\nIn a purely free market capitalist economy, there is no central authority, such as a\ngovernment, directing economic activity. Instead, individuals and companies make their\nown decisions about what goods and services to provide, and they keep the profits from\ntheir activities. When well-functioning markets support the efficient allocation of scarce\nresources, economies can grow and society benefits.\nIt is important to note that pure free market capitalism exists only in theory. In the real\nworld, governments play a role in all economic systems.\nIn some capitalistic economies, such as Western economies, the government’s role in\nbusiness may be relatively minimal.\nIn economies largely dependent on the extraction of natural resources, such as in some\nMiddle Eastern, African, and South American countries, the government may maintain\nsignificant control over key national industries.\nIn transition economies, which are moving from planned economies to market\neconomies, the government may play a significant role in business.\nHow the Investment Industry Fosters Economic Growth\nWhat role does the investment industry play in supporting the creation of goods and\nservices and, ultimately, enhancing the lives of consumers? We have considered the\ninvestment industry’s role in channeling funds between savers who have money to\ninvest and spenders who need money to finance businesses and projects.\nThe role of the investment industry in the economy includes elements such as:\n• Resource allocation: The investment industry contributes to the efficient\nallocation of resources in the economy. Without the investment industry, savers\nwould have to spend significant resources finding individuals, companies, and\ngovernments offering suitable investment opportunities. Resources would also be"},{"page":13,"text":"spent on the search for capital rather than on considering how best to use it,\nwhich would reduce efficiency. Capital that is put to more productive use fosters\neconomic growth and boosts the willingness of savers to supply funds to those\nwho need them.\n• Data collection and analysis: The investment industry helps investors collect\nand analyze data about economies and information about individuals, companies,\nand governments. It also assists investors in determining the value of real and\nfinancial assets. The types of inputs and tools used by investment industry\nparticipants are described in Course 4, Investment Inputs and Tools.\n• Investment services: Investment industry participants package investment\nopportunities so that they satisfy the needs of investors. In particular, the\ninvestment industry offers a wide range of services and products that make it\neasier for savers to invest.\n• Liquidity: The investment industry provides liquidity, which is the state of a\nmarket’s ability to transfer its products between buyers and sellers with ease.\nHighly liquid markets make it easy to buy or sell an asset without affecting the\nprice at which other people will participate in a similar transaction. Some assets,\nsuch as real estate, are inherently illiquid: selling your house will likely take some\ntime even if it is priced fairly. Other assets, such as shares that trade actively, are\nmore liquid.\nConsider an investor who holds 100 shares. She can probably sell her shares quickly\nwithout affecting the share price that others have to use for their transactions with the\nsame share. But if she owned 100,000 shares, selling them quickly could lower the\nshare price if the market is not liquid enough to be indifferent to that volume of shares.\nLiquidity is a very important aspect of well-functioning financial markets. Highly liquid\nmarkets allow investors to complete a transaction quickly and to reverse it quickly if they\nchange their minds. They give investors confidence about getting a fair price at that\nparticular moment.\nLesson 2 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it."},{"page":14,"text":"Question 1\nThe investment industry benefits the economy by providing:\nSelect all that apply.\na. Liquidity\nb. Relevant financial information\nc. Capital gains"}]},{"id":"m1-l3","moduleId":"m1","label":"Lesson 3","title":"How Investors Benefit from the Existence of the Investment Industry","pages":[{"page":15,"text":"Lesson 3: How Investors Benefit from the Existence of the Investment\nIndustry\nWelcome to Lesson 3 of Module 1!\nIn this lesson, you will explore the characteristics of a well-functioning investment\nindustry, the benefits experienced by investors, and how finance professionals can help\ninvestors.\nBy the end of this lesson, you will be able to explain how investors benefit from the\nexistence of the investment industry.\nLet’s get started!\nCharacteristics of Well-Functioning Markets\nA well-functioning investment industry depends on investor confidence. Such confidence\narises from a feeling of trust that all parties are adhering to a code of ethics and standards\nfor professional conduct, and that trust must be earned and verified consistently.\nSome of the things that work against that trust and lead to inefficient markets include the\nfollowing:\n• Unfair transactions\n• Shortfalls in integrity\n• Unreliable advice\n• Inefficient handling of trades\nIf transactions require increased analysis or due diligence, delays and costs are\nintroduced. A robust investment industry supports efficiency and benefits investors.\nOne aspect of a well-functioning investment industry is a broad range of investment\nopportunities that meet investors’ needs. Investors can invest in debt and equity\nsecurities, and they can invest in derivatives and alternative investments.\nInvestors may also choose to save by using investment vehicles that exist solely to hold\ninvestments on behalf of their shareholders, partners, or unit holders. We can think of\nunit holders as similar to shareholders, but they hold a unit in an investment vehicle that\ncould take many forms beyond a simple share or a bond, and such vehicles frequently\ninvest in shares and bonds."},{"page":16,"text":"A general name for such an arrangement is a pooled investment vehicle because\ngroups of individual investors put their money together to invest in the same customized\nfinancial arrangement that is professionally managed.\nParticipants may buy and sell real and financial assets and then package them to create\nnew assets that suit the needs of investors better than the original assets. Mortgage-backed\nsecurities are an example; they represent a claim on the money generated by a large\nnumber of mortgages that have been grouped together in a process called securitization.\nIn addition to being able to choose from many investment opportunities, investors\nbenefit from a broad range of services that support better investment decisions, such as\nthe following:\n• Financial planning\n• Information and research\n• Trading support\nHow investment industry participants assess and serve the needs of investors is\ndiscussed further in Course 5, Serving Client Needs.\nLearn more about some other characteristics of the investment industry that benefit\ninvestors in Exhibit 1.\nExhibit 1: Competitive and Liquid Markets\nCompetitive Markets\nLiquid Markets and Low Transaction Costs\nInvestors benefit when financial markets are\ncompetitive. Competitive markets lead to fair\nprices, which ensure that buyers and sellers\ntransact at a reasonable price. Markets in\ngeneral and financial markets in particular are\ncompetitive if a large number of participants\ncompete with one another without any one of\nthem having an undue influence on supply or\ndemand.\nInvestors benefit when financial markets are\nliquid and transaction costs are low. As\ncovered earlier, better liquidity lets investors\nquickly buy or sell an asset without unwanted\nprice effects.\nCompetitive markets promote production\nefficiency and keep the prices of goods and\nservices down, including investment products\nand services.\nIf we picture an active market with many\nbuyers and sellers, such as a stock exchange,\nthe costs incurred when a trade happens are\ncalled transaction costs. Because transaction\ncosts reduce the return on investments, the\nlower the transaction costs the better."},{"page":17,"text":"How Financial Professionals Help Investors\nTo make reasonable judgements about what to invest in, savers need relevant and\nreliable information about the companies and governments to which they may provide\ncapital. The data collecting and processing done by financial professionals benefits\ninvestors, and the timeliness of this information is critical because securities prices may\nchange quickly in response to new, relevant information.\nConsider a biotech company that just announced that its new wonder drug received\nregulatory approval; its share price will likely increase as investors anticipate higher\nprofits.\nA well-functioning investment industry supports society as it deals with risk, the\nuncertainty of future outcomes. Although the word “risk” can be taken as negative by\nindividuals who seek safe investments, uncertainty is unavoidable, and all investor\nchoices carry risk.\nInvestors can rely on investment industry expertise to determine whether a particular\nrisk is appropriate to their financial circumstances and justified by the expected\ninvestment return.\nIt is the financial adviser’s role to explain financial risk in terms that are understandable\nand to propose solutions for managing it.\nRisk management solutions in investment portfolios may range from complex hedging\nstrategies to simply replacing a large investment with a diversified basket of smaller\ninvestments. We will explore the concept of hedging in Course 2, Types and Functioning\nof Markets and Course 3, Investment Instruments.\nThe industry’s professionals provide advice on mitigating investment risk, and they can\nalso step in to reduce risk by providing insurance. Certain participants will be willing to\ntake on more risk by selling insurance or investments that allow others to reduce their\nrisks.\nLesson 3 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it."},{"page":18,"text":"Question 1\nInvestors benefit in many ways from a well-functioning investment industry. Which of the\nfollowing is not a benefit?\na. Access to a diverse range of investment products structured to meet investor\nneeds\nb. Availability of investment management and advisory services\nc. Low market volatility\nd. Access to financial and economic data\ne. Fair competitive pricing in liquid markets"}]},{"id":"m1-l4","moduleId":"m1","label":"Lesson 4","title":"Investment Industry Participants","pages":[{"page":19,"text":"Lesson 4: Investment Industry Participants\nWelcome to Lesson 4 of Module 1!\nIn this lesson, you will explore the roles of various professionals within the investment\nindustry through a hypothetical example. By engaging with this example, you will learn\nhow investment professionals are categorized and the key services they offer to assist\ninvestors and companies as well as interact with example personas representing key\nindustry participants.\nBy the end of this lesson, you will be able to describe the types of institutions, services,\nand functions of participants in the investment industry.\nLet’s get started!\nHow Companies and Governments Raise Capital\nAs a way of introducing investment industry participants, let’s consider the hypothetical\nfirm, Primo. This small, privately owned company has experienced steady growth over\nmultiple years and is now looking for investors to provide the capital it needs for more\naggressive expansion.\nThe financial services industry can step in to raise the money Primo needs and provide\ninvestors with ways to participate in the company’s growth. We first introduce those who\ncan help the company raise capital, and then we discuss investors and the professionals\nwho help them invest.\nPrimo wants to issue shares to raise capital. Until now, it has been a private company; it\nhas not raised money by issuing shares publicly. It wants to take the opportunity to\nbecome a public company and have its shares listed on a major stock exchange. Stock\nexchanges are organized and regulated financial markets that allow buyers and sellers\nto trade securities with each other.\nPrimo contacts an investment bank for guidance. Investment banks, also known as\nmerchant banks, are financial intermediaries that have expertise in assisting companies\nand governments with raising capital, often by organizing the sale of shares and bonds\nto the public. In the case of Primo, the equity sale is called an initial public offering, or\nIPO, because it is the first time the company will sell shares to the public.\nInvestment banks match investors with the companies and governments seeking capital.\nThe investment banks pay close attention to the types of investments that investors"},{"page":20,"text":"want so that they can design and propose securities that will suit the capital needs of the\ncompany or government and also appeal to investors. By offering securities that\ninvestors want to purchase, companies and governments can obtain capital at a lower\ncost.\nThe investment bank works with Primo to determine the price at which the new shares\nwill be issued, and that involves gauging investor interest in the company’s new shares.\nThe investment bank’s analysts, often called sell-side analysts because they work for\nthe organization selling the securities, collect and analyze information about the\ncompany and its competitors, and then prepare a report that is shared with potential\ninvestors.\nWhen Primo becomes a public company, it will have to comply both with the stock\nexchange rules where its shares are listed and with relevant national regulations. It may,\nfor instance, be required to file audited financial statements. Auditors evaluate the\ncompany’s internal controls and financial reporting to ensure that investors receive\nrelevant and reliable financial information, a key feature of well-functioning financial\nmarkets.\nHow the Investment Industry Helps Savers Invest Their Money\nPrimo may sell its shares to various investors whose needs vary. A distinction is often\nmade between individual and institutional investors; an individual investor is simply a\nperson who holds investments, whereas institutional investors are typically organizations\nthat invest either for themselves or on behalf of others.\nIndividual investors can be classified more specifically, but there is no universal\nstandard, and distinctions vary across countries, currencies, and investment firms.\nGenerally, retail investors have the least investible assets and high-net-worth\ninvestors have substantial investible assets.\nThe advice and services that individual investors receive depend on their wealth and\ninvestment knowledge, as well as on the regulatory environment. Retail investors tend to\nreceive standardized services, whereas wealthier investors often receive services\ntailored to their needs.\nInstitutional investors come in different forms, such as the following:\n• Pension plans: Pension plans hold and manage investment assets for the\nbenefit of current and future retired individuals, called beneficiaries."},{"page":21,"text":"• Endowment funds: Endowment funds are long-term funds belonging to not-for-\nprofit institutions, such as universities, colleges, schools, museums, theaters,\nopera companies, hospitals, and clinics. (In this context, “funds” refers to formal\nfinancial entities with dedicated investment criteria, rather than functioning as a\nsynonym for money or capital.)\n• Foundations: Foundations are grant-making institutions funded by financial gifts\nand by the investment income that they produce.\n• Sovereign wealth funds: Sovereign wealth funds are overseen by\ngovernments, which may gather more tax than they intend to spend by selling\nnatural resources or by financing the trade of goods and services. Such a surplus\nis usually invested, and some governments create sovereign wealth funds to\ninvest their surpluses for the benefit of their citizens.\nInstitutional investors that invest on behalf of others include investment firms and\nfinancial institutions, such as banks and insurance companies.\nInvestor Services\nDespite the differences among investors and their range of needs, many of the services\nthey require are common to all of them. Some of these services are shown in Exhibit 1.\nExhibit 1: Services Available to Investors\n\nWhen investors want to buy or sell shares, they need to find another investor who is\nwilling to buy or sell shares. Brokers and dealers are trading service providers that\nfacilitate this trading. Brokers act as agents—that is, they do not trade directly with\ninvestors but help buyers and sellers find and trade with each other."},{"page":22,"text":"In contrast, dealers act as principals—that is, they use their own accounts and their own\ncapital to trade with buyers and sellers in what is known as proprietary trading.\n(Proprietary traders will be expanded on in the Trading Services lesson in Module 3,\nIntroduction to Investment Services). They “make markets” in securities by acting as\nbuyers when investors want to sell and as sellers when investors want to buy.\nDealers often have thousands of clients, so if one client wants to sell shares at a certain\nprice, the dealer can usually identify another client who is willing to buy the shares at a\nsimilar price. Brokers and dealers provide liquidity and reduce transaction costs,\nestablished above as beneficial to investors and well-functioning markets.\nAlso providing trading services are clearing houses and settlement agents, which\nconfirm and settle trades after they have been agreed on. Custodians and depositories\nhold money and securities on behalf of their clients.\nInstitutional investors may employ analysts to review potential investments. These\nanalysts are called buy-side analysts because they work for the organization buying\nthe securities.\nTo gather data about a company and the markets in which it operates, analysts often\nrely on investment information providers, such as data vendors, or investment research\nand report providers.\nIndividual investors often do not have the time, inclination, or expertise to manage the\nentire investment process on their own, so many of them seek the help of investment\nprofessionals. Financial planners help clients to define their investment goals and\nunderstand their future needs. Investment management service providers, such as asset\nmanagers, help their clients make investment decisions or make them on their behalf to\nachieve the clients’ investment goals.\nMany investors, particularly retail investors, are willing to invest but lack the resources to\nhire an investment manager to look after their investments. Instead, these investors may\nbuy investment products offered by investment firms, banks, and insurance companies.\nAn individual planning for their retirement, for example, may need a convenient and\ninexpensive way to invest money regularly. In order to do this, they could buy shares in\na mutual fund, which is a professionally managed vehicle that invests in a range of\nsecurities. Mutual funds will be expanded on in Course 2, Types and Functioning of\nMarkets."},{"page":23,"text":"In the next section, we will explore examples of investment professionals and learn\nabout their roles, their areas of expertise, and the products they offer. We will also meet\ninvestors to learn about their needs and the products they use.\nMeet Some of the Industry Participants\nThe following hypothetical industry participants are a mix of investors and financial\nprofessionals working in the investment industry. You will continue to engage with these\ntypes of industry participants throughout the course as you expand your knowledge of\nvarious investment-related topics.\nExhibit 2 shows the investors’ goals and needs, and the roles that the financial\nprofessionals play in assisting other investors.\nExhibit 2: Investors’ Goals and Needs\nInvestor\nGoals, Needs, and Roles\n\nZhang Li is a retail investor. She earns SGD5,000 a month\nand wants to save for a deposit on an apartment in the\nsuburbs of Singapore. She also wants to save for her son’s\nuniversity education. She goes to her bank for investment\nadvice.\n\nMike Smith is a high-net-worth investor who lives in\nCalifornia. He recently sold his technology company and\nhas USD10 million to invest. He hires a financial planner to\nhelp him define his investment objectives in terms of return\nand risk.\n\nAnna Huber works for an institutional investor called Euro\nPension Fund in Frankfurt, Germany. The fund’s purpose\nis to finance the retirement of its members, and so it\ninvests the money it receives and pays out money to the\nretired members. Its asset management team, which\nHuber is a part of, devises the fund’s strategy and\nimplements it, managing a EUR50 billion portfolio invested\nin a wide range of assets."},{"page":24,"text":"Peter Robinson is an asset manager for Aus Ltd., based\nin Sydney. Aus Ltd. invests money in shares, bonds, and\nalternative investments on behalf of its clients. It works with\na data vendor to access global economic data and\nhistorical market prices, and it hires two investment\nresearch providers to keep it updated with the latest market\ndevelopments. Aus Ltd. has a broker that carries out trades\non its behalf and a custodian that safeguards clients’\nmoney and assets.\nAmina Al-Subari is a broker at Middle East Corp., based\nin Dubai. Investors, such as Aus Ltd. and Euro Pension\nFund, ask her to find and trade assets in the market.\nMiddle East Corp. can find and trade these assets on an\nexchange and also deal directly with other investors who\nwant to sell their assets.\n\nJames Armistead is with Big Bank Financial Services, a\ncustodian with offices all over the world. When an investor,\nsuch as Euro Pension Fund or Aus Ltd., buys securities,\nthe trade is confirmed by a clearing house and settlement\nagent. The custodian then holds the security on behalf of\nthe investor and makes sure a proper record is kept of the\nsecurity and its price.\nLesson 4 Knowledge Check\nThe following five questions are designed to reinforce your understanding of the\nconcepts taught in this lesson. They are ungraded, but you are strongly encouraged to\ncomplete them.\nFor each scenario, select the service provider best suited to help the industry participant\nwith their investment needs.\nQuestion 1\nPrimo Company needs to raise capital by issuing stock.\na. Buy-side analyst\nb. Investment bank\nc. Financial planner\nd. Broker/dealer\ne. Custodian"},{"page":25,"text":"Question 2\nZhang Li, a retail investor, needs to invest assets now to cover future expenses, such as\nher son’s college tuition and her retirement.\na. Investment bank\nb. Broker/dealer\nc. Custodian\nd. Buy-side analyst\ne. Financial planner\nQuestion 3\nPeter Robinson, asset manager for Aus Ltd., needs the latest market research to decide\nwhich investments to make on behalf of his clients.\na. Custodian\nb. Investment bank\nc. Broker/dealer\nd. Financial planner\ne. Buy-side analyst\nQuestion 4\nMike Smith, a high-net-worth investor, needs various advisory and trading-related services.\na. Buy-side analyst\nb. Investment bank\nc. Financial planner\nd. Broker/dealer\ne. Custodian\nQuestion 5\nAnna Huber, an investor at Euro Pension Fund, needs to have her firm’s securities held\nwith accompanying account statements for their records.\na. Investment bank\nb. Broker/dealer\nc. Custodian\nd. Buy-side analyst\ne. Financial planner"},{"page":27,"text":"Up Next\nYou have completed Lesson 4. We hope that this lesson has helped you to expand your\nknowledge of different professionals in the investment industry.\nYou should now be able to describe the types of institutions, services, and functions of\nparticipants in the investment industry."}]},{"id":"m1-summary","moduleId":"m1","label":"Summary","title":"Module 1 Summary","pages":[{"page":28,"text":"Module 1 Summary\nWithout the financial services industry, it would be difficult for money to find its way from\nsavers to individuals, companies, and governments that have businesses and projects\nto finance but insufficient capital to do so themselves.\nAt its best, the industry efficiently matches those who need money with those who have\nsavings to invest, minimizing the costs to each and allowing money to support the most\nproductive businesses and projects. The investment industry acts on behalf of savers,\nhelping them to navigate the financial markets. When the investment industry is efficient\nand trustworthy, economies and individuals benefit.\nWe began this module by defining the financial services industry and examining the\nactors within it, primarily savers and spenders, and how money in the form of assets and\nsecurities is transferred from one to the other.\n• The financial services industry exists to provide a link between\nsavers/lenders/providers of capital who have money to invest and\nspenders/borrowers/users of capital who need money.\n• Financial intermediaries go between savers and spenders.\nThe investment industry exists within an economic system. These systems differ from\ncountry to country, but the goal of most economic systems is the efficient allocation of\nscarce resources to the most productive uses.\n• The investment industry, a subset of the financial services industry, includes all\nparticipants that help savers invest their money and spenders raise capital in\nfinancial markets.\n• Financial markets and the investment industry help allocate capital, a scarce\nresource, to the most productive uses, which fosters economic growth and\nbenefits society.\n• The investment industry provides numerous benefits to the economy, including\nthe efficient allocation of scarce resources, better information about investment\nopportunities, products and services that are appropriate for providers and users\nof capital, and liquidity.\nInvestor confidence is key to fostering a well-functioning investment industry.\n• Trust is essential to the functioning of the investment industry as well as to the\nbroader financial services industry. Investor confidence arises from a feeling of\ntrust that all parties are adhering to a code of ethics and standards for"},{"page":29,"text":"professional conduct, and that trust must be earned and verified consistently. In\naddition, laws and regulations are necessary to protect investors and ensure the\nintegrity, transparency, and fairness of financial markets.\n• The benefits for investors of a well-functioning investment industry include a broad\nrange of investment products and services that meet their needs, competitive\nmarkets that provide liquidity and keep transaction costs low, timely and efficient\ndisclosure of information, and the ability to modify their risk exposures.\nCompanies and governments use investment (merchant) banks to help them raise\ncapital. Ensuring the investment industry performs at optimal levels involves a wide\nrange of participants.\nExhibit 1 shows the key investment industry participants on the investing side.\nExhibit 1: Categories and Participants with Key Characteristics\nCategories\nParticipants\nKey Characteristics\nInvestors\nRetail investors\nIndividual investors with the least amount of\ninvestible assets\nInvestors\nHigh-net-worth\ninvestors\nIndividual investors with a higher amount of\ninvestible assets\nInvestors\nInstitutional\ninvestors\nOrganizations that invest to advance their\nmission or on behalf of their clients\nInvestment\nmanagement\nservice providers\nAsset managers\nProfessionals who help their clients carry out\ninvestments to achieve their investment goals\nInvestment\ninformation\nservice providers\nBuy-side analysts\nProfessionals who collect and analyze\ninformation about companies and markets to\ninform the process of buying securities, typically\nworking for institutional investors\nInvestment\ninformation\nservice providers\nSell-side analysts\nProfessionals who collect and analyze information\nabout companies and their competitors to report\nand share with potential investors\nTrading service\nproviders\nBrokers\nProfessionals and their firms that facilitate trading\nbetween investors, acting as agents (they do not\ntrade with their clients)\nCustodial service\nproviders\nCustodians\nOrganizations that hold money and securities on\nbehalf of their clients"}]},{"id":"m2-overview","moduleId":"m2","label":"Overview","title":"Module overview","pages":[{"page":32,"text":"Module 2: Structure of the Investment Industry\nSell-side, buy-side, and front, middle, and back office are terms you may have come\nacross without much clarity on what they mean. Although the distinctions between them\nare not absolute, these terms can be helpful to understand investment firms’ relative\npositions, how their departments are categorized, and what roles are commonly held by\ntheir professionals. In Module 2, we will look at how banks, insurance companies, and\nthe wider investment industry are structured.\nBy the end of this module, you will be able to:\n● Distinguish between buy-side and sell-side firms and front-, middle-, and back-\noffice functions in the investment industry\n● Identify positions and responsibilities within firms in the investment industry\n● Identify types of financial institutions, including banks and insurance companies\nLet's get started!"}]},{"id":"m2-l1","moduleId":"m2","label":"Lesson 1","title":"Structure of Investment Firms","pages":[{"page":33,"text":"Lesson 1: Structure of Investment Firms\nWelcome to Lesson 1 of Module 2!\nIn this lesson, you will learn about how firms in the investment industry are classified\naccording to the types of services that they provide. You will also learn about the\nresponsibilities of portfolio managers.\nBy the end of this lesson, you will be able to distinguish between buy-side and sell-side\nfirms and front-, middle-, and back-office functions in the investment industry.\nLet’s get started!\nBuy-Side and Sell-Side Firms\nPractitioners classify many firms in the investment industry by whether they are on the\nsell side or the buy side.\nSell-side firms primarily provide investment products and services. They are typically\ninvestment banks, brokers, and dealers. Buy-side firms include firms that manage\nportfolios for clients, themselves, or both. This division of firms is shown in Exhibit 1.\nExhibit 1: Sell Side and Buy Side\n\nBuy-side participants purchase investment products and services from sell-side firms.\nInstitutional investors, such as pension plans, endowment funds, foundations, sovereign"},{"page":34,"text":"wealth funds, and insurance companies, are all considered to be on the buy side.\nPractitioners sometimes apply the buy-side label to consultants who provide services\nonly to buy-side firms. For example, many buy-side consultants help buy-side\ninstitutional investors evaluate investment performance.\nThe buy-side and sell-side classifications do not apply to all firms in the investment\nindustry. They are not relevant for firms providing investment information services, such\nas investment research providers, data vendors, or credit rating agencies.\nThe classifications are somewhat arbitrary and are not easily applied to many large,\nintegrated firms. Many investment banks have divisions or wholly owned subsidiaries\nthat provide investment management, which is a buy-side activity, although investment\nbanks are sell-side firms.\nFront, Middle, and Back Offices\nMost sell-side firms organize their activities along similar lines. Activities are classified by\nwhether they are in the front office, the middle office, or the back office.\nFront Office\nThe front office consists of client-facing activities that provide direct revenue generation.\nSales, marketing, and customer service are the most important front-office activities.\nSome practitioners consider trading to be a front-office activity, especially if the traders\nregularly interact with clients. Some consider research to be a front-office activity\nbecause it generates revenue from clients.\nMiddle Office\nThe middle office includes the core activities of the firm. Risk management, information\ntechnology (IT), corporate finance, portfolio management, and research are generally\nconsidered to be middle-office activities, especially if these departments do not interact\ndirectly with clients.\nIT is particularly important because most firms in the investment industry need to\nprocess and retrieve vast quantities of data efficiently and accurately. Risk management\nis also critical because it seeks to ensure that the firm and its clients are not\nintentionally, inadvertently, or fraudulently exposed to excessive risk.\nBack Office\nThe back office houses the administrative and support functions necessary to run the\nfirm. These functions include accounting, human resources, payroll, and operations."},{"page":35,"text":"For brokerage firms and banks that provide custodial services, the accounting\ndepartment is especially important because it is responsible for clearing and settling\ntrades and for keeping track of who owns what.\nSee Exhibit 2 for more information about the activities conducted in the front, middle,\nand back offices.\nExhibit 2: Front, Middle, and Back Office\n\nSome activities are not easily classified as belonging to the front, middle, or back office.\nCompliance, for example, is relevant to the entire organization because this department\nensures that the firm and its clients comply with the laws and regulations governing the\ninvestment industry.\nThe terms front office, middle office, and back office are not generally used when\ndescribing buy-side firms. But the main departments of buy-side investment\nmanagement firms are similar to those of sell-side firms. These departments include\nsales and client relations, investment research and portfolio management, trading,\ncompliance, accounting, and administration."},{"page":36,"text":"A Closer Look at Portfolio Management Activities\nJenna Egloff works as a portfolio manager at Primrose, a large bank. She manages the\nprivate wealth of 30 individual clients who have entrusted her and Primrose with full\ninvestment discretion over their assets.\nAs an investment professional directly responsible for managing client assets and for\nproviding investment advice, Jenna must act in accordance with her client’s best\ninterests. The responsibilities of a portfolio manager can vary based on institutional\nobjectives, client base, and geography. Professionals who perform these types of tasks\ncan also be referred to as investment managers, wealth managers, or advisers.\nFront-Office Activities\nAs a portfolio manager, Jenna’s front-office responsibilities encompass a variety of\nactivities:\n● Jenna meets with her clients either quarterly or semiannually to:\no check for any changes in their financial goals or circumstances,\no review past performance, and\no explain the bank’s economic outlook and current investment strategies.\n● Several of Jenna’s clients have close relationships with their tax accountants.\nWith her clients’ permission, Jenna meets once or twice a year with the\naccountants to discuss appropriate tax strategies.\n● Jenna participates in presentations made to prospective clients.\n● Jenna is periodically asked by local media to speak on investment-related topics.\nThe following information illustrates Jenna’s activities in the middle office and how she\nacts as an intermediary between her clients and the middle office.\nAt client meetings, Jenna leads discussions on portfolio risk measurement, client\nrisk tolerance, and expected returns. When appropriate, Jenna introduces\nsoftware that simulates expected returns under a variety of economic and\nfinancial scenarios.\nJenna discusses basic budgeting needs and financial planning strategies with\nclients. In complex situations, she may involve Primrose’s full-time financial\nplanner in the discussions.\nTaking into consideration her clients’ risk tolerance, their financial needs, their\ngoals, and any portfolio constraints (including taxes), Jenna constructs individual"},{"page":37,"text":"portfolios that are consistent with each client’s circumstances and Primrose’s\nstrategies for asset allocation and security selection.\nJenna is authorized to trade in her clients’ accounts. Her orders go to Primrose’s\nin-house trading desk where traders communicate with a wide range of\ninstitutional brokers. Primrose’s traders ultimately select the broker they believe is\nbest suited to match Jenna’s trade with a counterparty.\nJenna sometimes interacts directly with brokers, Primrose’s analysts, or other\nservice providers to obtain investment reports, economic forecasts, access to\nuseful databases, assistance with complex modelling, or performance\nmeasurement support.\nBack-Office Activities\nJenna does not routinely interact with the back office, but her client-facing position\nmeans she gets involved when a client is dissatisfied with a back- or middle-office\nfunction. Problems that arise may be simple, such as a misspelled family name, but they\ncan also be complex and time-consuming.\nJenna Egloff’s day-to-day activities at Primrose are just one example of how a portfolio\nmanager may interact with the front, middle, and back offices. Depending on the size of\nthe institution, the role can have different responsibilities and interface with different\ndepartments.\nLesson 1 Knowledge Check\nThe following four knowledge check questions are designed to reinforce your\nunderstanding of the concepts taught in this lesson. They are ungraded, but you are\nstrongly encouraged to complete them.\nQuestion 1\nWhich of the following are considered sell-side firms? Select all that apply.\na. Front office brokers\nb. Investment banks\nc. Sovereign funds"},{"page":38,"text":"Question 2\nCategorize the following activity as taking place in the front office, middle office, or back\noffice:\nThe account manager discusses a tax issue with a client’s tax accountant (who works\nfor another firm).\nA. Front office\nB. Middle office\nC. Back office\nQuestion 3\nCategorize the following activity as taking place in the front office, middle office, or back\noffice:\nThe firm’s risk manager prepares a quarterly assessment of the client’s exposure to risk\nfactors.\nA. Front office\nB. Middle office\nC. Back office\nQuestion 4\nCategorize the following activity as taking place in the front office, middle office, or back\noffice:\nThanks to efficient administrative and operational controls, the firm experiences very few\nlosses due to errors.\nA. Front office\nB. Middle office\nC. Back office"},{"page":39,"text":"example of buy-side firms. Brokers and investment banks primarily provide investment\nproducts and services and are examples of sell-side firms.\nQuestion 2\na. Correct. Given that the tax accountant represents the client’s interests, this would be\nconsidered a client-facing activity. It is also a marketing opportunity to demonstrate the\nfirm’s culture and capabilities to a potential source of business referrals.\nQuestion 3\na. Incorrect. Internal risk management is usually invisible to the client, so it would not\nbe in the front office, which deals with client-facing activities.\nb. Correct. Like other middle- and back-office activities, internal risk management is\nusually invisible to the client but critical to the firm’s successful operation.\nc. Incorrect. Internal risk management is usually invisible to the client but part of the\nfirm’s core activities that are in the middle office.\nQuestion 4\na. Incorrect. As with middle-office activities, back-office services are often invisible to\nclients and thus not considered front office.\nb. Incorrect. Administration and operational controls are housed in the back office.\nc. Correct. As with middle-office activities, back-office services are often invisible to\nclients but critical to the firm’s success.\nUp Next\nYou have completed Lesson 1. We hope that this lesson has helped you understand\nhow firms in the investment industry are classified according to the types of services that\nthey provide.\nYou should now be able to distinguish between buy-side and sell-side firms and front-,\nmiddle-, and back-office functions in the investment industry.\nIn the next lesson, you will explore investment staff and leadership."}]},{"id":"m2-l2","moduleId":"m2","label":"Lesson 2","title":"Investment Firm Staff and Leadership","pages":[{"page":40,"text":"Lesson 2: Investment Firm Staff and Leadership\nWelcome to Lesson 2 of Module 2!\nIn this lesson, you will explore the roles and responsibilities of staff and leaders in\ninvestment firms.\nBy the end of this lesson, you will be able to identify positions and responsibilities within\nfirms in the investment industry.\nLet’s get started!\nLeadership Titles and Responsibilities\nExhibit 1 lists the investment industry’s major leadership titles and responsibilities. The\nactual titles used by different firms may vary.\nExhibit 1: Leadership Title and Its Responsibilities\nTitle\nResponsibility\nChief Executive Officer\n(CEO)\nManages the firm\nChief Financial Officer\n(CFO)\nResponsible for arranging financing for the firm and for financial\nreporting\nChief Operating Officer\n(COO)\nResponsible for the day-to-day management of the firm\nChief Investment Officer\n(CIO)\nResponsible for any investment advice that the firm provides to\nits clients and for the investment decisions that the firm makes\nfor itself and on behalf of its clients\nHead Trader\nResponsible for all trading operations; at firms that engage in\nproprietary trading, the head trader is responsible for all\npositions, risks, and profits\nChief Accountant (also\nknown as the Finance\nController)\nResponsible for the accounting and financial systems"},{"page":41,"text":"Title\nResponsibility\nTreasurer\nResponsible for cash management, including the investment of\nreceipts and payment of invoices\nChief Risk Officer (CRO)\nResponsible for identifying and managing the risks to which the\nfirm and its clients are exposed\nChief Compliance Officer\n(CCO)\nResponsible for ensuring that the firm complies with all relevant\nlaws and regulations and handles clients appropriately\nChief Audit Executive\nLeads the internal audit department, which is responsible for\nproviding independent assessments of the firm’s operational\nsystems as well as suggestions for improvement\nGeneral Counsel\nLeads the legal department, which reviews and helps write\ncontracts, responds to or initiates lawsuits, and interprets\nregulations\nAt many firms, especially smaller ones, some people hold multiple titles and\nresponsibilities. For example, the chief investment officer of a smaller investment\nmanagement firm may also be the chief executive officer.\nInvestment Staff\nFirms in the investment industry employ many types of investment professionals,\nincluding the examples listed below:\n• Portfolio managers at buy-side firms make investment decisions for one or more\nportfolios.\n• Buy-side, sell-side, and independent research analysts produce the investment\nresearch that portfolio managers use to make decisions.\n• Research assistants help research analysts with the collection and analysis of\ninvestment information.\n• Buy-side traders interact with sell-side firms to trade orders created by their\nportfolio managers.\n• Sales traders at sell-side firms help arrange trades for their buy-side clients.\n• Sales managers handle sales for regions, products, or customer types.\n• Salespeople identify potential clients and sell them the firm’s products and\nservices.\n• Sales assistants provide administrative support to the salespeople."},{"page":42,"text":"• Client service agents and their assistants answer client questions and help clients\nopen, close, and manage their accounts.\nInvestment professionals who interact with clients are known as account executives and\naccount managers at many firms. The role of a research assistant is often the entry-level\nposition for investment professionals interested in becoming portfolio managers.\nAssistants who acquire strong expertise in a particular area, have good quantitative\nskills, and write well may be promoted to research analysts. Those analysts who\ndemonstrate excellent investment judgment often become portfolio managers. Likewise,\nsales assistants and account services assistants are entry-level positions for investment\nprofessionals interested in sales or account services.\nCompanies that provide investment management services also employ professionals\nwith expertise in accounting, information services, marketing, and legal services.\nLesson 2 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nTo fulfill orders given to them by portfolio managers, buy-side traders work with sell-side\ntraders to arrange and execute trades.\na. True\nb. False"},{"page":43,"text":"Up Next\nYou have completed Lesson 2. We hope that this lesson has helped you to expand your\nknowledge of roles and responsibilities of staff and leaders in investment firms.\nYou should now be able to identify positions and responsibilities within firms in the\ninvestment industry.\nIn the next lesson, you will explore financial institutions."}]},{"id":"m2-l3","moduleId":"m2","label":"Lesson 3","title":"Types of Financial Institutions","pages":[{"page":44,"text":"Lesson 3: Types of Financial Institutions\nWelcome to Lesson 3 of Module 2!\nIn this lesson, you will explore the different types of financial institutions and how they\nserve their clients and customers.\nBy the end of this lesson, you will be able to identify types of financial institutions,\nincluding banks and insurance companies.\nLet’s get started!\nFinancial Institutions\nFinancial institutions are types of financial intermediaries. Their role is to collect\nmoney from savers and invest it in financial assets. The two major types of financial\ninstitutions are banks and insurance companies.\nBanks\nBanks collect deposits from savers and transform them into loans to borrowers. In doing\nso, they indirectly connect savers with borrowers. The saver does not have a direct\nclaim on the borrower but rather has a claim on the bank through its deposit, the bank’s\nliability, and the bank has a claim on the borrower through the loan, the bank’s asset.\nBanks are also called deposit-taking institutions or depository institutions. In\nexchange for using the depositors’ money, banks offer transaction services, such as\ncheck writing and check cashing, and they may pay interest on deposits. Banks may\nalso raise money to make loans by issuing and selling bonds or stocks.\nBanks vary in whom they serve and how they are organized. They may have\ndifferent names in different countries.\nSavings and Loan Associations\nBuilding societies, also called savings and loan associations in some countries,\nspecialize in financing long-term residential mortgages."},{"page":45,"text":"Retail Banks\nRetail banks provide banking products and services to individuals and small businesses.\nThese products and services include current accounts (also known as checking\naccounts), savings accounts, debit and credit cards, mortgages, and personal loans.\nAn increasing number of retail banking transactions are now performed either\nelectronically via automated teller machines (ATMs) or online. Commercial banks\nprovide a wide range of products and services to companies and other financial\ninstitutions.\nCooperative and Mutual Banks\nCooperative and mutual banks are financial institutions that their members own and\nsometimes run. They may specialize in providing mortgages and loans to their\nmembers, and some offer a range of products and services similar to commercial banks.\nDepositors benefit because they earn a return in interest (from dividends), through\ntransaction services, or from appreciation on their capital without having to locate the\nborrowers, check their credit, contract with them, or manage their loans.\nIf borrowers default, banks must still pay their depositors. If the banks cannot collect\nsufficient money from their borrowers, the banks will have to use their owners’ capital to\npay their debts.\nIn many countries, depositors benefit from government-guaranteed deposit insurance.\nThis insurance gives depositors comfort that their savings are not at risk, although the\namount that is guaranteed is usually capped. The risk of losing capital should focus the\nbanks’ attention so that they do not offer credit in a careless manner that increases the\nrisk of not being paid back.\nNotable lapses occasionally occur: In the run-up to the financial crisis of 2008, investors\nand regulators were frequently unaware of the risks that banks were taking, they ignored\nthem, or the risks were beyond their control.\nIn 1982, Penn Square Bank, a small Oklahoma bank located in a shopping mall, was\nengaged in excessive risk-taking with borrowed funds.\nExhibit 1 demonstrates the consequences of excessive risk-taking with borrowed funds."},{"page":46,"text":"Exhibit 1: Circumstances\nCircumstance\nDescription\nAggressive Growth\nIn the preceding years of high oil prices, Penn Square Bank had\ngrown aggressively by making high-risk loans to companies in the\noil and gas sector. It had leveraged its lending (i.e., used borrowed\ncapital) by selling “participation” in these loans to other banks\nacross the country.\nFiling for\nBankruptcy\nOil prices peaked in 1981 and then began to decline. By July 1982,\nPenn Square Bank declared bankruptcy, leaving uninsured\ndepositors and banks that had participated in its loans with\nsometimes devastating losses.\nCascading Effect\nThe subsequent collapse in 1984 of Continental Illinois, once a top-\ntier US commercial bank, was attributed in part to losses stemming\nfrom Penn Square Bank’s failure.\nDisregarding the\nRisks\nPenn Square Bank’s aggressive lending program would not have\nbeen possible without funding from depositors and financial\ninstitutions who, in the quest for high returns, chose not to look\nclosely at the associated risks.\nInsurance Companies\nInsurance companies offset risks. To protect themselves against a potential loss,\nindividuals and companies buy insurance contracts, also known as policies, that provide\npayments in the event that losses occur. They typically pay insurance companies non-\nrefundable payments, called premiums, when they purchase insurance contracts. If the\ninsured risks materialize, the insured individual or company makes a claim to the\ninsurance company and collects the insurance settlement.\nProperty and casualty insurers cover assets, such as homes, cars, and businesses,\nwhereas legal liability and life insurers pay out sums of money upon the death or serious\ninjury of the insured person. The business of insurance, also called insurance\nunderwriting, is based on risk pooling and can be demonstrated with a simplified\nexample of life insurance.\nJon, who is 35 years old and married with two children, has determined that\nUSD1 million would cover his family’s expenses and make up for his lost future\nincome if he were to die unexpectedly."},{"page":47,"text":"Given that he does not have USD1 million, he cannot “self-insure,” so he buys life\ninsurance. Insurance companies make it possible for Jon to essentially join a pool\nof 35-year-olds with similar health profiles to benefit from risk pooling.\nWith large pools of similar individuals, insurance companies can estimate the number of\ndeaths that will occur in a given period with a high degree of confidence.\nThis ability allows the insurance company to insure the entire group while charging each\ninsured person a reasonable rate, such that the premiums paid by all the members in\nthe pool cover the payouts, also known as the settlements, for the small number of\nmembers who actually die. The premiums are also enough to cover the insurers’\nadministrative expenses and expected profits.\nOn top of the insurable risks they take on, insurance companies are exposed to price\ncompetition from other insurers, the effect of market volatility on their invested reserves,\nand other business risks, including the following examples\nFraud\nFraud occurs when people deliberately cause or falsely report losses in order to collect\ninsurance settlements\nMoral Hazard\nMoral hazard occurs when people are less careful about avoiding losses once they\nhave purchased insurance. Moral hazard leads to losses occurring more often with\ninsurance than without.\nAdverse Selection\nAdverse selection occurs when only those who are most at risk buy insurance, causing\ninsured losses to be greater than average losses.\nConsider the following example:\nJon has always been a bit adventurous, but before buying the USD1 million life insurance\npolicy, his hobbies were golf and tennis. Now that he is insured, Jon abandons those\n“safe” sports and indulges his long-standing interest in scuba diving and skydiving.\nJon’s wife expresses concern about this change in hobbies and attitude, to which he\nresponds, “Don’t worry—we’re insured!” If other members of Jon’s insurance pool"},{"page":48,"text":"experienced similar changes in attitudes about engaging in risky hobbies, the insurance\ncompany would likely have to make higher policy payouts.\nBased on the above list of insurable risks, which of these is Jon guilty of committing:\nfraud, moral hazard, or adverse selection?\nInsurers are not only financial intermediaries but are also large institutional investors.\nThey usually invest a significant portion of the premiums they receive, and they manage\nthese investments to meet the cost of future claims.\nLesson 3 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nBanks take deposits from their customers and then use the funds to make loans. From a\nbank’s perspective, deposits represent:\na. debt obligations that the bank must repay.\nb. a source of exposure to default risk.\nc. proof of financial stability."}]},{"id":"m2-summary","moduleId":"m2","label":"Summary","title":"Module 2 Summary","pages":[{"page":49,"text":"Module 2 Summary\nTo better understand the structure of the investment industry, in this module we\nexplored where investment firms sit relative to each other, how their departments are\ncategorized, and what roles are commonly held by their professionals. We first focused\non buy-side versus sell-side firms and then looked at front-, middle-, and back-office\nfunctions.\n● Sell-side firms, such as investment banks, brokers, and dealers, primarily provide\ninvestment products and services. Institutional investors, who are considered buy\nside, purchase these investment products and services from sell-side firms. Buy-\nside firms include firms that manage portfolios for clients, themselves, or both.\n● Sell-side firms organize their activities into front-, middle-, and back-office\nfunctions. The front office consists of client-facing activities that provide direct\nrevenue generation. The middle office includes the core activities of the firm, such\nas risk management, information technology (IT), corporate finance, portfolio\nmanagement, and research. The back office houses the administrative and\nsupport functions necessary to run the firm, including accounting, human\nresources, payroll, and operations.\n● The terms front, middle, and back office are not generally used when describing\nbuy-side firms, but the main departments of buy-side investment management\nfirms are similar to those of sell-side firms. These typically include such\ndepartments as sales and client relations, investment research, portfolio\nmanagement, trading, compliance, accounting, and administration.\nNext, we went a level deeper into the types of positions and associated responsibilities\nthat exist in the investment industry, from leadership roles to investment staff.\n●\nTypical titles that exist within a firm’s leadership include, but are not limited to,\nChief Executive Officer (CEO), Chief Financial Officer (CFO), Chief Investment\nOfficer (CIO), Chief Operating Officer (COO), Chief Compliance Officer (CCO),\nChief Risk Officer (CRO), Chief Audit Executive, Chief Accountant (also known as\nthe Finance Controller), Head Trader, and General Counsel. Depending on the\nfirm’s size, some people may hold multiple titles and responsibilities.\n●\nFirms in the investment industry employ many types of investment professionals,\nincluding portfolio managers, research analysts (buy-side, sell-side, and\nindependent firms), research assistants, traders (buy side and sell side), sales\nmanagers, salespeople, sales assistants, client service agents, and account\nexecutives or account managers."},{"page":50,"text":"Lastly, we looked at two main financial institutions, banks and insurance companies, to\nunderstand the role they play in the investment industry.\n● Banks collect deposits from savers and transform them into loans to borrowers,\nwhich is also why they are referred to as deposit-taking or depository institutions.\nThey may also raise money to make loans by issuing and selling bonds or stocks.\nBanks vary in whom they serve and how they are organized, and they may have\ndifferent names in different countries.\n● Insurance companies are not only financial intermediaries that connect buyers of\ninsurance contracts with providers of capital who are willing to bear the insured\nrisks, but they are also among the largest investors.\nUp Next\nNow that you understand the structure of the investment industry, in the next module,\nyou will explore the variety of services offered in the investment industry and how they fit\nwithin the larger financial services industry."}]},{"id":"m3-overview","moduleId":"m3","label":"Overview","title":"Module overview","pages":[{"page":52,"text":"Module 3: Introduction to Investment Services\nIn this module, you will be introduced to types of investment management, investment\ninformation, and trading services as well as how the investment industry fits within the\nlarger financial services industry.\nBy the end of this module, you will be able to:\n•\nDescribe investment management services\n•\nDescribe investment information services\n•\nDescribe trading services\n•\nCompare the roles of brokers and dealers\n\n•\nCompare the roles of clearinghouses and custodians\nLet's get started!"}]},{"id":"m3-l1","moduleId":"m3","label":"Lesson 1","title":"Investment Management Services","pages":[{"page":53,"text":"Lesson 1: Investment Management Services\nWelcome to Lesson 1 of Module 3!\nIn this lesson, you will learn about the different investment management services offered\nby investment managers.\nBy the end of this lesson, you will be able to describe investment management services.\nLet’s get started!\nInvestment Management Strategy\nOnce they have determined the relevant financial goals and constraints, individual and\ninstitutional investors must develop and implement a strategy for achieving their goals.\nInvestment management services are frequently required, including asset allocation,\ninvestment analysis, and portfolio construction. The range of the services investors have\naccess to depends largely on the amount of investable assets they have.\nServices for High-Net-Worth and Institutional Clients\nSome high-net-worth and institutional clients rely on investment professionals to take\ncare of the entire investment process, from identifying potential investments to\nimplementing the investments and evaluating their performance. Others use the\nservices of investment professionals selectively. Many investment professionals receive\nauthority from their clients to trade securities and assets on the client’s behalf.\nThose who have such discretionary authority are often called investment managers or\nasset managers. Depending on the context, these terms may refer to the individuals\nwho make the investment decisions or to the investment firms for which they work.\nInvestment Management Activities\nThere are three major services that investment managers provide to clients.\n• Asset allocation: Asset allocation indicates the proportion of a portfolio that should\nbe invested in available asset classes and why.  Asset classes include cash, equity\nand debt securities, and alternative investments, such as private equity, real estate,\nand commodities. The optimal allocation of equity and debt may include foreign\nand domestic securities. Investment managers assess the risk and return of\nvarious asset classes to determine the appropriate allocation."},{"page":54,"text":"• Investment analysis: Investment analysis involves determining the value of\ninvestments and identifying attractive securities and assets. An investment’s\nfundamental value, also called its intrinsic value, can be the price that investors\nwould pay for the investment if they had a complete understanding of its\ncharacteristics. A common approach to estimating the fundamental value is to\ncalculate the value of all the cash flows—such as dividends—that the investment\nwill generate in the future. (Present value and securities valuation will be covered\nin Course 3, Investment Instruments, and Course 4, Investment Inputs and Tools.)\nProvided that it fits the client’s needs, an investment is financially appealing when\nits price is below its estimated fundamental value.\n• Portfolio construction: Portfolio construction brings everything together.\nInvestment managers invest in the attractive securities and assets that they\nidentified through their investment analysis while taking into account the client’s\nrequirements and appropriate asset allocation. To do so, they must trade securities\nand assets; hold, manage, and account for these securities and assets during the\nperiods of investment; and evaluate the performance of these investments.\nThe investment managers who assist high-net-worth and institutional investors typically\nwork for investment firms. Clients pay management fees. The size of these fees typically\ndepends on the total assets under management—bigger investments usually carry\nbigger fees. Clients may also pay performance fees that depend on how well the\nportfolio has done.\nThe Portfolio Construction Process\nPlease return to the online course to view a video on this process.\nPassive and Active Investment Management\nInvestment managers typically take either a passive or an active approach to managing\nclients’ investments. Select the following accordion tabs to learn more about these two\napproaches.\nPassive Investment Managers\nPassive investment managers seek to match the return and risk of an appropriate\nbenchmark. Benchmarks include broad market indices that cover an entire asset\nclass, indices for a specific industry, and benchmarks that are customized to the\nneeds of a specific client."},{"page":55,"text":"Passive investing involves low-cost strategies because it entails buying and\nholding securities based only on their characteristics relative to a given index—\nsuch as the S&P 500 in the United States, FTSE 100 in Europe, or S&P Asia 50\nin Asia—rather than on an analysis of their future return prospects. Index\ninvesting is a common passive investment strategy and is discussed further in\nCourse 2, Types and Functioning of Markets.\nActive Investment Managers\nActive investment managers try to predict which securities and assets will\noutperform or underperform comparable securities and assets. The managers\nthen act on their opinions by buying the securities and assets that they expect to\noutperform and selling (or simply not buying) the securities and assets that they\nexpect to underperform.\nActive investment strategies are more expensive than passive investment\nstrategies because they require greater resources. So, clients hire active\nmanagers only when they believe that these managers have the skills needed to\noutperform the market after considering all the fees and commissions.\nActive investment managers analyze as much relevant information as they can to\npredict which securities and assets will outperform or underperform their peers in\nthe future. They often need the help of investment information service providers\nto gather the required data.\nServices for Retail Clients\nRetail investors do not typically require the full range of services used by high-net-worth\nand institutional investors. Retail clients frequently obtain assistance and advice on\ninvestment management—including asset allocation, investment analysis, and portfolio\nconstruction—from financial planners or brokers. Brokers are discussed in greater detail\nlater in this module.\nUnlike brokers and agents, who are paid commissions on the trades and contracts they\nrecommend, fee-only professionals do not have incentives to generate commissions by\nrecommending specific products or excessive trades. Alternatively, retail clients could\nimplement their investment plans with a passive investment in pooled investment\nvehicles, such as mutual funds, that are professionally managed. Types and\ncharacteristics of pooled investment vehicles are discussed in Course 2, Types and\nFunctioning of Markets."},{"page":56,"text":"Lesson 1 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nMatch the active and passive investment managers with their investment objective.\nInvestment Managers\na. Passive managers\nb. Active managers\nInvestment Objective\na. Seek to outperform a benchmark by analyzing the securities it tracks and\ninvesting in them selectively.\nb. Seek simply to match the return of a benchmark.\nQuestion 2\nAfter analyzing the risk and return characteristics of appropriate asset classes,\ninvestment managers construct client portfolios that reflect the relative attractiveness of\ncurrent pricing and:\na. provide maximum income.\nb. correctly represent client goals and constraints.\nc. offer downside protection."},{"page":57,"text":"Question 2\na. Incorrect. Income needs and goals are client specific. Generating maximum income\nwill not be appropriate in every case. When investment goals focus on long-term\nobjectives, maximizing income may come at the expense of reduced growth\nexpectations.\nb. Correct. Client goals and constraints determine how the analysis of asset classes\nand securities will be applied to construct the investment portfolio. Considerations\ninclude tax implications, risk appetite, income goals, funding for expenses, and planned\ngifting strategies.\nc. Incorrect. Downside protection describes limiting the potential for losses and usually\ninvolves a trade-off or opportunity cost. The appropriateness of downside protection will\nvary with market conditions and client-specific circumstances.\nUp Next\nYou have now completed Lesson 1! We hope that this lesson has helped you to expand\nyour knowledge of the different investment management services offered by investment\nmanagers.\nYou should now be able to describe investment management services.\nIn the next lesson, you will explore investment information services."}]},{"id":"m3-l2","moduleId":"m3","label":"Lesson 2","title":"Investment Information Services","pages":[{"page":58,"text":"Lesson 2: Investment Information Services\nWelcome to Lesson 2 of Module 3!\nIn this lesson, you will learn about the types of information services available to\ninvestors and the types of providers that offer these services.\nBy the end of this lesson, you will be able to describe investment information services.\nInvestment Information Services\nThe investment research, financial data, and consultancy that investors need comes\nfrom investment research providers, credit rating agencies, financial news services,\nfinancial data vendors, and investment consultants. This section introduces these firms\nand discusses their business models.\nInvestment Research Providers\nMany investors use research reports that dive deeper into the risk and return prospects\nof investments. Firms that provide research reports assemble information and opinions\nthat most investors cannot easily produce themselves. To produce the reports, these\nfirms employ data collectors, financial reporters, and expert analysts.\nResearch can be particularly valuable when it is written by industry experts who\nunderstand the financial implications of new technologies or industry regulation—for\nexample, the regulatory process a biotech company navigates to get its new drug\napproved and what that means for when the drug will go to market.\nInvestment Research Data Inputs\nResearch reports are largely based on publicly available information, and they\nsummarize text and data from lengthy disclosures, such as financial statements and\nregulatory filings, saving investors considerable time as show in Exhibit 1. Many reports\nestimate the fundamental value of securities."},{"page":59,"text":"Exhibit 1: Investment Data Research Inputs\n\nInvestors often get research reports from their brokers, who purchase them or use their\nown research departments to produce them. Brokers publish research to serve their\nclients, attract new clients, and encourage their clients to trade. Investors can also\npurchase reports from independent research firms, or the reports may be issued by\nresearch firms that were paid to produce reports by the companies.\nCredit Rating Agencies\nCredit rating agencies specialize in providing opinions about the credit quality of bonds\nand the companies or governments that issue them. A high bond credit rating indicates\nthat the credit rating agency believes that the bond issuer has a high probability of\nmaking all future payments of principal and interest when they are due.\nMost credit rating agencies do not charge investors for their ratings, although they may\ncharge them for the detailed reports on which the ratings are based. Instead, companies\npay credit rating agencies to rate their securities. They do so because having a rating\ngenerally makes a security more marketable.\nThus, an obvious conflict of interest arises because companies are likely to direct their\nbusiness to those credit rating agencies that will provide higher ratings. Equally, the"},{"page":60,"text":"credit rating agencies may give companies high ratings to secure future business. But if\nthey lose their independence, credit rating agencies run the risk that investors no longer\nrespect their ratings. Such a situation would have a negative effect not only on credit\nrating agencies but also on the general economy—particularly the investment industry\nbecause flows of capital would be reduced.\nData Vendors\nTo invest and trade successfully, most investors need current, accurate data about\ncompanies and market conditions. Many data vendors provide such data, including\nhistorical and real-time data.\nFollowing are some examples of historical data that may be of interest to investors and\nhow investors may use the data to make decisions.\nExamples and Potential Uses of Historical Data\nMacroeconomic data: Investment professionals use macroeconomic data to\nbetter understand the environment in which companies operate and compete.\nExample: Information about economic activity and international trade\nCorporate accounting data: Investment professionals use corporate accounting\ndata to assess a company’s financial performance and to estimate the\nfundamental value of its securities, such as common shares.\nExample: Information about a company’s financial statements, including the\nbalance sheet, income statement, and cash flow statement\nHistorical market data: Investment professionals use historical market data to\nevaluate the performance of their investments and to identify securities that may\noutperform in the future.\nExample: Information about past market prices and trading volumes\nNews feeds and market data feeds are important real-time data resources used by\ninvestment professionals. News feeds provide news about companies and markets that\ninvestors need to know because such news may affect the value of the companies’\nsecurities. Market data feeds provide information on market quotes, the orders investors\nsubmit for securities, and the prices and volumes of recent trades—all of which are\nhelpful for investors who want to trade.\nAccess to investment data was once very expensive and thus restricted to investment\nfirms and institutional investors. The growth of information technologies, particularly"},{"page":61,"text":"those involving the internet, has substantially reduced the cost of accessing data,\nmaking more investment data now available to the general public. In many countries,\nsome data, such as regulatory disclosures by issuers, can be freely accessed online.\nOther data are only available on a subscription basis from data vendors.\nThe widespread availability of investment data has greatly changed the investment\nindustry landscape. Although access to data used to be a key driver of investment\nprofits, investment profits now increasingly depend on the ability to analyze data.\nLesson 2 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nWhich of the following research reports have no obvious conflicts of interest?\na. Reports written by internal brokerage house analysts and provided at no charge\nto brokerage customers\nb. Research reports sold directly to investors by independent research firms\nc. Credit reports written by credit rating agencies that charge the company being\nrated for the research and rating"},{"page":62,"text":"Up Next\nYou have now completed Lesson 2. We hope that this lesson has helped you to expand\nyour knowledge of investment information services.\nYou should now be able to describe investment information services.\nIn the next lesson, you will explore trading services and the types of professionals who\nprovide those services."}]},{"id":"m3-l3","moduleId":"m3","label":"Lesson 3","title":"Trading Services","pages":[{"page":63,"text":"Lesson 3: Trading Services\nWelcome to Lesson 3 of Module 3!\nIn this lesson, you will learn about trading services, compare the roles of brokers and\ndealers, and compare the roles of clearinghouses and custodians.\nBy the end of this lesson, you will be able to:\n● Describe trading services\n● Compare the roles of brokers and dealers\n● Compare the roles of clearinghouses and custodians\nLet’s get started!\nTrading Services\nThere are various service providers that facilitate investment by holding assets for\nclients and by helping buyers and sellers of securities and investment assets arrange\ntrades with each other, including the following:\n● Brokers\n● Dealers\n● Clearinghouses\n● Settlement agents\n● Custodians\n● Depositories\nExhibit 1: The Life of a Trade\nExhibit 1 illustrates the life of a trade, from transaction to custody services."},{"page":64,"text":"The following outlines the steps in further detail.\n• Transaction\nStep 1: An investor places a sell order with Broker 1.\nStep 2: The sell order is matched with a buy order.\nNote: The broker may match the sell order with a buy order in-house. Small\norders may go to an exchange for automated matching. For example, small\ntrades in highly liquid securities are typically submitted to an exchange (such as\nthe New York Stock Exchange) for automated matching with the best buy offer.\nLarge trades in illiquid securities can affect the price. For example, large orders\nmay have to be broken into smaller quantities and traded over time.\n• Clearing and Settlement\nStep 3: The terms of the trade are confirmed and followed by a final exchange of\ncash and securities.\nNote: Time + 2 trade settlement takes place on the second day following a trade\nand is performed by a clearinghouse or a depository that also provides other\nservices. In Europe, that could be Euroclear, and in the United States, it could be\nthe Depository Trust Corp.\n• Custody Services\nStep 4: Custodians interface between asset owners and their investments and\nprovide safekeeping for securities, recordkeeping, and the distribution of\ndividends. Custody services may be provided by brokers or custodian banks. In\nthe United States, Charles Schwab and Mellon Bank are providers.\nBrokers\nBrokerage services are provided to clients who want to buy and sell securities; they\ninclude not only execution services—that is, processing buy and sell orders on behalf of\nclients—but also investment advice and research.\nBrokerage services are provided by brokerage firms or brokers. Brokers are agents who\narrange trades for their clients. They do not trade with their clients but instead search for\ntraders who are willing to take the other side of their clients’ orders. Brokers help their\nclients by reducing the cost of finding counterparties for their clients’ trades."},{"page":65,"text":"Brokers find sellers for their clients who want to buy and buyers for their clients who\nwant to sell. For highly liquid securities, the search usually only involves directing a\nclient’s order to an exchange or to a dealer. Exchanges arrange trades by matching buy\nand sell orders and are discussed in Course 2, Types and Functioning of Markets.\nDealers are discussed in the next section of this module. For less liquid securities and\nassets, brokers may spend substantial resources looking for suitable counterparties.\nFor complex trades, such as real estate transactions, for which effective negotiation is\nessential for a successful investment, brokers often serve as professional negotiators. In\nsuch transactions, skilled negotiators can increase the probability of arranging trades\nwith favorable financial terms.\nClients pay commissions to their brokers for arranging their trades. The commissions\nvary widely but typically depend on the value or quantity traded. It is worth noting that\ncommissions, particularly for stock trades, have decreased over the past 30 years,\nprimarily because of deregulation, technological progress, and increased competition\namong brokers.\nBrokers often ensure that their clients settle their trades. Such assurances are essential\nwhen exchanges arrange trades between strangers who do not have credit\narrangements with each other. For such trades, brokers guarantee the settlement of\ntheir clients’ trades.\nIndividual brokers may work, for example, at large brokerage firms or in the brokerage\narms of investment banks or at exchanges. Some brokers match clients personally.\nOthers use specialized computer systems to identify potential trades and help clients fill\ntheir orders. Many simply route their clients’ orders to exchanges or to dealers.\nFollowing is some insight into block brokers and prime brokerage.\nBlock brokers\nBlock brokers help investors who want to trade large blocks of securities. Large\nblock trades are hard to arrange because finding a counterparty willing to buy or\nsell a large number of securities is often quite difficult. Investors frequently have\nto offer price concessions—an adjustment up or down to increase\nattractiveness—to encourage other investors to do a block trade with them.\nBuying a large quantity of securities often requires paying a premium on the\nmarket price, and selling a large quantity of shares often requires offering a\ndiscount on the current market price."},{"page":66,"text":"Prime brokerage\nPrime brokerage refers to a bundle of services that brokers provide to some of\ntheir clients, usually investment professionals engaged in trading. In addition to\nthe typical brokerage services mentioned, a prime broker helps these\nprofessionals finance their positions. Although the trades may be arranged by\nother brokers, prime brokers clear and settle them. Thus, prime brokerage allows\nfor collateral requirements to be combined across all trades and thus lowers the\ncosts of financing for the trader.\nDealers\nDealers make it possible for their clients to trade without having to wait to find a\ncounterparty; they are ready to buy from clients who want to sell and ready to sell\nto clients who want to buy. In this way, they participate in their clients’ trades, in\ncontrast to brokers who do not trade with their clients but only arrange trades on\ntheir behalf.\nNext is more information about the role and responsibilities of dealers.\nDealers profit when they can buy securities for less than they sell them—that is, when\nthe price at which they buy securities (the bid price) is lower than the price at which they\nsell them (the ask price or offer price). If dealers can arrange trades simultaneously with\nbuyers and sellers, they make risk-free profits. Dealers risk losses if prices fall after they\npurchase but before they can sell or if prices rise after they sell but before they can\nrepurchase.\nDealers provide liquidity to their clients by allowing them to buy and sell when they want\nto trade. In effect, dealers match buyers and sellers who want to trade the same\ninstrument at different times and are unable to trade directly with each other. In contrast,\nbrokers must bring a buyer and a seller together to trade at the same time and place.\nDealers are often called market makers because they are willing to make a market—that\nis, trade on demand—in specified securities at their bid and ask prices.\nDealers may organize their operations within investment banks, hedge funds, or sole\nproprietorships. Almost all investment banks have dealing operations ready to buy and\nsell currencies, bonds, stocks, and derivatives if no other counterparty can be found.\nSome dealers rely on people they hire to make trading decisions, whereas others\nprimarily use computers.\nMany dealers also broker orders, and many brokers also operate like dealers as they\ninteract with their clients in a process called internalization. Internalization is when"},{"page":67,"text":"brokers fill their clients’ orders by acting as proprietary traders rather than as agents,\ntrading directly with their clients rather than arranging trades with others on behalf of\ntheir clients. Because the distinction between broker and dealer is not always clear,\nmany practitioners often use the term “broker/dealer” to refer to them.\nBroker/dealers face a conflict of interest with respect to how they fill their clients’ orders.\nWhen acting as brokers, they must seek the best price for their clients’ orders. When\nacting as dealers, however, they profit most when they sell to their clients at high prices\nor buy from their clients at low prices. This trading conflict of interest is most serious\nwhen clients allow their brokers to decide whether to trade their orders with other traders\nor to fill them internally. Consequently, when trading with broker/dealers, some clients\nmay specify that they do not want their orders to be internalized. Or they may choose to\ntrade only via brokers who do not also act as dealers.\nPrimary dealers are dealers that central banks trade with when conducting monetary\npolicy. Monetary policy refers to central bank activities that aim to influence the money\nsupply, interest rates, and credit availability in an economy. Central banks sell bonds to\nprimary dealers to decrease the money supply. The primary dealers then sell the bonds\nto their clients. Central banks buy bonds from primary dealers to increase the money\nsupply, with the primary dealers buying bonds from their clients and selling them back to\nthe central banks. Monetary policy will be covered further in Course 4, Investment Inputs\nand Tools.\nClearinghouses\nClearinghouses and settlement agents settle trades after they have been arranged as\nshow in Exhibit 2. Clearing refers to all activities that occur from the arrangement of the\ntrade to its settlement. Settlement consists of the final exchange of cash for securities."},{"page":68,"text":"Exhibit 2: Clearinghouse\n\nClearinghouses arrange for the final settlement of trades. Members of a clearinghouse\nare the only traders for whom the clearinghouse will settle trades. Thus, brokers and\ndealers who are not members of the clearinghouse must arrange to have a clearing\nmember settle their trades at the clearinghouse.\nTrades fail when the exchange of cash and ownership does not take place on the\nscheduled settlement date. There can be understandable reasons for a failed trade, but\ncorrections typically involve opportunity cost and lost time. Reliable trade settlement\nthrough a clearinghouse reduces settlement risk—the risk that counterparties will not\nsettle their trades—for both buyers and sellers. A secure clearing system increases the\nnumber of counterparties available for a trader to safely arrange a trade.\nCustodians and Depositories\nThe following provides definitions for custodians and depositories and outlines the roles\nand responsibilities of these investment participants.\nCustodians: Custodians are typically banks and brokerage firms that hold money\nand securities for safekeeping on behalf of their clients. They play an important\nrole in reducing the risk of securities being lost or stolen. Security ownership\nrecords were once commonly held as actual paper certificates in secure vaults.\nNow, securities are almost exclusively held in electronic book-entry form as\nsecure computer records, which greatly reduces the costs of clearing and settling"},{"page":69,"text":"trades. Custodians may offer other services, including trade settlement and the\ncollection of interest and dividends.\nDepositories: Depositories act not only as custodians but also as monitors. They\nare often regulated, and their responsibilities are as follows:\n• To prevent the loss of securities and payments through fraud, deficient\noversight, or natural disaster\n• To ensure securities cannot be pledged more than once by the same\nborrower as collateral for loans\n• To ensure securities that are said to be purchased are actually purchased\nHaving reputable third-party custodians and depositories hold all assets managed by an\ninvestment manager helps prevent investment fraud—for example, Ponzi schemes,\nwhich use money contributed by new investors to pay purported returns to existing\ninvestors rather than to purchase additional securities.\nMost individual investors and many smaller institutional investors hold securities in\nbrokerage accounts that provide them with custodial services. Their brokers, in turn,\nhold the securities with custodians and depositories for safekeeping.\nComparison of Providers of Trading Services\nThe following information provides a recap of the roles and responsibilities of those that\nprovide trading services:\nBrokers\n• Act as agents\n• Find sellers for clients who want to buy and buyers for clients who want to\nsell\n• Serve as professional negotiators\n• Ensure clients will settle their trades\nDealers\n• Participate in their clients’ trades\n• Allow clients to trade when they want by being ready to buy when their\nclients want to sell and to sell when their clients want to buy\n• Provide liquidity because they are willing to trade on demand\n• Are often proprietary traders"},{"page":70,"text":"Clearinghouses\n• Arrange for final settlement of trades\n• Promote liquidity by reassuring investors that their trades will be settled\nSettlement Agents\n• Arrange final exchange of cash for securities\nCustodians\n• Hold money and securities for safekeeping on behalf of clients\n• May offer other services for clients, such as trade settlement and collection\nof interest and dividends\n• Depositories\n• Act not only as custodians but also as monitors to prevent the loss of\nsecurities and fraud\n• Often are regulated\nLesson 3 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nWhich of the following services is not performed by a broker?\na. Finding counterparties for clients who want to buy or sell a security\nb. Routing small trades in highly liquid securities to an exchange\nc. Using a proprietary portfolio to transact directly with the client when it is in the\nclient’s best interest.\nQuestion 2\nWhich of the following services are not provided by custodians and depositories?\na. Safekeeping and recordkeeping\nb. Trade settlement\nc. Dividend collection\nd. Credit rating analysis"}]},{"id":"m3-summary","moduleId":"m3","label":"Summary","title":"Module 3 Summary","pages":[{"page":72,"text":"Module 3 Summary\nYou have now completed Lesson 3. We hope that this lesson has helped you\nunderstand trading services, the role of brokers and dealers, and the role of the\nclearinghouses and custodians.\nYou should now be able to describe trading services, compare the roles of brokers and\ndealers, and compare the roles of clearinghouses and custodians.\nOnce they have determined financial goals and constraints, individual and institutional\ninvestors must develop and implement a strategy for achieving their goals. Investment\nmanagement services are frequently required. The range of these services that\ninvestors have access to depends largely on the amount of investable assets they have.\n●\nSome high-net-worth and institutional investors rely on investment professionals\nto take care of the entire investment process, whereas other clients use the\nservices of investment professionals selectively.\n●\nMany investment professionals receive authority from their clients to trade\nsecurities and assets on their behalf.  The three major services that investment\nmanagers provide to clients are asset allocation, investment analysis, and\nportfolio construction. Retail investors do not typically require the full range of\nservices used by high-net-worth and institutional investors. They frequently obtain\nassistance and advice on investment management from financial planners or\nbrokers.\nThe investment research, financial data, and consultancy that investors need comes\nfrom investment research providers, credit rating agencies, financial news services,\nfinancial data vendors, and investment consultants. We looked at each of these types of\nservice providers.\n●\nMany investors and their investment managers rely on investment information\nservices to obtain investment research, financial data, and consultancy services\nthat help them make decisions. The investors use research reports that dive\ndeeper into the risk and return prospects of investments, which can be helpful\nwhen estimating the fundamental value of securities.\n●\nCredit rating agencies specialize in providing opinions about the credit quality of\nbonds and of the companies or governments that issue the bonds. A high credit\nrating indicates that the credit rating agency believes that the bond issuer has a\nhigh probability of making all future payments of principal and interest when they\nare due. Most credit rating agencies do not charge investors for their ratings,"},{"page":73,"text":"although they may charge them for the detailed reports on which the ratings are\nbased.\n●\nData vendors provide investors with current, accurate data about companies and\nmarket conditions. Market data feeds provide information on market quotes, the\norders investors submit for securities, and the prices and volumes of recent\ntrades—all of which are helpful for investors who want to trade. Access to\ninvestment data was once very expensive and thus restricted to investment firms\nand institutional investors. The growth of information technologies, particularly\nthose involving the internet, has substantially reduced the cost of accessing data\nand increased accessibility. The widespread availability of investment data has\ngreatly changed the investment industry landscape. Although access to data\nused to be a key driver of investment profits, such profits are increasingly\ndependent on the ability to analyze data.\nFinally, we examined how trading service providers—including brokers, dealers,\nclearinghouses, settlement agents, custodians, and depositories—facilitate investment\nby holding assets for clients and by helping buyers and sellers of securities and\ninvestment assets arrange trades with each other.\n●\nBrokers act as agents, arrange trades for their clients, and ensure that clients\nsettle their trades. For complex trades, they often serve as professional\nnegotiators.\n●\nDealers participate on the opposite side of their clients’ trades and are willing to\ntrade on demand, thus providing liquidity.\n●\nAfter a trade has been agreed on, clearinghouses arrange for final settlement of\nthe trade, and then settlement agents organize the final exchange of cash for\nsecurities.\n●\nCustodians and depositories hold money and securities for safekeeping on behalf\nof their clients and help prevent loss from securities investment fraud.\nUp Next\nIn the next module, you will learn how investment professionals organize their efforts to\nhelp clients meet their financial goals and explore how fintech is transforming the world\nof finance."}]},{"id":"m4-overview","moduleId":"m4","label":"Overview","title":"Module overview","pages":[{"page":74,"text":"Module 4: Financial Planning Services and Introduction to Fintech\nThe investment industry facilitates saving and investing. This module discusses how\ninvestment professionals organize their efforts to help clients meet their financial goals.\nIt also describes how the rise of AI and fintech is revolutionizing the services that\ninvestment professionals and firms provide.\nBy the end of this module, you will be able to:\n• Describe the needs served by the investment industry\n• Describe financial planning services\n• Explain fintech and the power of artificial intelligence (AI)\n• Describe how fintech applications are currently transforming the world of finance\nLet's get started!"}]},{"id":"m4-l1","moduleId":"m4","label":"Lesson 1","title":"Needs Served by the Investment Industry","pages":[{"page":75,"text":"Lesson 1: Needs Served by the Investment Industry\nWelcome to Lesson 1 of Module 4!\nIn this lesson, you will be introduced to the reasons why investors seek out investment\nprofessionals to help them invest their money (capital).\nBy the end of this lesson, you will be able to describe the needs served by the\ninvestment industry.\nLet's get started!\nHow the Investment Industry Promotes Successful Investing\nThe investment industry provides services to individual and institutional investors who\nhave money (capital) to invest. As providers of capital, most investors seek professional\nassistance with activities that they cannot, or choose not to, do themselves, including\nthe following:\n1. Determine financial goals, particularly how much money needs to be invested to\nmeet those goals\n2. Identify potential investments\n3. Evaluate the risk and return prospects of potential investments\n4. Trade securities and assets\n5. Hold, manage, and account for securities and assets during the periods of the\ninvestments\n6. Evaluate the performance of the investments\nThese steps generally require information, expertise, and systems that few individual or\ninstitutional investors possess.\nInvestors are assisted by investment professionals to take these steps, either by hiring\nthem or by investing in investment vehicles that the industry creates and oversees.\nSome investment professionals specialize in a single service, whereas others provide a\nbroad spectrum. Even though most investment firms and professionals provide multiple\nservices, for the sake of clarity, this course considers each service separately."},{"page":76,"text":"Lesson 1 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nTrue or False: Most investors seek professional assistance when they lack the\nnecessary expertise, information, and systems support to do their own financial planning\nand asset management.\na. True\nb. False"}]},{"id":"m4-l2","moduleId":"m4","label":"Lesson 2","title":"Financial Planning Services","pages":[{"page":77,"text":"Lesson 2: Financial Planning Services\nWelcome to Lesson 2 of Module 4!\nFinancial planners assist their clients in understanding their financial needs, the risks\ninvolved, and the difference between preserving their capital and growing it at the same\ntime.\nBy the end of this lesson, you will be able to describe financial planning services.\nLet’s get started!\nFinancial Planning Services\nInvestment clients often need advice to set their financial goals and determine how\nmuch money they should save. Some clients also need advice about how much money\nthey can spend on expenses while still preserving their capital.  Financial planners help\ntheir clients understand their current and future financial needs, the risks they will face\nwhen investing, their ability to tolerate risks, and their preferences for capital\npreservation versus capital growth. This process is described further in Course 5,\nServing Client Needs.\nFinancial planners create savings and investment plans that are appropriate for their\nclients. The plans often require a complex analysis of many moving pieces:\n1. The expected risk and rates of return for various securities and assets\n2. The client’s capacity and tolerance for bearing risk\n3. Tax considerations\n4. Forecasts of expenses\nExpenses are often particularly difficult to forecast. They may depend on inflation and, in\nthe case of retirement, uncertain life expectancy and health care costs. Analysis of\npensions and health care is typically done by actuaries, who are professionals that\nspecialize in assessing insurance risks using statistical models.\nMany pension funds employ financial planners to help their beneficiaries make better\nsavings decisions. Some employers contract with financial planners to make their\nservices available to their employees. Increasingly, financial planners provide advice\nonline to retail investors.\nOrganizations may require financial planning to meet their investment objectives. For\nexample, foundations and endowment funds, which are not-for-profit institutions with"},{"page":78,"text":"long-term investment objectives, hire financial planners to create payout policies.\nPayout policies specify how much money can be taken out of long-term funds for current\nspending.\nThe payout policies depend on the assumptions the financial planners make about\ninvestment returns. Assuming high future returns allows for higher spending, but if these\nassumptions are too optimistic, payouts will exceed the returns, and spending will have\nto be curbed to preserve the fund’s capital.\nLesson 2 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nWhich of the following inputs do financial planners use to help investors anticipate future\nexpenditures and develop appropriate saving and investment strategies that reinforce\nfinancial security in retirement?\nSelect all that apply.\na. Life expectancy\nb. Educational attainment\nc. Inflation\nd. Investment returns"}]},{"id":"m4-l3","moduleId":"m4","label":"Lesson 3","title":"Introduction to Fintech","pages":[{"page":79,"text":"Lesson 3: Introduction to Fintech\nWelcome to Lesson 3 of Module 4!\nFintech refers to technology-driven innovation in the financial services industry. And as a\npart of fintech, artificial intelligence speeds up tasks, such as investment advice,\nfinancial planning, business lending, and payments.\nBy the end of this lesson, you will be able to explain fintech and the power of artificial\nintelligence (AI).\nLet’s get started!\nFintech\nIn its broadest sense, fintech refers to technology-driven innovation in the financial\nservices industry. Early forms of fintech included the automation of routine functions,\nsuch as data processing (as distinct from data analysis), but the focus now is on\ntechnological innovations that impact the design and delivery of financial services.\nFintech can also refer to companies—often new, startup companies—involved in\ndeveloping these technologies and to the wider sector these companies are a part of.\nThese innovations provide a real challenge to traditional business models and\nestablished financial services providers.\nFintech has advanced into decision-making applications based on complex machine\nlearning algorithms, where computer programs are able to “learn” how to complete tasks\nover time. In some applications, advanced computer systems perform tasks at levels far\nsurpassing human capability. Fintech has changed the financial services industry in\nmany ways, giving rise to new systems for investment advice, financial planning,\nbusiness lending, and payments.\nThere is often no clean separation of fintech components. AI is used to develop\nalgorithmic trading software; robo-advisors, in turn, are supported by automated trading\nplatforms that can seek out the best liquidity at the best price.\nArtificial Intelligence (AI)\nWhat do we mean by artificial intelligence? During its early development, AI typically\nreferenced the ability of machines to solve problems and to display cognitive skills more\nclosely associated with humans than machines. Today, it is generally taken to mean"},{"page":80,"text":"machines acting within the context of the intelligence they have iteratively improved as\nthey collect information, which implies the ability to learn and adapt.\nLearn more about how AI can be used to elevate the efficiency of various financial\nprocesses next.\nCredit Assessment\nAI assesses whether someone should be offered a loan and suggests the best\ntype based on the client’s circumstances. This is particularly important when it\ncomes to supporting the historically unbanked and underbanked. The use of AI in\nthis context can reduce losses from bad loans by approximately 20%.\nFraud Detection\nThe automated calls that cardholders receive from their credit card company\nabout unusual activity are triggered by an AI analysis of their spending habits.\nPreventing cyber fraud and identifying money laundering are important AI\napplications.\nRisk Management\nAI is used to analyze unstructured data (i.e., information that either does not have\na pre-defined data model or is not organized in a pre-defined manner) and to\nidentify trends and risk signals.\nTrading\nAlgorithmic trading programs often utilize AI. Some investment funds are totally\nautomated, with AI making the trading decisions and executing the trades.\nPersonalized Banking\nAI is seen in the form of virtual assistants and chatbots that use natural language\nprocessing (NLP) to suggest suitable financial recommendations and support 24-\nhour customer service.\nProcess Automation\nAI can automate many repetitive, mundane, or time-consuming tasks, such as\nreviewing loan applications, in which human errors are common."},{"page":81,"text":"Ethics and AI\nWith AI-based process automation reducing human error, it can reduce human\nbias. But is it correct to say that AI has no bias? Moreover, what are the ethical\nquestions that arise from the use of AI?\nThe ethical issues that arise from the use of AI include the following:\n• Bias: AI programs are built on data, and it is possible, although likely not\nintentional, that the data itself reflects biases. An AI program developed to predict\nwhich patients require additional medical care was found to have a racial bias.\nThe program itself did not consider race, but the underlying data that was used to\nbuild and train the AI program did have a racial bias.\n• Accountability: Where does accountability lie if a decision made by AI results in\ndamage or personal injury? This problem is very real in the context of self-driving\ncars. If a car being driven in a hands-off mode is involved in an accident, who is\nto blame—the driver, the manufacturer, or the software designer?\n• Transparency: If an AI program turns down a loan application and the applicant\nwants to know why, the lender’s response may be something along the lines of,\n“The computer said so.” Finding out why an algorithm comes to a particular\nconclusion can be difficult.\nLesson 3 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nWhich of the following are served by fintech or AI applications?\nSelect all that apply.\na. Automation of routine functions\nb. Portfolio construction\nc. Loan credit analysis\nd. Implementation of trading strategies"}]},{"id":"m4-l4","moduleId":"m4","label":"Lesson 4","title":"Fintech Applications","pages":[{"page":83,"text":"Lesson 4: Fintech Applications\nWelcome to Lesson 4 of Module 4!\nLarge amounts of personal data are analyzed daily by analytical tools to establish client\nbehavior, which is integrated into the decision-making process. There are different types\nof intelligent automation applications, such as fintech applications,\nautomated/algorithmic trading, automated advice and robo-advisors, mobile banking,\ndecentralized finance (DeFi), and crypto assets. We will look at each of these to get a\nbetter understanding of how they are transforming the world of finance.\nBy the end of this lesson, you will be able to describe how fintech applications are\ncurrently transforming the world of finance.\nLet's get started!\nAnalysis of Large Datasets\nWhy do social media companies provide “free” services? The answer is that they are not\nreally free. We pay for them by providing large amounts of personal data, which includes\ndata about our shopping habits, our likes and dislikes, where we go, and how we get\nthere.\nFinancial analysts no longer limit themselves to studying financial statements, economic\nreports, and market indicators. They also dive deeply into the stories told by non-\ntraditional data from non-traditional sources. These sources produce a huge amount of\ndata that must be integrated into the decision-making process, a task that fintech\nsupports through the development of analytical tools.\nBig Data\nBig data (or alternative data) encompasses data generated by financial markets,\nbusinesses, governments, individuals, sensors, and the “Internet of Things.”\nBig data has exploded over the past decade, especially in the form of unstructured data\ngenerated from social media, email and texts, web traffic, online news sites, and other\nelectronic information. Investment practitioners are increasingly using big data in their\ndecision making as they augment structured data with unstructured data to improve their\nfinancial models and forecasts."},{"page":84,"text":"The characteristics of big data differ from those of traditional data in several ways. Four\ncore areas of difference—the four Vs—are volume, variety, velocity, and veracity.\n• Volume: The quantity of data available\n• Variety: The wide array of available data sources\n• Velocity: The speed at which data is created\n• Veracity: The credibility and reliability of different data sources\nOne of the first problems to consider when using big data is deciding what data is\nactually relevant and where it comes from. For example, if an analyst is trying to\ndetermine the likely profitability of a chain of coffee shops, what data could be useful?\nIf a financial analyst is trying to determine the likely profitability of a chain of coffee\nshops, what data could be useful?  Review each form of data and select “Yes,” “No,” or\n“Unlikely.”\n1. Structured data from the firm’s financial statements\n2. Management expertise\n3. The volume of pedestrian traffic past the shops\n4. The demographics of those pedestrians\n5. The height of the pedestrians\n6. Voting habits of the pedestrians"},{"page":85,"text":"Analytical models must be able to distinguish between data that adds value to the\nanalysis and data that detracts from it. To test the explanatory power of the data,\nanalysts will combine traditional techniques, such as regression and time-series\nanalysis, with AI and machine learning–based techniques.\nIs AI valuable when dealing with complex and nonlinear relationships that are\nbeyond the scope of traditional quantitative methods and statistical analysis?\nTake a moment to consider this question, and then compare your response to\nthis response:\nYes. Advances in AI-based techniques are enabling new data analysis\napproaches. For example, analysts are turning to AI to sort through the enormous\namount of data from company filings, annual reports, and earnings calls. AI helps\ndetermine which data is the most important, uncovers trends, and generates\ninsights on human sentiment and behavior. Natural language processing also\ncomes into play here.\nNatural Language Processing (NLP)\nStated concisely, NLP is a set of techniques that begins with transforming unstructured\ntext data into structured (i.e., machine-readable) data and then classifies or clusters it to\nextract useful information. Consider the following two investment examples.\nStock Sentiment Analysis\nNLP is applied to the classification of company news into “positive” or “negative”\nsentiment to quickly and robustly answer the question, Does the stock market\nperceive this news as good or bad for the company’s stock price? Sentiment\nanalysis can augment analysts’ forecasting and valuation models to improve the\ntiming of stock purchases and sales.\nTheme Extraction and Identification\nNLP can be used to quickly analyze quarterly reports and regulatory filings for\nnumerous companies, such as S&P 500 Index companies, to extract and cluster\ninformation that reveals underlying trends or themes. These include supply chain\nissues, profit margins becoming thinner, or weakening consumer demand. These\nthemes may then become the basis for trading or investment strategies."},{"page":86,"text":"Automated/Algorithmic Trading\nAlgorithmic trading is the computerized buying and selling of financial instruments, in\naccordance with pre-specified rules and guidelines. It is widely used in both institutional\nand retail environments to implement trading strategies.\nInstitutions may use algorithmic trading to execute large orders, slicing them into smaller\npieces to avoid market impact and executing them across a number of different trading\nvenues to get the best price. During the day, these algorithms may continuously update\nand revise their execution strategy on the basis of changing prices, volumes, and market\nvolatility.\nAlgorithmic trading is not restricted to institutions. Many investment firms offer retail\nfunds in which all trading decisions and trade executions are automated. This type of\nfund could use a simple strategy based on technical analysis, with trades being based\non moving averages and trading volumes. These rules can be easily programmed and\nautomated.\nAlgorithmic trading provides speed, anonymity, and lower transaction costs.\nHigh-Frequency Trading\nHigh-frequency trading (HFT) is a particular form of algorithmic trading that pulls in large\namounts of data from traditional and non-traditional sources to automatically place\ntrades when certain conditions, such as mispricing, are met. The algorithm directs\ntrades to ultra-high-speed, low-latency networks in fractions of a second. The\nfragmentation of traditional trading venues has facilitated the development of HFT\nalgorithms that can exploit small, transitory pricing differences across exchanges.\nIt is estimated that in the United States, for example, 50% of trading volume is driven by\nHFT. The ultra-high speed of these systems allows a computer to analyze, process, and\nexecute a trade in approximately 10 milliseconds. As a consequence, some companies\nlocate their servers as close as possible to key exchanges to reduce the time needed to\nexecute a trade by a fraction of a millisecond.\nAutomated Advice and Robo-Advisors\nRobo-advisors make algorithmically driven investment suggestions based on client data.\nThey have a role to play in the automation of personal wealth management services and\nin the provision of investment services to a larger number of retail investors at a lower\ncost than is possible with traditional adviser models."},{"page":87,"text":"Engaging a robo-advice service typically begins with an investor questionnaire that may\ncover income, time left until retirement, anticipated spending, risk tolerance, financial\nknowledge, and investment experience. Once assets, liabilities, risk preferences, and\ntarget investment returns have been digitally entered by a client, the robo-adviser\nproduces recommendations based on algorithmic rules, historical market data, and the\nclient’s responses to the questionnaire.\nAlthough robo-advice covers both active and passive management styles, most robo-\nadvisers follow a passive investment approach. These robo-advisers typically charge\nlow fees and recommend low-cost, diversified, index-based mutual funds or exchange-\ntraded funds (ETFs).\nTwo services dominate robo-advice: fully automated digital wealth managers and\nadviser-assisted digital wealth managers.\nLearn more about these services:\nFully Automated Digital Wealth Managers\nThe fully automated model does not rely on assistance from a human financial\nadviser, usually presents a low-cost solution to investing, and often recommends\na portfolio composed of ETFs. The service package may include direct deposits,\nperiodic rebalancing, and dividend reinvestment options.\nAdviser-Assisted Digital Wealth Managers\nAdviser-assisted digital wealth managers provide automated investment services\nalong with a financial adviser, who is available virtually (by phone or online) to\noffer basic financial planning advice and periodic reviews. Adviser-assisted digital\nwealth managers’ services may involve a more holistic analysis of a client’s\nassets and liabilities.\nAs robo-advisors have been incorporated into the investment landscape, they have\ndrawn the attention of regulatory authorities.\nIn the United States, robo-advisors must be established as registered investment\nadvisers, and they are regulated by the Securities and Exchange Commission.\nIn the United Kingdom, they are regulated by the Financial Conduct Authority."},{"page":88,"text":"In Australia, all financial advisers must obtain an Australian Financial Services license,\nwith guidance on digital advisers coming from the Australian Securities and Investments\nCommission.\nAlthough regulatory conditions vary, there are indications that robo-advisors will be held\nto a similar level of scrutiny and code of conduct as other investment professionals.\nMobile Banking\nFor many people, the impact of fintech is most obvious when it comes to mobile\nbanking. The ability to transfer money from one account to another, view bank\nstatements, make investments, and pay bills with a banking app on a phone is a benefit\nof fintech for most retail banking customers. But behind this improved digital experience,\nfinancial transactions still settle in traditional, centralized depositories and\nclearinghouses out of view.\nFintech banking via mobile phones has generally made bank services more convenient\nand, in communities not well served by physical banks, more accessible. As with AI,\nhowever, an increasingly cashless society carries societal impacts. Cashless\ntransactions may result in certain jobs becoming irrelevant, such as cashiers in shops\nand ticket clerks at railway stations. And because cashless transactions make spending\neasy, critics worry it encourages reckless spending.\nDecentralized Finance (DeFi)\nDecentralized finance (DeFi) is an umbrella term for financial services and financial\ninstruments that do not rely on intermediaries, such as brokerages, exchanges, or\nbanks. By using smart contracts on public blockchains, DeFi platforms allow people to\nlend or borrow funds from others, insure against risks, earn interest in savings-like\naccounts, and trade crypto currencies.\nAs of early 2022, the value of assets used in decentralized finance amounted to\nUSD200 billion. Blockchain technology provides the foundation for DeFi and crypto\ncurrencies. Broadly speaking, blockchains are created by networks of users\n(decentralized) who use digital ledgers to securely engage in transactions and maintain\nrecords of ownership. The costs and inefficiencies of intermediaries are reduced or\neliminated as transactions are decentralized; transactions may settle in hours rather\nthan days.\nBecause the digital ledgers are duplicated and distributed across the entire peer-to-peer\nnetwork, making the information about the transaction immutable, blockchain technology"},{"page":89,"text":"promises to create the same level of investor trust that historically required reliable third\nparties, such as clearinghouses.\nBlockchains store data in “blocks” that are “chained” together. In the case of public\nblockchains, such as Bitcoin, this structure creates an irreversible chronological record.\nDifferent types of information can be stored on blockchains, but financial transactions\npredominate.\nCrypto currencies are typically accounted for using blockchain technology. Advantages\ninclude the efficiency of transacting and the relative independence from government\nfiscal and monetary policy. Although initially thought to be suited for commerce and retail\ntrade, the volatility of crypto currencies has drawn comparisons with commodities.\nDeFi, blockchain, and the decentralized protocols they support are examples of\ntechnology’s impact on finance. They will all be discussed in more detail in Course 2,\nTypes and Functioning of Markets.\nTo be successful, DeFi must provide solutions to some of the problems identified with\ncentralized and traditional finance, such as the following:\n• Centralized control\n• Limited access\n• Inefficiency\n• Lack of interoperability\n• Opacity\nWe briefly consider each of the problems and how DeFi addresses them.\nLearn more about the problems of traditional finance and how DeFi addresses them in\nExhibit 1."},{"page":90,"text":"Exhibit 1: Problems in Traditional Finance Addressed by DeFi\nProblem\nTraditional\nDeFi\nCentralized\ncontrol\nRetail banking can be highly\nconcentrated, with many markets\ndominated by a small number of banks.\nAlthough there is competition, these\nbanks tend to offer similar products at\nsimilar rates, and if one bank turns down\na request for a business loan, then it is\nquite likely that most of the others will.\nBank transactions, even the simple task\nof transferring money from one account\nto another, are not instantaneous and\ncan be costly because of their reliance\non a centralized clearing system.\nThe complexity of clearing large daily\nvolumes of transactions requires a costly\ninfrastructure typically built around a\nnational central bank, such as the US\nFederal Reserve (the Fed), the Bank of\nEngland, or the People’s Bank of China.\nIt is worth noting that every US dollar\ntransferred across the national banking\nsystem is ultimately recorded at the Fed\nas an increase in dollars held by one\nbank and a reduction in dollars held by\nanother bank.\nBlockchain offers peer-to-peer\ntransactions without the\nreliance on any traditional\nfinancial intermediaries.\nLimited access It is estimated that around 1.7 billion\npeople around the world are unbanked\nand have no access to the banking\nsystem. It can also be very difficult for\nentrepreneurs and startups to obtain\nfinancing at an affordable rate as banks\nhave become collectively more risk\naverse.\nIn a public blockchain without\npermissions, like Bitcoin or\nEthereum, opening an account\nto trade assets or instruments\non the blockchain is easily\ndone and available to\neveryone."},{"page":91,"text":"Problem\nTraditional\nDeFi\nInefficiency\nExamples of inefficiency include the\ntime and cost involved in moving\nmoney internationally. For instance, it\nusually takes two days to settle a\nsimple stock transaction.\nBlockchain transactions are\nusually executed in a matter of\nminutes, although speed can\ndepend on how busy the\nblockchain is at any given\nmoment.\nLack of\ninteroperability\nThe banking system is siloed and\nisolated from other systems, which\nmakes it vulnerable to inefficiencies.\nThe silo effect can be observed when\nbuying real estate because there is no\nlink between the banking system,\nwhich is required to pay for the\nproperty, and the registration system,\nwhich records transfers of ownership.\nUsing a special standard for\ncreating and issuing “smart”\ncontracts on a network, such\nas the Ethereum blockchain,\nfungible tokens that represent\nan asset, a right, an ownership,\naccess, or a crypto currency can\nbe used on any protocol across\nthat network, thus ensuring a\nhigh level of transactional\ninteroperability.\nOpacity\nThere is little transparency into the\nfinancial health and security of financial\ninstitutions. A bank that is offering a\nhigh interest rate on its short-term debt\nmay have ample funds but may want to\nattract new customers. Alternatively,\nthe bank could be desperate for funds\nand near collapse. The consequence of\nthis lack of transparency is excessive\nand costly regulation.\nEverything is done on a\ntransparent public blockchain,\nfrom the smart contract code to\nthe details of every transaction.\nCrypto Assets\nBitcoin is probably the most well-known crypto asset that trades on a blockchain.\nSupporters of Bitcoin have claimed it is the future of money.\nSatoshi Nakamoto’s 2008 paper, “Bitcoin: A Peer-to-Peer Electronic Cash System,”\nproposed an asset that could be used as an alternative to traditional fiat currency to"},{"page":92,"text":"settle transactions. Although Bitcoin has not fulfilled this purpose, it has found a purpose\nas a store of value, although a very volatile one.\nAn arguably bigger impact of the blockchain is the Ethereum network and the\ndevelopment of the smart contracts that are deployed on it. These smart contracts, a\ncouple of which are discussed in the next course, are at the heart of decentralized\nfinance.\nThe ability technology has brought to execute swaps, loans, and derivative transactions\nwith a program, the smart contract, and the removal of intermediaries and counterparties\nhas a real impact on finance. Throw in open access to all users, and blockchain\ntechnology appears truly revolutionary.\nWhether this technology will truly revolutionize the world of finance remains to be seen.\nThe potential is real, but so are the risks and pitfalls.\nLesson 4 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nDecentralized finance refers to financial products and services that promise to eliminate\nwhat are seen as inefficiencies in centralized financial systems. Which of the following\ncriticisms is not associated with traditional, centralized financial systems?\na. Centralized controls can lead to complex and costly operational infrastructure.\nb. In some markets, the high costs associated with building and staffing physical\nbanks result in limited access to banking services.\nc. Money laundering regulations impede small cash transactions.\nd. Interoperability—the ability of service providers to interact smoothly across their\nvarious financial platforms—is constrained when institutions have different\nsoftware systems and accounting protocols."},{"page":93,"text":"large cash transactions or unusual activity. In the course of normal business, small cash\ntransactions are not considered unusual activities.\na., b., and d. are incorrect. Each are associated with centralized financial systems\nUp Next\nYou have now reached the end of Lesson 4! We hope that this lesson has helped you to\nunderstand the different types of automation in the finance world.\nYou should now be able to describe how fintech applications are currently transforming\nthe world of finance."}]},{"id":"m4-summary","moduleId":"m4","label":"Summary","title":"Module 4 Summary","pages":[{"page":94,"text":"Module 4 Summary\nIn this module, we focused on financial planning services. Often investors seek\nprofessional assistance with activities that they either cannot or choose not to do\nthemselves. Some of these activities include determining financial goals; identifying\npotential investments; evaluating the risk and return prospects of potential investments;\ntrading securities and assets; holding, managing, and accounting for securities and\nassets during the periods of the investments; and evaluating the performance of those\ninvestments.\n●\nFinancial planners help investors set their financial goals and determine how\nmuch money they should save for future expenses and/or how much money they\ncan spend on current expenses while still preserving their capital.\nNext, we looked at how fintech is changing the financial services industry and, in\nparticular, how it is changing investment advice, financial planning, business lending,\nand payments.\n●\nAI generally refers to machines acting within the context of the intelligence they\nhave iteratively improved as they collect information, which implies the ability to\nlearn and adapt. The use and application of AI has led to rapid innovations within\nfinancial services.\n●\nAI has been instrumental in advancements in credit assessment, fraud detection,\nrisk management, trading, personalized banking, and process automation.\n●\nThe prevalence of the use of AI in financial services has led to the rise of many\nethical implications around the issues of bias, accountability, and transparency.\nLastly, we went over the specific ways in which fintech applications are transforming the\nworld of finance.\n●\nFinancial analysts no longer limit themselves to studying financial statements,\neconomic reports, and market indicators but also dive deeply into the stories told\nby non-traditional data from non-traditional sources, which must be integrated into\nthe investment decision-making process. Fintech supports the development of\nanalytical tools that aid in this process.\n● Big data (or alternative data) encompasses unstructured data generated by\nfinancial markets, businesses, governments, individuals, sensors, and the\n“Internet of Things.” The characteristics of big data differ from those of traditional\ndata in four core ways—volume, variety, velocity, and veracity.\n● AI is especially valuable when dealing with complex and nonlinear relationships\nthat are beyond the scope of traditional quantitative methods and statistical"},{"page":95,"text":"analysis, such as insights on human sentiment and behavior. Natural language\nprocessing is a set of techniques that begins with transforming unstructured text\ndata into structured (i.e., machine-readable) data and then classifies or clusters it\nto extract useful information. Stock sentiment analysis and theme extraction and\nidentification are two examples of such applications.\n● Algorithmic trading is the computerized buying and selling of financial\ninstruments, in accordance with pre-specified rules and guidelines. It provides\nspeed, anonymity, and lower transaction costs. High-frequency trading (HFT) is a\nparticular form of algorithmic trading that pulls in large amounts of data from\ntraditional and non-traditional sources to automatically place trades when certain\nconditions, such as mispricing, are met.\n● Robo-advisors make algorithmically driven investment suggestions based on\nclient data, and they have a role to play in the automation of personal wealth\nmanagement services and in the provision of investment services to a larger\nnumber of retail investors at a lower cost than is possible with traditional adviser\nmodels. Two services dominate robo-advice: fully automated digital wealth\nmanagers and adviser-assisted digital wealth managers.\n● Fintech banking via mobile phones has generally made bank services more\nconvenient; however, an increasingly cashless society carries societal impacts,\nincluding people losing their jobs and the potential for reckless spending.\n● DeFi is an umbrella term for financial services and financial instruments that do\nnot rely on intermediaries, such as brokerages, exchanges, or banks. Blockchain\ntechnology provides the foundation for DeFi and crypto currencies. DeFi\nplatforms, via smart contracts on public blockchains, allow people to lend or\nborrow funds from others, insure against risk, earn interest in savings-like\naccounts, and trade crypto currencies. Broadly speaking, blockchains are created\nby (decentralized) networks of users who use digital ledgers to securely engage\nin transactions and maintain records of ownership. Because the digital ledgers\nare duplicated and distributed across the entire peer-to-peer network, making the\ninformation about the transaction immutable, blockchain technology promises to\ncreate the same level of investor trust that historically required third parties, such\nas clearinghouses.\n● DeFi provides solutions to some of the problems identified with centralized and\ntraditional finance, such as centralized control, limited access, inefficiency, lack of\ninteroperability, and opacity."}]},{"id":"m5-overview","moduleId":"m5","label":"Overview","title":"Module overview","pages":[{"page":97,"text":"Module 5: Investment Professionalism and Regulations\nTrust is essential to the functioning of the investment industry as well as the broader\nfinancial services industry.\nInvestment professionals are responsible for providing access to information about\ninvestment opportunities and financial markets. Regulations govern who is allowed to\noperate as an investment professional and how financial products are marketed. Failure\nto comply with regulations, policies, and procedures can have significant consequences\nfor employees, managers, customers, the company, the investment industry, and the\neconomy.\nBy the end of this module, you will be able to:\n● Describe how ethics and regulation are key forces driving the investment\nindustry\n● Define  why regulations for the financial industry are so important\n● Describe the objectives of regulation\n● Identify specific types of regulation and describe the reasons for each\n● Describe the potential consequences of compliance failure\n● Describe why trust and ethics in the investment industry are important\n● Identify common obligations that individuals as professionals in the investment\nindustry have toward various stakeholders\n● Identify elements of the CFA Institute Code of Ethics and explain how standards\nof professional conduct that are based on the CFA Institute Code of Ethics can be\napplied in practice\n● Explore the benefits of ethical conduct as well as the consequences of unethical\nconduct for various parties in the investment industry and the economy as a\nwhole\n● Describe a framework for making ethical decisions\nLet's get started!"}]},{"id":"m5-l1","moduleId":"m5","label":"Lesson 1","title":"Key Forces Driving the Investment Industry","pages":[{"page":98,"text":"Lesson 1: Key Forces Driving the Investment Industry\nWelcome to Lesson 1 of Module 5!\nIn this lesson, you will learn about ethics and regulations in the investment industry. You\nwill dive deeper into such concepts as investor trust and ethical guidelines as well as the\nneed for rules, regulations, and laws that promote ethical behavior.\nBy the end of this lesson, you will be able to describe how ethics and regulations are key\nforces driving the investment industry.\nLet's get started!\nExhibit 1: The Need for Trust, Laws, and Regulations\n\nAt its best, the investment industry efficiently matches those who need money with those\nwho have savings to invest, allowing money to support the most productive businesses\nand projects. Like many industries, the investment industry evolves in response to"},{"page":99,"text":"internal and external drivers of change as shown in Exhibit 1. Competition and\ntechnology are internal drivers; regulation (laws) and globalization are external drivers.\nWhen the investment industry is efficient and trustworthy, economies and people\nbenefit.\nTrust is essential to the proper functioning of the financial system in general and the\ninvestment industry in particular. Investors should be confident they will be treated fairly\nby the people and institutions they transact with as well as by those who advise them,\nsell them investment products, and manage their investments. If trust is lacking,\ninvestors will be reluctant to commit their capital to viable investment opportunities and\nthe economy and society will suffer.\nLaws and regulations are necessary to ensure that investors are treated fairly and\nhonestly. Usually, laws are passed by a legislative body, such as Congress in the United\nStates, Parliament in the United Kingdom, and the Diet in Japan. Regulations are\ncreated by agencies, such as the Canadian Securities Administrators in Canada, the\nAutorité des marchés financiers in France, and the Securities and Futures Commission\nof Hong Kong.\nNote: Laws and regulations must be enforceable to be effective.\nThe form and extent of laws and regulations vary among countries and change over\ntime, but a few general principles are widely applied. Laws and regulations are designed\nto do the following:\n1. Prevent fraud\n2. Protect investment industry participants—in particular, investors\n3. Promote and maintain the integrity, transparency, and fairness of financial\nmarkets\nFor example, trading based on non-public information that could affect a security’s price,\nknown as insider trading, is forbidden in most jurisdictions.\nThis means that an analyst who learns during a private meeting with a company’s\nmanagement that the company is about to acquire a competitor is not allowed to buy or\nsell shares in the company or its competitor until the company has officially announced\nthe acquisition. If the analyst trades before this information is available to all market\nparticipants, he could gain from this inside information, and the integrity and fairness of\nthe financial market would be compromised. In many jurisdictions, the analyst could also\nface legal or regulatory punishment."},{"page":100,"text":"The Need for Ethical Behavior\nThe adoption and successful application of ethical and professional standards,\nregulations, and corporate policies create trust.\nAlthough the investment industry is subject to them, laws and regulations cannot cover\nevery eventuality, nor can they completely prevent fraud and market abuse. For this\nreason, it is important that investment industry professionals behave professionally and\nethically, in accordance with a set of moral principles, and that financial institutions\nproactively promote cultures of integrity.\nThe story of Wells Fargo Bank shows why individual behavior at all levels of\nmanagement is so important in the financial industry. It is up to the individuals working in\nfinancial institutions to inspire public trust by always behaving professionally and\nethically.\nIn 2016, Wells Fargo Bank was found to have fraudulently created millions of new\nsavings and checking accounts in the names of their customers over a period of years.\nThe accounts had been opened without customers’ knowledge or permission. Initial\nreports indicated that rogue employees or offices had responded inappropriately to sales\nincentives. As the scale of the fraud became apparent, however, it was determined that\nmuch of the blame lay with upper management’s pressure on employees to show\nsuccessful cross-selling of Wells Fargo’s services, such as creating credit card accounts\nfor clients who were taking out home loans or opening savings accounts. Wells Fargo’s\nCEO was subsequently barred from the banking industry. In 2020, Wells Fargo agreed\nto pay USD3 billion to settle criminal and civil investigations. Because of the scandal,\nWells Fargo suffered reputational damage, and public trust in the financial industry\nsuffered.\nLesson 1 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion\nLaws and regulations that promote integrity, transparency, and fairness in financial\nmarkets are necessary for which of the following reasons?"},{"page":101,"text":"Select all the correct choices that apply.\na. Regulations are needed to assure investors that they will be treated fairly.\nb. Investors who lack confidence in the financial markets will be reluctant to invest,\nraising the costs for seekers of capital to find providers.\nc. Regulations create global standards for determining fair prices."}]},{"id":"m5-l2","moduleId":"m5","label":"Lesson 2","title":"Financial Industry Regulation","pages":[{"page":102,"text":"Lesson 2: Financial Industry Regulation\nWelcome to Lesson 2 of Module 5!\nIn the financial industry, rules and regulations are in place to prevent not only\nconsumers from losing their life savings but also large financial services companies from\nfailing, which would cause serious damage to the economy. Regulations frequently drive\nindustry change and underpin attempts to prevent, identify, and punish undesirable\nbehavior. Financial services and products are highly regulated because industry failure\nor disruption can have devastating consequences.\nBy the end of this lesson, you will be able to define why regulations for the financial\nindustry are so important.\nLet’s get started!\nWhat Exactly Are Regulations?\nRules are important to the investment industry. Without them, customers could be sold\nunsuitable products and lose their life savings. Customers can also be harmed by the\ninvestment industry misusing their assets. Furthermore, the failure of a large financial\nservices company can lead to a systemic chain reaction that results in the failure of\nmany other companies, causing considerable damage to the economy.\nRegulations are rules that set standards for conduct and that carry the force of law. They\nfrequently drive industry change and underpin attempts to prevent, identify, and punish\nundesirable behavior.\nFinancial services and products are highly regulated because industry failure or\ndisruption can have devastating consequences.\nSet and enforced by government bodies and by entities authorized by government\nbodies, regulations differ from ethical principles or professional standards. Violations of\nethical principles and professional standards have consequences, but those\nconsequences may be less severe than what arises from violations of laws or\nregulations. Laws and regulations can be used to reinforce ethical principles and\nprofessional standards.\nCompanies and employees that fail to comply with regulations face sanctions that can\nbe severe on top of the harm that the noncompliance can have on companies,\nemployees, and trust in the industry. When companies enforce rules for their employees"},{"page":103,"text":"to ensure compliance, and as they guide employees with matters outside the scope of\nregulation, their corporate policies serve to establish good behavior and business\npractices. An understanding of the regulatory environment and the corporate policies of\none’s employer is essential for success in the investment industry.\nIn this module, many of the examples are drawn from developed economies, primarily\nbecause the regulatory systems in these economies have had longer to evolve. Many of\nthese systems have been adjusted over the years, so they not only protect investors and\nthe financial system but also allow the investment industry to innovate and prosper.\nLesson 2 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion\nTrue or False: Regulations are rules that set standards for conduct and carry the force of\nlaw. They can be used as effective tools to reinforce ethical principles and professional\nstandards.\nQuestion choices\na. True\nb. False"},{"page":104,"text":"Up Next\nYou have now completed Lesson 2. We hope that this lesson has helped you\nunderstand the consequences of unethical behavior and why regulation is necessary.\nYou should now be able to define why regulations for the financial industry are\nimportant. In the next lesson, you will learn about the objectives of regulation."}]},{"id":"m5-l3","moduleId":"m5","label":"Lesson 3","title":"Objectives of Regulation","pages":[{"page":105,"text":"Lesson 3: Objectives of Regulation\nWelcome to Lesson 3 of Module 5!\nBy the end of this lesson, you will be able to describe the objectives of regulation.\nObjectives of Regulation\nRegulators act in response to a perceived need for rules. Regulation is needed when\nmarket solutions are insufficient. Understanding the objectives of regulation makes it\neasier for industry participants to anticipate and comply with regulation. The following\ninformation describes these objectives.\nProtect Consumers\nConsumers in this space include borrowers, depositors, and investors, and\nalthough they may be able to quickly determine the quality of goods or services,\nmany of them may not have the skills or information needed to determine the\nquality of financial offerings. Regulators seek to protect consumers from abusive\nand manipulative practices, including fraud. Regulators may, for instance, prevent\ninvestment firms from selling complex or high-risk investments to individuals\nlacking sufficient knowledge or assets.\nFoster Capital Investment and Economic Growth\nFinancial markets match suppliers of capital with users of capital, such as\ncompanies and governments. The allocation of capital to productive uses is\nessential for economic growth. Regulators seek to ensure fair and efficient\nfinancial markets to foster economic development.\nSupport Economic Stability\nThe increasingly complex interconnections among global financial institutions\nmay increase the consequences, if not the risk, of a systemic failure, which is a\nfailure of the entire financial system. Regulators thus seek to ensure that financial\nfirms, both individually and as an industry, do not engage in practices that could\nput the whole industry at risk.\nEnsure Fairness\nNot all market participants have the same information. Sellers of financial\nproducts might choose not to communicate negative information about the"},{"page":106,"text":"products they are selling. Insiders who know more than the rest of the market\nmight trade on their inside information. These information asymmetries, or\ndifferences in available information, can deter investors from investing, thus\nharming economic growth.\nRegulators attempt to deal with these asymmetries by requiring fair and full\ndisclosure of relevant information on a timely basis and by enforcing prohibitions\non insider trading. Regulators seek to maintain fair and orderly markets in which\nno participant has an unfair advantage.\nEnhance Efficiency\nRegulations that standardize processes can enhance economic efficiency by\nreducing duplication and confusion. Regulations that ensure an efficient dispute\nresolution process can also reduce costs and increase economic efficiency.\nImprove Society\nGovernments may use regulations to achieve social objectives. These objectives\ncan include increasing the availability of credit financing to a specific group,\nencouraging homeownership, or increasing national savings rates.\nAnother social objective is preventing criminals from using financial firms to\ntransfer money from illegal operations to other, legal activities, a process known\nas money laundering. As a consequence of the transfer, the money becomes\n“clean.” Regulations help prevent money laundering and detect and prosecute\ncriminal activity.\nSpecific regulations are developed in response to the broad objectives of regulation.\nRegulation can help to achieve multiple objectives. For example, rules about insider\ntrading protect consumers (investors) and promote fairness in financial markets. Specific\ntypes of regulation are discussed in the following lessons.\nLesson 3 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it."},{"page":107,"text":"Question\nIn addition to reinforcing ethical principles and standards, regulations are needed when\nmarket solutions are not sufficient to meet economic and societal goals. Which of the\nfollowing is not a broad objective of regulation?\nQuestion choices\na. Consumer protection\nb. Capital formation and economic growth\nc. Population growth\nd. Economic stability"}]},{"id":"m5-l4","moduleId":"m5","label":"Lesson 4","title":"Types of Regulation","pages":[{"page":108,"text":"Lesson 4: Types of Regulation\nWelcome to Lesson 4 of Module 5!\nIf regulators do not enforce rules of conduct, it can cause irreparable damage to the\neconomy through a chain reaction from customer to company to industry failure. To help\nprevent this failure, sets of rules that focus on specific types of activity in the industry\nhave evolved to ensure the smooth operation of the financial system.\nBy the end of this lesson, you will be able to identify specific types of regulation and\ndescribe the reasons for each.\nLet's get started!\nTypes of Financial Market Regulation\nWhen regulations fail to achieve their intended purpose, the consequences for\nindividuals, institutions, and the economy can be severe. Trust in the financial services\nindustry, which includes the investment industry, can also be damaged.\nCustomers may lose their life savings when they are sold unsuitable products, or\ncustomers could be harmed if an investment firm misuses customer assets.\nFurthermore, the failure of one large company in the financial services industry can lead\nto a catastrophic chain reaction (contagion) that results in the failure of many other\ncompanies, causing serious damage to the economy.\nIn response to this risk, multiple groups of related regulations have evolved to ensure\nthe smooth operation of financial systems.\nThe broad objectives of regulation are attained by creating sets of rules that focus on\nspecific types of investment industry activity. These rules include the following:\n1. Gatekeeping rules\n2. Operations rules\n3. Disclosure rules\n4. Sales practice rules\n5. Trading rules\n6. Anti-money-laundering rules\n7. Business continuity rules"},{"page":109,"text":"1. Gatekeeping Rules\nGatekeeping rules govern who is allowed to operate as an investment professional and\nhow financial products are marketed. A primary activity of regulators is screening\ninvestment industry personnel to ensure they meet established standards for integrity\nand competence. Regulators in most financial markets require industry personnel to\npass licensing exams to ensure a sufficient understanding of financial products and\nrelevant financial law.\nFinancial products typically must comply with numerous regulations before they can be\nsold to the public. Gatekeeping rules are necessary because some financial products\nare difficult to understand and should not be sold to clients who are unable to fully\nappreciate the associated risks.\n2. Operations Rules\nRegulations may dictate certain aspects of how financial firms operate. One example is\nthe case of net capital. It is important that financial firms have sufficient resources to\nhonor their obligations.\nHistory shows that highly leveraged companies, which are companies with a high\namount of debt relative to equity, pose a risk not only to their own shareholders but also\nto their customers and the economy. Regulators seek to maintain financial industry\nstability by imposing capital requirements that limit the amount of leverage and risk that\ncompanies assume. Minimum equity capital ratios are an example.\n3. Disclosure Rules\nFor markets to function properly, market participants require information, including the\nfollowing:\n• Information about companies and governments that are raising funds\n• Information about financial instruments that are being sold and traded\n• Information about the markets the financial instruments trade in\nNote: Disclosure rules specify what information is to be passed on to participants and\nhow.\nHere are some examples of the types of disclosure rules.\n• Corporate issuers: Regulators typically require corporate issuers of securities to\ndisclose detailed information to potential buyers before the securities are offered"},{"page":110,"text":"for sale. The disclosures generally include audited financial statements,\ninformation about the general business of the company, the intended use of the\nbuyers’ proceeds, information about management, and important risk factors.\n•\nMarket transparency: Information about what other investors are willing to pay\nfor a security, or the price they just paid, is valuable, but investors often do not\nwant to reveal private information. Regulators generally require the dissemination\nof at least some information regarding the trading environment for securities.\n•\nDisclosure triggers: Stock exchanges and market regulators may require public\ndisclosure of trading activity when a trigger event occurs or when a threshold is reached.\nDisclosures about shares may describe potential takeover activity, directors’ dealings in\nthose shares, or short positions. In the United States, for example, investors are required\nto file a public disclosure when their ownership in a public company exceeds 5% of the\noutstanding shares.  A real-world example of this occurred in April 2022, entrepreneur\nElon Musk filed a Schedule 13D with the US Securities and Exchange Commission that\nreported his beneficial ownership of 73,115,038 shares, or 9%, of Twitter, Inc (NYSE:\nTWTR).\n4. Sales Practice Rules\nSome consumers seeking financial advice may not have sufficient knowledge to assess\nthe quality of the advice they are receiving, and as a result, they may be vulnerable to\nabusive sales practices. For instance, some providers may be incentivized to\nrecommend products that pay them high commissions rather than products that best suit\nthe consumer.\nThe following are examples of different sales practice rules:\nAdvertising\nRegulators may control the form and content of advertising to ensure it is not\nmisleading. Regulators often disapprove of advertised promises, such as\n“guaranteed” returns and “sure win” situations, and they seek to ensure fair\nrepresentation of past and anticipated future returns by creating industry\nstandards for presenting performance.\nFees\nRegulators may impose price controls to limit the commissions that can be\ncharged on the sale of financial products as well as to limit the markups and\nmarkdowns that occur when investment firms trade securities directly with their\ncustomers."},{"page":111,"text":"Information Barriers\nMany large investment firms offer investment banking services to corporate\nissuers while publishing investment research and providing financial advice. This\ncreates potential conflicts of interest. Biased investment advice could help them\nwin more lucrative investment banking business from any corporate client they\npublicly praise. Similarly, research analysts may be under pressure to publish\nfavorable reports on securities in which the firm has large positions in its\ninventory. Regulators attempt to resolve these conflicts of interest by requiring\nfirms to create both virtual and physical barriers between investment banking and\nresearch teams.\nSuitability Standards\nRegulation seeks to hold those in the investment industry accountable for the\nadvice that they give to their clients. Any advice or recommendation should be\nsuitable for the client and consistent with the client’s interests. Regulators may set\nan even higher standard and require that the financial service provider act in the\nclient’s best interest. In most common law countries, including the United\nKingdom and the United States, a well-established body of law has developed\naround the role of fiduciaries and their fiduciary duty to act in the client’s best\ninterest ahead of their own. You will learn more about fiduciary duty in Course 6,\nServing the Greater Good.\nRestrictions on Self-Dealing\nSelf-dealing is the practice of a fiduciary trading directly with the investor, rather\nthan matching the trade with a third-party buyer or seller. Many firms in the\ninvestment industry sell financial products, such as securities, directly out of their\nown inventories, which allows the firm to provide faster service and better liquidity\nto their customers. However, self-dealing can create conflicts of interest because\nthe firm is incentivized to charge the highest price to the customer, who wants to\npay the lowest price. There can also be confusion among some customers as to\nwhether the firm is acting as a principal (i.e., buying or selling for the firm’s\ninventory) or as an agent (i.e., working for the client but not trading with the\nclient).\nRegulators may impose the best execution requirements, they may require that\nthe firm disclose the conflict, or they may ban self-dealing altogether."},{"page":112,"text":"5. Trading Rules\nRegulations are often designed to set investment industry standards and to prevent\nabusive trading practices.\nThe following are some trading rules.\nMarket Standards\nGovernment regulation can be used to set the standard length of time between a\ntrade and the settlement of the trade, which is three business days for equities in\nmost global markets.\nMarket Manipulation\nRegulators attempt to prevent and prosecute market manipulation. Market\nmanipulation involves actions intended to move the price of a stock to generate a\nshort-term profit.\nInsider Trading\nA market in which some participants have an unfair advantage over other\nparticipants lacks legitimacy and thus deters investors. For this reason, most\njurisdictions have rules designed to prevent insider trading. Regulators often\nexpect companies to have policies and procedures in place to restrict access to\nsuch information and to deter parties with access from trading on this information.\nFront-Running\nFront-running is the act of placing a personal order ahead of a customer’s order\nto take advantage of the price impact that the customer’s order will have. For\nexample, if you know a customer is ordering a large quantity of stock that is likely\nto drive up the price, you could take advantage of this information by buying in\nadvance of that customer’s order. As with insider trading, regulations may help\nensure that companies have procedures in place to deter front-running and to\nmonitor employees’ personal trading.\n6. Anti-Money-Laundering Rules\nCompanies in the financial services industry can be used by criminals to launder money\nor otherwise facilitate illegal activities. Governments naturally want to deter such\nactivities, and they may use their regulatory power over companies in the financial"},{"page":113,"text":"services industry to do so. Regulations may require companies to confirm and record\nthe identity of their clients; to report payments, such as dividends, to tax authorities; and\nto report other pertinent activity, such as large cash transactions.\n7. Business Continuity Rules\nGiven the essential nature of financial services to the economy, regulators may be\nconcerned about business continuity in the event of disasters, such as fires, floods,\nearthquakes, and epidemics. Regulators want to be assured that customer records are\nadequately backed up and that companies have plans in place to recover from a\ndisaster.\nLesson 4 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nRegulatory failures undermine investor confidence in the financial system and the\nwillingness to engage in transactions. Which of the following is not an example of\nregulatory failure?\nQuestion choices\na. For an extended period of time, margin deposits at a futures exchange remain\nbelow the minimum levels required by regulators. Failure to identify and correct\nthe inadequate capital levels results in a major loss to the exchange.\nb. A bank whose net capital has fallen below regulatory minimums continues to\nmake high-risk loans. When the economy slows and borrowers’ default, the bank\nannounces that it will be unable to fully repay its depositors.\nc. A brokerage firm is confronted by clients who believe that the firm should have\nadvised them to sell their holdings of Deepdive Corporation before the stock\nmarket dropped."},{"page":114,"text":"Question 2\nRegulations that attempt to prevent market manipulation are examples of:\nQuestion choices\na. trading rules.\nb. operational rules.\nc. sales practice rules."}]},{"id":"m5-l5","moduleId":"m5","label":"Lesson 5","title":"Consequences of Compliance Failure","pages":[{"page":116,"text":"Lesson 5: Consequences of Compliance Failure\nWelcome to Lesson 5 of Module 5!\nRegulation helps maintain market stability and enables participants to thrive. Regulatory\nrules together with company policies and procedures help ensure compliance and that\nall parties can benefit.\nBy the end of this lesson, you will be able to describe the potential consequences of\ncompliance failure.\nLet's get started!\nConsequences of Compliance Failure\nFailure to comply with regulations and policies and procedures can have significant\nconsequences for employees, managers, customers, the company, the investment\nindustry, and the economy.\nCompanies may fire employees and managers who fail to comply. When a regulatory\naction occurs, even if no formal charges are brought, the legal costs to the individuals\nand firms who deal with it can be high.\nRegulators have many ways of disciplining firms and individuals who violate informal\nrules. Sanctions for individuals include fines, imprisonment, the loss of their financial\nlicence, and lifetime bans from working in the investment industry. When subordinates\nviolate rules, managers may also face consequences for failure to adequately supervise\nthem. Even long after the issue is resolved, the regulatory sanctions remain a matter of\npublic record that can tarnish the reputations of the individuals involved for the rest of\ntheir lives. The economic impact of a damaged reputation can be huge.\nCompanies also face sanctions, including fines, loss of licences, and forced closure. A\ncompany may be forced to spend significant resources on corrective actions, such as\nhiring outside consultants, to demonstrate compliance. Companies interact with\nregulators on an ongoing basis, so running afoul of a regulator’s opinion in one area can\nlead to problems in other areas.\nCompliance failures affect more than just the company and its employees. Customers\nmay lose all their money, counterparties can suffer losses, and trust in the industry and\nmarkets can be seriously damaged."},{"page":117,"text":"Lesson 5 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion\nThe consequences of failure to comply with regulations and corporate policies and\nprocedures:\nQuestion choices\na) include costs to only the firm and employees.\nb) range from individual costs to damage to the global economy.\nc) are borne by the employee who failed to comply and not by the employee’s\nsupervisor or employer."}]},{"id":"m5-l6","moduleId":"m5","label":"Lesson 6","title":"Ethics and the Investment Industry","pages":[{"page":118,"text":"Lesson 6: Ethics and the Investment Industry\nWelcome to Lesson 6 of Module 5!\nBecause of the growth of the financial markets, there is an increase in the complexity of\nethical dilemmas, especially in business conducted across borders under different\nregulatory and cultural frameworks. Therefore, guidance is needed to inform the\nacceptable behavior of market participants. While the ideas of “do the right thing” and\n“always act ethically” seem simple, in the world of investments, the right path isn’t\nalways as clear. For this reason, and given the importance of maintaining ethical\nbehavior in the investment profession, Lesson 6 is the longest lesson of this module.\nBy the end of this lesson, you will be able to describe why trust and ethics in the\ninvestment industry are important.\nA Deeper Dive on the Importance of Ethics in the Investment Profession\nUnethical behavior, whether legal or not, can have significant consequences for the\nreputation of professional bodies, the financial system, and the economy at large. When\nfaced with ethical dilemmas and decisions that can affect multiple stakeholders,\nprofessionals working within the investment industry must have a well-developed set of\nprinciples.\nEstablishing and applying an ethical decision-making framework in practice is crucial to\nengaging in ethical conduct and can result in engendering stakeholder trust and positive\nsentiment for the industry at large.\nBy the end of this lesson, you will be able to:\n• Identify common obligations that individuals as professionals in the investment\nindustry have toward various stakeholders (clients, prospective clients, employers,\nand coworkers)\n• Identify elements of the CFA Institute Code of Ethics\n• Explain how the Standards of Professional Conduct that are based on the CFA\nInstitute Code of Ethics can be applied in practice\n• Describe benefits of ethical conduct\n• Describe consequences of conduct that is unethical or unprofessional\n• Describe a framework for making ethical decisions\n• Describe benefits of ethical conduct\n• Describe consequences of conduct that is unethical or unprofessional\n• Describe a framework for making ethical decisions"},{"page":119,"text":"Let's get started!\nEthics and Trust\nEthics form a personal moral philosophy that is related to a person’s upbringing and to\nthe cultural, social, economic, and legal environments the person moves through.\nBecause there are no universally agreed-on standards of ethical behavior, we need\nadditional guidance.\nWe can find additional guidance for ethical behavior in the following places.\n• Professional standards: Professional standards, including codes of ethics, are\nestablished by professional associations to guide the behavior of individuals\nwithin the profession.\n• Regulations: Regulations carry the force of law and set standards for conduct.\nRegulations can be used to reinforce ethical and professional standards.\n• Policies and procedures: Corporate policies and procedures are put in place by\ncompanies to promote desired behaviors and to guide employees.\nGuidance may include rules that cover many situations, but they cannot reasonably be\nexpected to cover every contingency. It is important to recognize that ethics and rules\nare interlinked: Ethical standards help guide the development of rules, and equally,\nrules help individuals think about and form ethical standards. A two-way feedback\nprocess between individual behavior and rules is critical to creating an ethical\ninvestment industry that inspires trust among investors.\nAs mentioned, ethics is a set of moral principles or the principles of conduct governing\nan individual or a group. Ethics plays an essential role in protecting financial market\nintegrity and the functioning of the investment industry. Financial market integrity refers\nto financial markets that are fair and transparent and that provide investor protection.\nNote: Trust in the investment industry is enhanced when workers in the industry\ndemonstrate ethical decision-making.\nCase Study\nIn the 2022 CFA Institute Investor Trust Study “Enhancing Investors’ Trust” (CFA\nInstitute 2022), researchers examined trust in the financial services industry."},{"page":120,"text":"They determined that trust levels among institutional and retail investors were relatively\nhigh, but they also found that only 33% of those surveyed believed that their advisers\nwould “always” put the client’s interests first.\nA more positive finding was that trust in the financial services sector was significantly\nhigher among retail investors who used advisers than among those who did not.\nThe study further noted a “trust multiplier” effect from technology. Investors indicated\nthat the increased use of financial tools and access to financial data had increased their\ntrust in the industry. The study summarized its findings with the observation that “trust, in\nsome form, is at the center of all financial transactions.” As show in Exhibit 1:\n• Ethical standards and some professional standards are based on principles that\nsupport and promote desired values or behaviors.\n• Professional organizations, such as CFA Institute, establish codes of ethics and\nprofessional standards based on ethical principles to guide practice.\nExhibit 1: Ethics, Rules, and Standards\n\nEthics and rules (i.e., regulations) are intertwined; ethical standards help guide the\ndevelopment of rules, and rules help individuals and groups, such as professional\nassociations, think about, develop, and apply ethical standards.\nA culture of integrity based on ethical standards can be built at a personal and business\nlevel by applying four basic steps:\n1. Set ambitious standards, and put them in writing.\n2. Get adequate and ongoing training on professional and ethical standards.\n3. Assess the integrity of individuals and groups you encounter.\n4. Take action when integrity and ethical standards are breached.\nThese steps help people assess and deal with ethical dilemmas. Ethical dilemmas are\nsituations in which values, interests, or rules conflict. Sometimes the dilemma and an\nappropriate response are obvious; sometimes they are not. The challenge of resolving\nethical dilemmas is addressed further in Course 6, Serving the Greater Good."},{"page":121,"text":"Why Is Ethical Behavior Important?\nGlobal financial markets have grown in size and complexity over the last few decades.\nInvestment products and financial services have also increased in breadth and\ncomplexity. Such growth and complexity increase the likelihood of ethical dilemmas,\nespecially in business conducted across borders under different regulatory and cultural\nframeworks.\nInvestment professionals provide access to and information about investment\nopportunities and financial markets. They are involved in making and helping clients\nmake investment decisions and in creating products that help with and add value to the\ninvestment decision-making process.\nIndividuals who work in the investment industry, but outside the investment\nmanagement functions, are also critical to the functioning of the industry. These\nindividuals include employees working in fund administration, securities trading and\naccount services, and other support activities, including legal, human resources,\nmarketing, sales, and information technology.\nThe decisions and actions of all investment industry professionals may directly or\nindirectly affect clients, prospective clients, employers, and coworkers. These\nprofessionals have a responsibility to make ethical decisions and to act appropriately. In\nother words, they must be trustworthy.\nFor example, clients seeking wealth management advice trust that the investment\nprofessionals they consult will provide suitable recommendations. Typically, these\nprofessionals rely on the support of others to provide investment services to clients. This\nsupport may be provided from within the investment firm or, in some cases, by third\nparties, such as legal or tax consulting firms. Such support also extends to the use of\nthird-party information, such as credit ratings and investment research.\nWhen relying on these sources, investment industry professionals must be careful and\nconduct due diligence to ensure the reliability of the information. If all parties are\ncommitted to acting in the best interests of the client, the client’s trust in the professional\nrelationship is more likely to be sustained.\nLesson 6 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it."},{"page":122,"text":"Question\nRegulations cannot anticipate every situation in which questions of integrity or fairness\nwill arise. For this reason, individuals and institutions should be guided by ethical\nprinciples and a culture of ethical behavior. Which of the following should not be\nconsidered a reliable source of guidance for the application of ethical principles?\nQuestion choices\na. Professional standards addressing activities specific to the financial\nindustry\nb. Financial regulations carrying the force of law\nc. Peer group behavior\nd. Corporate policies and procedures designed to promote ethical behavior"}]},{"id":"m5-l7","moduleId":"m5","label":"Lesson 7","title":"Trust and Stakeholder Obligations","pages":[{"page":123,"text":"Lesson 7: Trust and Stakeholder Obligations\nWelcome to Lesson 7 of Module 5!\nEstablishing trust among stakeholders is paramount for the credibility of both\nprofessions and professionals. Upholding high ethical standards can both engender trust\nand enable effective collaboration in the pursuit of serving clients.\nBy the end of this lesson, you will be able to identify common obligations that individuals\nas professionals in the investment industry have toward various stakeholders (clients,\nprospective clients, employers, and coworkers).\nLet's get started!\nHow Professions Establish Trust\nFor a profession to be credible, its primary goal must be to establish trust among clients\nand society in general. In doing so, professions have to fulfill some common obligations\nthat, when combined, greatly increase confidence and credibility in professionals and\ntheir organizations. The following sections go into more detail about those obligations.\nProfessions Normalize Practitioner Behavior\nProfessionalism is underpinned by a code of ethics and standards of conduct developed\nby professional bodies. Regulators typically support professional ethics and recognize\nthe framework for ethics that professions can provide. Many regulators around the world\nhave engaged closely with professional bodies to understand their codes of ethics\n(codes) and standards of conduct (standards) as well as how they are enforced.\nCodes and standards developed by practitioners can be complementary to regulations,\ncodifying many more individual practices than the high-level principles set by regulation.\nMany governments have recognized that a profession can develop a more sophisticated\nsystem of standards than a regulator can via continuous practitioner input and a strong\nmutual interest within the profession to maintain good standards and adopt best\npractices. Government support of professions is attributable to the role of professions in\nhelping the public and ensuring expert and principled performance of complex services.\nProfessions Provide a Service to Society\nThere is an obligation for professionals to go beyond codes and standards.\nProfessionals should advocate for higher educational and ethical standards in their\nindustry—individually and through their organizations. Professions can widen access to\nservices and support economic activity by encouraging trust in the industries they serve."},{"page":124,"text":"Professions have realized that earning community trust not only creates professional\npride and acceptance but also delivers commercial benefits.\nA profession that earns trust may ultimately have greater flexibility and independence\nfrom government and regulators to manage its own affairs, which allows members of the\nprofession to develop service models that are both useful to clients and beneficial to\nmembers.\nProfessions Are Client Focused\nAn integral part of a profession’s mission is to develop and administer codes, best\npractice guidelines, and standards that guide an industry. These codes, standards, and\nguidelines help ensure that all professionals place the integrity of their profession and\nthe interests of clients above their own personal interests.\nAt a minimum, professionals must act in the best interests of the client, exercising a\nreasonable level of care, skill, and diligence. The obligation to deliver a high standard of\ncare when acting for the benefit of another party is called fiduciary duty, as we learned in\nModule 1, Industry Overview and Structure. Other entities, including employers,\nregulators, trade associations, and not-for-profit organizations, may also support an\nindustry but are not the same as professional bodies. Unlike professions, these other\nentities generally do not exist to set and maintain professional standards. Most\nemployers encourage employees to be members of relevant professional bodies, and\nmany financially support this membership to ideally improve the quality of client service\nand reinforce ethical awareness.\nProfessions Have High Entry Standards\nMembership in a profession is a signal to the market that the professional will deliver\nhigh-quality service of a promised standard, going beyond academic and technical\ncredentials. Professions develop curricula that equip future professionals to be\ncompetent, including in their knowledge, technical skills, and ethics.\nProfessions Possess a Body of Expert Knowledge\nA repository of knowledge, developed by experienced and skilled practitioners, is made\navailable to all members of a profession. This knowledge helps members work\neffectively and ethically and is based on best practice."},{"page":125,"text":"Professions Encourage and Facilitate Professional Development\nEntry into a profession does not, on its own, guarantee that an individual will maintain\ncompetency and continue to uphold professional standards. After qualification and\nthroughout the working life of a professional, there will be changes in knowledge and\ntechnical skills to perform certain jobs, in technology, in standards of ethical behavior, in\nservices that can be offered, and in the legal and business environment in which\nprofessional services are delivered.\nThese changing aspects of a profession all require the development of competence and\nethical awareness. Most professional bodies make it a condition of membership that a\nspecific amount of new learning is undertaken each year.\nTypically, such conditions specify a time commitment, which may be separated into\ndifferent competencies and types of learning activity. This is often referred to as\ncontinuing professional development (CPD) and is seen as an important part of\nmaintaining professional standards. The training and education that professionals\nundertake increase the value of human capital, which can contribute to economic growth\nand social mobility.\nProfessions Monitor Professional Conduct\nMembers of a profession must be held accountable for their conduct to maintain the\nintegrity and reputation of an industry. Doing so often involves self-regulation by\nprofessional bodies through monitoring and imposition of sanctions on members.\nProfessions Are Collegial\nProfessionals should be respectful to each other, even when they are competing. At the\nvery least, they must respect the rights, dignity, and autonomy of others, especially\ncoworkers.\nLesson 7 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it."},{"page":126,"text":"Question 1\nAccording to fundamental ethical and professional principles applicable to the\ninvestment industry, which group should have their interests ranked first?\na. Clients\nb. Employers\nc. Coworkers"}]},{"id":"m5-l8","moduleId":"m5","label":"Lesson 8","title":"Ethics and Standards of Professional Conduct","pages":[{"page":127,"text":"Lesson 8: Ethics and Standards of Professional Conduct\nWelcome to Lesson 8 of Module 5!\nLaws and regulations alone cannot fully protect the integrity of the financial system.\nProfessional codes of ethics complement laws and regulations by establishing universal\nstandards to which professionals are held accountable by the professional body.\nBy the end of this lesson, you will be able to identify elements of the CFA Institute Code\nof Ethics and explain how standards of professional conduct that are based on the CFA\nInstitute Code of Ethics can be applied in practice.\nLet’s get started!\nThe Ideal Asset Management Professional\nHaving obtained a high-level understanding of how a profession establishes trust within\nsociety, in this lesson we will take a closer look at the key attributes of a successful\ninvestment industry professional and provide an overview of how industry employees\nand employers can maintain high ethical standards in practice.\nLaws and regulations help to ensure that those working in the investment industry fulfill\ntheir obligations. They also help protect the integrity of the financial system and promote\nfairness and efficiency of financial markets. But laws and regulations alone are not\nsufficient to protect the financial system. Laws and regulations may not extend to all\nareas of finance and can be vague or ambiguous, making their interpretation a\nchallenge. Laws and regulations are often slow to catch up with market innovations.\nActivities that occur in different jurisdictions can be complicated by inconsistencies in\nlegal obligations in different countries. Situations may arise in which no applicable law\nexists or the existing law is inconclusive. The effectiveness of laws and regulations\ndepends on how market participants interpret and comply with them.\nThe need for ethical standards is particularly apparent in situations in which vague or\nambiguous legal rules provide room for unethical behavior that could affect the integrity\nof the investment industry and result in a loss of clients’ and/or investors’ trust. To\nprotect the financial system in these cases, ethical standards should guide the behavior\nof market participants. The principles embedded in codes of ethics and professional\nstandards should help guide the behavior of industry participants and allow them to\nadapt to a continuously changing investment industry."},{"page":128,"text":"Professionalism at the Individual Level\nWe are all familiar with job advertisements. Often, some of the required attributes are\ndescribed as “preferred but not essential” because employers are looking for the right\nbalance of qualifications, experience, and personal qualities. In the investment industry,\nthe need to maintain high ethical standards means that specific characteristics are\ndefinitely “essential.”\nLearn more about the specific non-exhaustive characteristics outlined in the CFA\nInstitute Code of Ethics and Standards of Professional Conduct:\n• Knowledge of the law: Related to Standard I(A): Professionalism – Knowledge\nof the Law, professionals should have an understanding of the various laws and\nrules issued by governments, regulatory bodies, licensing authorities, and\nprofessional associations that govern the industry.\n• Independence and Objectivity: Related to Standard I(B): Professionalism –\nIndependence and Objectivity, professionals must use sound judgement to\nmaintain independence and objectivity at all times. This behavior means not\noffering, soliciting, or accepting any gift, benefit, inducement, or compensation\nthat could be interpreted as compromising their objective evaluation.\n• Misrepresentation: Related to Standard I(C): Professionalism –\nMisrepresentation, professionals must never knowingly make any\nmisrepresentations relating to investment analysis, recommendations, or other\nactivities.\n• Misconduct: Related to Standard I(D): Professionalism – Misconduct,\nprofessionals must not engage in any dishonest, fraudulent, or deceitful activity\nthat reflects adversely on their reputation, integrity, or competence.\n• Remain informed with regular reviews: Related to Standard V(A): Investment\nAnalysis, Recommendations, and Actions – Diligence and Reasonable Basis,\ninvestment professionals usually deal with a substantial information load, so it is\noften challenging for them to keep pace with industry developments. Employers\ncan help by making sure their employees are regularly informed about changes in\nlaws, rules, regulations, and case law. In most firms, compliance departments or\nlegal advisers can provide this information in a concise, easily digestible form.\nRegular workshops or seminars are also an effective way of keeping staff up to\ndate.\nBut in a busy work environment, some information can easily be missed or\noverlooked. Professionals and their employers should, therefore, carry out regular\nreviews of the company’s compliance procedures to ensure they reflect current\nlaw and provide guidance on permissible conduct."},{"page":129,"text":"• Unconflicted opinions matter: Related to Standard VI(A): Conflicts of Interest –\nDisclosure of Conflicts, professionals need to be aware that when producing\nreports, investment analysis, or client notes, it is easy for personal opinions to\nfilter through and potentially compromise objectivity. To prevent this from\nhappening, employers should establish a clear policy to ensure that every\nresearch report, especially those covering the securities of a corporate client,\nreflects the unbiased opinion of the analyst. Firms should also design\ncompensation systems that encourage integrity in the investment decision-\nmaking process.\n• Beware of contacts bringing gifts: Also related to Standard VI(A), gifts are\nnice, but they often come with strings attached. As such, investment\nprofessionals must restrict their acceptance of gratuities and gifts to only token\nitems. This issue can be a sensitive topic because local customs in many\ncountries perceive the refusal of a gift as impolite; refusing a gift could run the risk\nof damaging business relationships. Therefore, companies should set\nunambiguous guidelines on gifts for employees in each jurisdiction, perhaps by\nsetting a strict value limit or imposing an aggregate annual value ceiling.  Broadly\nspeaking, customary business-related entertainment is acceptable, provided its\npurpose is not to influence or reward, and individual professionals should be able\nto use their experience and judgement to gauge what is acceptable. Accepting a\ncup of coffee or a glass of wine is acceptable; taking a bottle of vintage\nchampagne is not.\nNow that we have described several key principles of professional conduct contained in\nthe CFA Institute Code of Ethics and Standards of Professional Conduct, we will explore\na case study to help bring these principles to life.\nCase Study 1: Cross-Referral of Clients\nRaphael, an investment adviser for the fictional firm Enright Financial Solutions (EFS),\nenters into an understanding regarding the referral of clients with a friend, who is a\nlawyer.\nRaphael will refer EFS clients needing legal services to the lawyer in return for the\nlawyer recommending clients needing financial advisory services to\nRaphael and EFS.\nWhat do you think of this arrangement?"},{"page":130,"text":"a. It is acceptable because there are no payments involved.\nb. It is acceptable as long as the lawyer discloses the arrangement to the clients he\nrefers to Raphael.\nc. It is acceptable as long as EFS is aware of Raphael’s agreement with the lawyer.\nd. It is unacceptable.\nLet’s take a look at which option is correct and which options are incorrect.\nChoice A\nOption A is incorrect. Although this choice addresses the need for disclosure, it places\nthe onus of disclosure on the lawyer and not on Raphael. Standard VI(C) requires\nRaphael to disclose the referral arrangement to any clients he refers to the lawyer and\nany potential clients referred to him by his friend.\nChoice B\nOption B is incorrect. Although this choice also addresses the disclosure issue by\ncorrectly stating that Raphael must disclose the arrangement to his employer, it does not\ngo far enough because Standard VI(C) requires disclosure to be made to clients,\nprospective clients, and the employer.\nChoice C\nOption C is incorrect. The facts of the case do not mention whether Raphael has made\nall of the appropriate disclosures required by Standard VI(C). Assuming Raphael has not\nmade the required disclosures to all applicable parties, this arrangement would be\nunacceptable.\nChoice D\nOption D is correct. Although there is no money changing hands between Raphael and\nhis friend in this arrangement, there is mutual consideration and benefit. The fact that no\nmoney is exchanged does not preclude the obligation for disclosure.\nAnalysis\nThis case concerns a mutually beneficial referral arrangement, whereby service\nprofessionals refer clients to one another. Although such an agreement is not\nnecessarily unethical and may ultimately be beneficial for the clients, there is a potential\nfor a conflict of interest that must be disclosed. CFA Institute Standard VI(C): Conflicts of\nInterest – Referral Fees requires members to disclose to their employer, clients, and"},{"page":131,"text":"prospective clients “any compensation, consideration, or benefit received from or paid to\nothers for the recommendation for products of services.” This disclosure allows both\nclients and the employer to evaluate any partiality shown in the recommendation of\nservices and the full cost of those services.\nProfessionalism at the Firm Level\nProfessionalism goes beyond the remit of the individual. There is also the need to\nuphold professionalism at the firm level.\nLearn more about the essential, but non-exhaustive, characteristics of professionalism\nat investment firms outlined in the CFA Institute Code of Ethics and Standards of\nProfessional Conduct:\n• Restrict investments: Related to Standard VI(B): Conflicts of Interest – Priority\nof Transactions, all firms need clear, formal policies covering the timing of\ninvestment transactions by their employees. In particular, firms should require\nprior approval for employee participation in initial public offerings (IPOs), prompt\ndisclosure of investment action taken following any equity offering, and limits on\nany involvement in private placements. There should also be strict supervisory\nprocedures to ensure employees comply with these policies.\n• Diligent and reasonable effort to safeguard independence: Related to\nStandard V(A): Investment Analysis, Recommendations, and Actions – Diligence\nand Reasonable Basis, firms that have developed a strong reputation for financial\nresearch are those that guard their independence. Individual professionals must\ntake the same approach and fiercely defend their integrity. All firms should,\ntherefore, adopt formal written policies that protect the objectivity of their\nresearchers.\n• Responsibilities of supervisors: Related to Standard IV(C): Duties to\nEmployers – Responsibilities of Supervisors, once compliance standards have\nbeen adopted, it can be tempting to sit back and assume employees will remain\nalert to them, which is not always the case. So, firms should appoint a senior\nofficer with compliance oversight responsibilities to enforce their code of ethics\nand all regulations concerning the business. Firms should provide every\nemployee with procedures and policies to report potentially unethical or illegal\nbehavior.\nIn addition, all businesses should operate a no-tolerance policy toward violations.\nCompanies should ensure that all employees are aware of the consequences of\nviolations by distributing a list of potential infringements and associated\nsanctions, up to and including dismissal."},{"page":132,"text":"• Safeguarding the integrity of capital markets: Related to Standard II: Integrity\nof the Capital Markets, firms should thoroughly check the references of all\npotential employees to ensure they are not ineligible to work in the investment\nindustry because of past infractions. Protecting the integrity of the industry and its\nprofessionals is a two-pronged task. First, firms and employees need to ensure\nthey are armed with the right knowledge. Second, that knowledge needs to be put\ninto practice, every day.\nFollowing these guidelines can help ensure the industry, and the professionals working\nwithin it, protect their most valuable asset—their reputation.\nNow that we have described several key principles of professionalism at the firm level\ncontained in the CFA Institute Code of Ethics and Standards of Professional Conduct,\nwe will explore a case study to help bring these principles to life.\nCase Study 2: Misrepresented Return Performance\nProsper Funding (Prosper) is a (fictional) privately owned marketplace lender that\nenables borrowers to obtain unsecured consumer loans and allows investors to\npurchase securities linked to the performance of those loans. Prosper creates individual\naccount pages for each investor on its website, which provides information on the\nconsumer loans, gives the annualized net return (ANR) performance of each investor’s\naccount, and includes a link through which they can invest in Prosper securities.\nProsper calculates the ANR for each investor using an automated process, which was\ndeveloped some years ago by personnel no longer with the firm. ANR results are\nreported prominently on each investor’s online account page.\nAfter several years, Prosper implements a “debt sale program” through which eligible\nnon-performing, charged-off consumer loans linked to Prosper securities are sold.\nBecause of the unforeseen effect of a previous, unrelated change to the original coding\nin the program, Prosper reports an ANR to its clients that excludes the impact of the\nworst-performing securities that they previously held but that have since been sold to\nthird-party debt purchasers. Periodically, Prosper reviews all the computer processes\nused by the company, and through that review, it becomes clear that current employees\nlack an understanding of the ANR calculation process. The review is always general and\nat a high level, and thus Prosper does not identify the error in the ANR calculation.\nBecause of the error, Prosper reports to a majority of its investors that their investments\nare earning up to double the returns they had actually earned."},{"page":133,"text":"When certain affected investors raise questions about the accuracy of the ANR\ncalculations they received, Prosper’s customer service department handles the\ncomplaints and confirms the reported figures were calculated erroneously because of a\nflawed computer program. The customer service employees do not elevate any of these\ncomplaints to Prosper’s product, engineering, or compliance departments. Prosper has\nalso solicited new investors for its securities based on the miscalculated ANR by\nsending hundreds of emails that highlight their (erroneous) ANR performance and has\nrecommended that investors “add funds and build on their solid returns.”\nProsper does not identify the error for several years and discovers it only after receiving\na complaint from a large institutional investor. Prosper notifies investors that it\nmiscalculated and misstated their ANR and provides a current, correct calculation of the\nANR to investors at that time.\nAnalysis\nLearn more about the different Prosper personnel, how certain employees may have\nviolated the CFA Institute Code of Ethics and Standards of Professional Conduct (Code\nand Standards), and why:\n• Employee responsible for the computer program that calculates the ANR:\nProsper’s issues begin with ANR performance that is calculated incorrectly and\nposted to client accounts. The CFA Institute Standard of Professional Conduct\nIII(D): Performance Presentation requires CFA Institute members, and those\nabiding by the Code and Standards, to make reasonable efforts to ensure that\ninvestment performance is presented in a fair, accurate, and complete manner.\nThe ANR is calculated using a computer program that was created many years\nearlier, and over the years, it has developed a defect that leads to dropping\nunderperforming accounts from the calculation. The person currently responsible\nfor calculating the ANR likely did not create the computer program, and they do\nnot understand the program’s process and have not adequately reviewed the\ncalculation method to ensure that it is accurate, thus allowing the error to\ncontinue.\n• Customer service employee responding to client complaints about the\nANR: Although the customer service employee responding to client complaints is\nnot responsible for the ANR calculation error, that employee is responsible for\nacting in accordance with Standard III(A): Duties to Client – Loyalty, Prudence,\nand Care to protect client interests once the issue has been raised. That\nemployee failed to elevate any of the investor complaints to Prosper’s personnel\nresponsible for the calculation and apparently simply recalculated the ANR using"},{"page":134,"text":"the same flawed code. The customer service employee did not engage with or\ninvestigate the client complaints with sufficient reasonable care, diligence,\ncompetence, or professionalism, as required by Standard V(A): Investment\nAnalysis, Recommendations, and Actions – Diligence and Reasonable Basis and\nthe Code of Ethics.\n• Marketing employee using the ANR performance calculations to solicit\ninvestments: The marketing employee using erroneous ANR performance is not\nresponsible for the calculation error. Team members should be able to rely on the\nwork of others in their firm (in this case, those calculating the ANR) to fulfill their\nresponsibilities in an appropriate manner to produce accurate work. But in this\ncase, the marketing employee is ultimately responsible for distributing misleading\ninformation that misrepresents the true performance of the securities, which\nviolates Standard I(C): Professionalism – Misrepresentation. Once the marketing\nemployee becomes aware that the information is inaccurate, that employee must\ntake steps to remediate the error and distribute accurate and complete\ninformation.\n• Compliance employee responsible for firm policies and procedures: The\ncompliance employee has a responsibility to review the firm’s policies and\nprocedures to ensure that they meet relevant regulatory and ethical requirements.\nProsper only sporadically reviews all the computer programs and processes used\nby the company, uses employees who lack an understanding of the ANR\ncalculation process to calculate the ANR performance, and conducts only a high-\nlevel review that would not catch the error in the ANR calculation. Similar to the\ncustomer service employee, the compliance employee did not exercise sufficient\ncare, diligence, competence, or professionalism as required by Standard V(A):\nInvestment Analysis, Recommendations, and Actions – Diligence and\nReasonable Basis and the Code of Ethics to ensure that an adequate compliance\nprogram was in place to address errors or properly investigate problems once\ndiscovered.\n• CEO of Prosper: The Prosper CEO likely has no direct involvement with the\ncalculation and presentation of performance, addressing client complaints, or\ncreating and implementing compliance procedures. But the CEO does have overall\nresponsibility to ensure that the firm complies with the law (Standard I(A):\nProfessionalism – Knowledge of the Law) and protects client interests (Standard\nIII(A): Loyalty, Prudence, and Care) as well as overall supervisory responsibility for\nfirm employees (Standard IV(C): Duties to Client – Responsibilities of Supervisors).\nThe CEO is allowed to delegate this responsibility. But the Code and Standards\nrequire those with supervisory responsibility to make reasonable efforts to ensure\nthat those under their supervision comply with applicable laws and the Code and"},{"page":135,"text":"Standards. The breakdown of the policies and procedures of the firm designed to\naccurately calculate performance, adequately address complaints, and implement\nan appropriate compliance program are all red flags indicating a potential failure of\nthe CEO to properly supervise employees of the firm.\nLesson 8 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nThe fundamental ethical principle to act with independence and objectivity is best upheld\nwhen:\na. client confidentiality is maintained.\nb. personal education and professional development are undertaken.\nc. work and opinions are unaffected by any potential conflict of interest."}]},{"id":"m5-l9","moduleId":"m5","label":"Lesson 9","title":"Benefits of Ethical Conduct and Consequences of Unethical Conduct","pages":[{"page":136,"text":"Lesson 9: Benefits of Ethical Conduct and Consequences of Unethical\nConduct\nWelcome to Lesson 9 of Module 5!\nIn this lesson, you will explore the benefits of ethical conduct as well as the\nconsequences of unethical conduct for various parties in the investment industry and the\neconomy as a whole.\nBy the end of this lesson, you will be able to describe the benefits of ethical conduct and\nthe consequences of conduct that is unethical or unprofessional.\nLet's get started!\nThe Benefits of Ethical Conduct\nUnethical behavior, whether legal or not, can have significant consequences for the\nfinancial system and the economy. Compliance with ethical standards is important to\nprevent financial crises that can affect economic development and society’s welfare.\nAccordingly, one of the benefits of complying with ethical standards is the increased\nstability of the financial system and thus of the entire economy. Importantly, ethical\nstandards complement existing legal obligations, professional standards of conduct, and\norganizational policies and procedures to prevent behavior that can affect other\nindustries and even the global economy.\nLearn more about the beneficial effects of ethical conduct in the investment\nindustry on the market and greater economy:\n• Trust: The liquidity, profitability, and efficiency of markets and economies are\nrooted in trust. Compliance with ethical standards increases trust in investment\nprofessionals and in the entire investment industry.\n• More trust equates to lower transactional friction: Increased investor trust in\nthe investment industry is an outcome of ethical behavior by the industry’s\nprofessionals. It also strengthens the fairness of financial markets. This increased\ntrust increases market participation and market efficiency (by which prices adjust\nquickly to reflect new information about the value of assets in the marketplace),\nwhich, in turn, help investors achieve their investment goals.\n• Greater transactional volume equates to increased liquidity: Increased\nmarket participation benefits all market participants and stakeholders. These\nbenefits include increased liquidity (investors are able to trade assets without\naffecting prices significantly) and increased market efficiency."},{"page":137,"text":"Increased market participation also promotes public awareness and\nunderstanding of the financial system. This understanding, in turn, leads to\nadditional participation in and efficiency of financial markets.\n• Increased market efficiency improves access to both equity and debt\nfinancing: Increased market efficiency and trust can increase access to equity\nand debt funding and decrease the cost of capital for companies and\ngovernments requiring capital. Increasing the availability of capital and\ndecreasing the cost of capital may positively influence the profitability and growth\nof companies as well as the development of the investment industry and the\noverall economy.\n• An ethical environment better aligns the goals of companies and\nemployees: Increased market efficiency and participation can directly support\nthe goals of companies in the investment industry. These goals include economic\nobjectives, such as profitability and share value, and non-economic objectives,\nsuch as reputation and customer satisfaction.\nIn addition, an employee following ethical standards is less likely to take\nexcessive or unauthorized risk or to misappropriate company assets. Such\nmisappropriation can be of tangible assets (for example, using the company car\nfor personal trips without authorization) or intangible assets (for example, sharing\ninformation about customers or company research).\nIf employees behave ethically, their actions are less likely to have far-reaching\n(including legal) consequences for their employers.\nWithout trust, the public is unlikely to use investment professionals to manage\ninvestments, to obtain advice on issues related to financial goals, or to provide services\nto support the overall investment process. Therefore, compliance may enhance\nemployment security and increase certainty in career development.\nComplying with ethical standards may directly and positively affect a professional’s\nposition, compensation, and reputation. It may also provide indirect benefits through the\nincreased reputational and business success of a professional team and entire firm,\nthereby providing long-term career and skill set development opportunities.\nConsequences of Unethical Conduct\nWhen ethical and professional standards are violated, there can be significant\nconsequences. These consequences include failure to achieve goals on behalf of a\nclient or an employer, negative effects on the entire investment industry through reduced\nmarket participation, and a loss of trust in the integrity of financial markets and the"},{"page":138,"text":"investment profession. Such consequences can have long-lasting effects on the\ninvestment industry and the economy.\nConsequences for Industry and Economy\nWhen people in the investment industry act unethically, it can lead to changes in the\nbehavior of market participants. If investors lose trust in the investment industry, they\nmay cease to invest. Potential consequences include companies being unable to raise\ncapital in financial markets, investment firms losing business or even going out of\nbusiness, and the economy slowing down.\nUnethical and/or illegal behavior can be responsible for these kinds of negative\nconsequences.\nExample: Madoff Ponzi Scheme\nFormer US businessman Bernard L. Madoff ignored his duty to put his clients’\ninterests first when he turned an allegedly legitimate wealth management firm into\na Ponzi scheme, in which investors were paid “investment returns” with money\nfrom other investors. Madoff acted deceitfully and defrauded clients. The\nunveiling of this fraud in 2008 resulted in Madoff being sentenced to 150 years in\nprison and caused a widespread loss of investor trust in investment industry\nprofessionals.\nIn addition to the immediate consequences of unethical behavior on companies in\nthe investment industry and their clients, the transmission of financial shocks from\none company to another can be dangerous for interconnected companies and,\npotentially, for the economy and the financial system.\nTherefore, the consequences of unethical behavior at one company can affect\nother companies (and their clients) despite them not being involved in the\nunethical behavior.\nFor example, if a company goes bankrupt as a result of unethical behavior, the\ncompany’s unfulfilled liabilities could result in a widespread crisis for a larger group of\nrelated companies, thereby potentially damaging the economy. Such spillovers or\nfinancial contagion may result in decreased economic output, increased unemployment,\nand reduced long-term economic growth expectations."},{"page":139,"text":"Example: Financial Crisis of 2008\nAs a consequence of unethical behavior—in the form of aggressive mortgage\nlending by some market participants coupled with other financial events—the US\nhousing and stock markets declined in 2008. As a result, the US-based global\ninvestment firm Lehman Brothers went bankrupt. These events led to a liquidity\ncrisis (a shortage of available funds) in the financial markets.\nThe ensuing global financial crisis almost resulted in the bankruptcy of American\nInternational Group (AIG), a large multinational insurance company, which\nrequired a regulatory bailout to survive. The crisis negatively also affected many\nmore companies and reduced the output and growth expectations of several\neconomies around the world. This extreme case demonstrates how unethical\nbehavior, such as aggressive mortgage lending, by some market participants can\nlead to the bankruptcy of a company and a negative impact on other interlinked\ncompanies, their clients, and the entire financial system.\nConsequences for Clients\nWhen people in the investment industry act unethically, clients may suffer both\nfinancially and emotionally. They may receive inappropriate investment advice or\nservices, lose confidence in the investment profession and in financial markets,\nlose personal wealth and current or future income, and experience personal\ndistress.\nUnethical behavior resulting in inappropriate investment advice or services may\nexpose clients to the following:\n● Excessive risks\n● Ownership of unsuitable assets\n● Lack of diversification\n● Inflated costs of investment management services\n● Unjustified transaction and management costs\nFor example, excessive trading of client assets to maximize trading commissions will\nresult in clients incurring excessive transaction costs and may result in clients owning\nassets that are not consistent with their objectives and needs. Because of the central\nrole of trust in a client relationship, the violation of legal and ethical standards generally\ndecreases a client’s trust in investment professionals and possibly in the investment\nindustry as a whole. Violations related to financial market transactions (for example,\ninsider trading) further decrease a client’s trust in the integrity of financial markets."},{"page":140,"text":"In all of these cases of unethical behavior, clients can lose wealth and income.\nFor example, if a client owns shares in an investment bank and there is a trading\nscandal, the value of the shares may fall, and the client may lose money. The client may\nalso suffer a decrease in current income because of lower dividend payments. In\naddition, the client’s future income can be reduced if retirement funds have been\naffected.\nFaced with financial damage to wealth and income, clients can experience a great level\nof personal distress along with severe mistrust in the investment industry, regardless of\nwhether that mistrust is justified or misplaced.\nConsequences for Employers\nFrom an employer’s point of view, the consequences of ethical standard violations\ninclude negative effects on current and future client relationships, loss of reputation and\ncompany value, and legal liabilities and increased scrutiny by regulators, which creates\nadditional administrative and analysis costs. The worst-case scenario includes going out\nof business.\nOften, ethical violations become apparent externally only when the conduct results in\nlegal scrutiny, including threat of lawsuits, legal charges, and prosecution. Because\nclients associate a company’s employees with the company’s brand, illegal or unethical\nconduct can result in a loss of company reputation that can damage or destroy current\nand future client relationships.\nExample: Enron and Barings Bank\nIn some cases, an employer can face closure because of the unethical and/or\nillegal behavior of one or more individuals within the company. US energy and\ncommodity trading company Enron, for instance, collapsed in 2001 as a result of\nunethical, aggressive accounting practices, which were later identified to be\nillegal. As a result, Enron CEO Jeffrey K. Skilling received a 24-year prison\nsentence. In addition, Arthur Andersen, Enron’s audit firm, was negatively\naffected and later dissolved because of questions of integrity with respect to\nsome of its partners involved in the Enron audit.\nIn a different case, unethical and ultimately illegal behavior by former British\nderivatives trader Nicholas Leeson caused losses exceeding GBP800 million,\nresulting in the bankruptcy of the United Kingdom’s oldest investment bank,\nBarings Bank, in 1995. Leeson, who had executed unauthorized trades, was sent\nto prison for six and a half years."},{"page":141,"text":"Interestingly, if the back-office accounting person had refused to comply with\nLeeson’s orders on accounting matters, the losses might have been identified\nearlier when they were significantly lower.\nThese extreme examples show how the unethical behavior of a few individuals\ncan have detrimental effects on coworkers and employers. A loss of reputation\ncan result in a loss of profits and a loss of shareholder value. In cases of illegal\nconduct, a company in the investment industry may be held liable for financial\nlosses sustained by customers or other market participants. If prosecuted, the\nemployer may also be subject to fines, lose their operating licenses, and may be\nobliged to compensate clients or other market participants for financial losses.\nThese consequences can result in additional loss of company value, which is\namplified if the company loses the right to provide some investment services.\nThe employer’s profits may further decrease as a result of expenditures required\nto assess, manage, and prevent future occurrences of compliance failures.\nLastly, a company may become subject to increased regulatory scrutiny and\nrequired to use company resources to administer and provide additional costly\nanalysis and information.\nConsequences for Individuals\nFor the individual, the legal, professional, personal, and economic consequences for\nviolating ethical standards can be significant. In circumstances where there has been a\nbreach of ethical standards that results in legal scrutiny, the individual may be subject to\ncivil or criminal prosecution. The consequences can include expenses to defend a\nprosecution, fines, imprisonment, and loss of current and future employment in the\ninvestment industry. Unethical behavior resulting in legal offences includes investment\nfraud, insider trading, accounting fraud, and unauthorized decision making—all of which\ncan result in significant prison sentences for the perpetrator.\nIn addition to the previously mentioned cases involving Jeffrey Skilling of Enron,\nNicholas Leeson of Barings Bank, and Bernard Madoff, each of whom received long\nprison sentences, other examples illustrate the consequences of unethical and/or illegal\nbehavior for individuals.\nExample: Martha Stewart\nUS businesswoman Martha Stewart was accused of making false statements to\nfederal investigators about a suspiciously timed share sale. Although she was not\ncharged with insider trading, she was charged with conspiracy, obstruction of"},{"page":142,"text":"justice, and perjury. In 2004, she was found guilty of some of these charges and\nsentenced to a five-month prison term and fined USD30,000. In 2007, she settled\na civil action suit for insider trading brought by the US Securities and Exchange\nCommission (SEC) by paying a fine of USD195,000 and accepting a five-year\nban on serving as an officer or director of a public company.\nConsequences for breaches of ethical and professional standards also include\ndisciplinary action by the employer and/or a professional or regulatory body and\ndisapproval from clients, colleagues, and peers within the industry. This discipline can\nresult in the decreased ability to advance a career because of a loss of reputation, which\nhas personal and economic consequences. In particular, the individual can suffer a loss\nof income as a result of a restricted ability to provide current or future services. The\nindividual could also face the loss of job and career, and even alienation of family and\nfriends.\nLesson 9 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nQuestion 1\nWhich of the following outcomes of acting with high ethical standards will most likely\ndirectly benefit both clients and investment professionals?\na. Enhanced employment security\nb. Reduced risk of adverse legal consequences\nc. Increased trust in the fairness of financial markets\nQuestion 2\nWhich of the following is most likely a potential effect of unethical behavior by people in\nthe investment industry?\n\na. Increased employment\nb. Decreased economic output\nc. Decreased regulatory scrutiny"}]},{"id":"m5-l10","moduleId":"m5","label":"Lesson 10","title":"Ethical Decision-Making Framework","pages":[{"page":144,"text":"Lesson 10: Ethical Decision-Making Framework\nWelcome to Lesson 10 of Module 5!\nBy the end of this lesson, you will be able to describe a framework for making ethical\ndecisions.\nLet’s get started!\nIntroduction\nLaws, regulations, codes of ethics, and professional standards of conduct can guide\nethical behavior, but individual judgement is a critical ingredient in making principled\nchoices and engaging in appropriate conduct. One strategy to increase trust in the\ninvestment profession is to increase the ability and motivation of market participants to\nact ethically and help them minimize the likelihood of unethical actions.\nFirms can enhance the ability and the motivation of their employees to act ethically by\nintegrating ethics into all decision-making activities. An investment professional’s natural\ndesire to “do the right thing” can be reinforced by building a culture of integrity and\naccountability in the workplace.\nNote: Development, maintenance, and demonstration of a strong culture of\nintegrity within the firm by senior management may be the single most important\nfactor in promoting ethical behavior among the firm’s employees.\nAdopting a code that clearly lays out the ethical principles that guide the thought\nprocesses and conduct the firm expects from its employees is a critical first step. But a\ncode of ethics, although necessary, is insufficient. We need to exercise ethical decision-\nmaking skills to develop the ability necessary for fundamentally ethical people to make\ngood decisions despite the reality of conflicts.\nA strong ethical culture built on a defined set of ethical principles that helps honest\npeople engage in ethical behavior will foster the trust of investors, lead to robust global\nfinancial markets, and ultimately benefit society. That is why an ethical decision-making\nframework is important.\nThe CFA Institute Ethical Decision-Making Framework\nWhen faced with decisions that can affect multiple stakeholders, investment\nprofessionals must have a well-developed set of principles. Otherwise, their thought\nprocesses can lead to, at best, indecision and, at worst, fraudulent conduct and"},{"page":145,"text":"destruction of the public trust. Establishing an ethical decision-making framework to\nguide an investment professional’s internal thought process regarding how to act is a\ncrucial step to engaging in ethical conduct.\nInvestment professionals are generally comfortable analyzing and making decisions\nfrom an economic (profit/loss) perspective. Given the importance of ethical behavior in\ncarrying out professional responsibilities, it is also important to analyze decisions and\ntheir potential consequences from an ethical perspective.\nLearn more about the benefits of ethical decision-making frameworks:\n1. Using a framework for ethical decision-making will help investment professionals\nto examine their choices effectively in the context of conflicting interests common\nto their professional obligations (e.g., researching and gathering information,\ndeveloping investment recommendations, and managing money for others). Such\na framework provides investment professionals, as well as those that support\nthem, with a tool to help them adhere to a code of ethics and allows them to\nanalyze and choose options to meet high standards of ethical behavior.\n2. By applying the framework and analyzing the particular circumstances of each\navailable alternative, professionals working in the investment industry are able to\ndetermine the best course of action to fulfill their responsibilities in an ethical\nmanner.\n3. An ethical decision-making framework helps a decision maker see the situation\nfrom multiple perspectives and pay attention to aspects of the situation that may\nbe less evident with a short-term, self-focused perspective. The goal of getting a\nbroader picture of a situation is to be able to create a plan of action that is less\nlikely to harm stakeholders and more likely to benefit them.\n4. If a decision maker does not know or understand the effects of her or his actions\non stakeholders, the likelihood of making a decision and taking action that harms\nstakeholders is more likely to occur, even if unintentionally.\n5. Finally, an ethical decision-making framework helps decision makers explain and\njustify their actions to a broader audience of stakeholders.\nAn ethical decision-making framework is designed to facilitate the decision-making\nprocess for all decisions. It helps people look at and evaluate a decision from multiple\nperspectives to identify important issues they might not otherwise consider. Using an\nethical decision-making framework consistently helps professionals develop sound\njudgement and decision-making skills and avoid making decisions that have\nunanticipated ethical consequences. Ethical decision-making frameworks come in many\nforms, with varying degrees of detail."},{"page":146,"text":"Examining an Ethical Decision-Making Framework\nAn ethical decision-making process includes multiple phases, each of which has multiple\ncomponents. The process is often iterative, and the decision maker may move between\nphases in an order different from that presented. For simplicity, we will discuss the\nphases sequentially. A general ethical decision-making framework developed by CFA\nInstitute1 is shown in Exhibit 1.\nExhibit 1: Phases of the CFA Institute Decision-Making Framework\n\n1. Identify: In the first phase, you will want to identify the important facts that you\nhave available to you as well as information that you may not have, but would like\nto have, to give yourself a more complete understanding of the situation.\nο It is helpful to distinguish between facts and personal opinions,\njudgements, and biases.\nο You will also want to identify the stakeholders and the duties you have to\neach of them.\nYou will then identify relevant ethical principles and/or legal requirements\nthat might apply to the situation.\n\n1 The CFA Institute ethical decision-making framework is based on “A Framework for Thinking Ethically”\nfrom the Markkula Center for Applied Ethics at Santa Clara University\n(www.scu.edu/ethics/practicing/decision/framework.html)."},{"page":147,"text":"ο You should also identify any potential conflicts of interest inherent in the\nsituation or conflicts in the duties you hold to others. For example, your\nduty to your client may conflict with your duty to your employer.\n2. Consider: In the second phase of the framework, you will take time to consider\nthe situational influences as well as behavioral biases that could affect your\nthinking and thus decision-making. During this phase, you may seek additional\nguidance from trusted sources, turn to your compliance department for\nassistance, or possibly consult outside legal counsel.\nSeeking additional guidance is a critical step in viewing the situation from different\nperspectives. You should seek guidance from someone, possibly external to the\nfirm, who is not affected by the same situational influences and behavioral biases\nas you are and can, therefore, provide a fresh perspective. You should also seek\nguidance from your firm’s policies and procedures and the CFA Institute Code of\nEthics and Standards of Professional Conduct.2\nA helpful technique can be to imagine how an ethical peer or role model might act\nin the situation.\n3. Act: The third phase of the framework is to decide and act. After all the thinking\nand information collection, it is still “theory” at best. If no action is initiated, nothing\nwill change. At this stage, one should leverage the holistic and thoughtful\npreparation of Phases 1 and 2. Doing so should prevent unnecessary hesitation\nor deliberation.\n4. Finally, subject to the unique circumstances surrounding different situations, the\ntiming of execution can be further fine-tuned to achieve optimal impact.\n5. Reflect: After you have acted on your decision, the fourth phase is to reflect on\nand assess your decision and its outcome:\nο Was the outcome what you anticipated? Why or why not?\nο Had you properly identified all the relevant facts, stakeholders and duties\nowed, relevant ethical principles and/or legal requirements, and conflicts of\ninterest?\nο Had you considered the situational influences?\nο Did you identify behavioral biases that might affect your thinking?\nο Had you sought additional guidance?\nο Had you considered and properly evaluated a variety of alternative\nactions?\n\n2 Please visit cfainstitute.org/ethics for full text of the CFA Institute Code and Standards."},{"page":148,"text":"You may want to reflect on the decision multiple times as the immediate and longer-term\nconsequences of your decision and actions become apparent over time.\nThe ethical decision-making process is often iterative. After identifying the relevant facts\nand considering situational influences, you may, for example, decide that you cannot\ndecide without more information. When faced with such a situation, you may want to do\nthe following:\n● Seek additional guidance on how to obtain the information you need\n● Begin considering alternative actions regarding how to proceed based on\nexpectations of what the additional information will reveal\n● Wait until you have more information, reflect on what you have done and learned\nso far, and start the process over\nApplication of an Ethical Decision-Making Framework\nSometimes situations can be complicated, and multiple iterations may reveal that no\ntotally acceptable solution can be created. Applying an ethical decision-making framework\ncan help you evaluate the situation so you can make the best possible decision.\nUsing an ethical decision-making framework will help you evaluate situations from\nmultiple perspectives, avoid poor decision making, and avoid the consequences that can\nresult from taking an ill-conceived course of action. Using an ethical decision-making\nframework is no guarantee of a positive outcome but may help you avoid making\nunethical decisions.\nAfter all, there is nothing perfect in life. As long as you make a best effort attempt to\nminimize blind spots and act in full alignment with your holistically thorough\nconsideration, you are not likely to be too wrong.\nCase Study: Applying an Ethical Decision-Making Framework\nCarlos experienced the following dilemma:\n1. Several colleagues and their friends from outside of the office go out after work\nwith Carlos, a newly hired employee.\n2. The more experienced employees tell the “new guy” to charge the meal and\ndrinks to the company credit card. Carlos’s colleagues tell him the friends are\n“prospective clients” and that they have charged similar outings on the card\nbefore, and the boss always has always approved the charges.\n3. Carlos is confused. During orientation, the presenter from human resources\nmade it clear that it is against company policy to charge personal expenses on\nthe company’s credit card."},{"page":149,"text":"4. Based on the orientation, he wonders if using the company credit card would be\nwrong. But if it is common practice at his firm, maybe it is okay?\nUsing an ethical decision-making framework may help him make an ethically sound\ndecision.\nLearn more about using the ethical decision-making framework to work through\nCarlos’s dilemma below.\n1. Identify the ethical issue(s) and relevant duties/obligations\nWhat is the ethical dilemma?\nIs it appropriate for Carlos to use the company credit card to pay for the dinner\nwith colleagues and their friends?\nTo whom is a duty owed, or who might be affected by the decision?\nOften a decision is easier if you can put a face to the party that might be affected.\nCarlos owes a duty to his employer, which includes displaying loyalty, following\nits policies, and acting with integrity. His decision will potentially affect his\nrelationships with his employer, his boss, and his colleagues.\nAre any duties in conflict, and which duty takes precedence?\nIn some situations, duties to multiple parties may exist for the individual facing the\ndilemma. In this case, Carlos’s sole duty is to his employer.\n2. Identify conflicts of interest\nAre personal interests affecting the decision/action?\nIn this case, Carlos may struggle with wanting to fit in with his new colleagues\nversus following his understanding of the policies of the employer.\n3. Get the relevant facts\nWhat are the relevant facts in the situation?\nDuring Carlos’s orientation, limitations on the use of the company credit card\nwere identified. During the dinner, more experienced colleagues told Carlos it is\nokay to use the card for business expenses of this nature. The friends were\nidentified by them as prospective clients.\nAre there any facts not known that should be known?"},{"page":150,"text":"Carlos would like to know the company policies on allowable client entertainment\nexpenses and for classifying and documenting someone as a potential client. He\nwould like to know if the friends are, in fact, prospective clients.\nThe following are other questions that might be asked in fact gathering:\n• What resources are available to learn more about the situation?\n• Is there enough available information to make a decision?\nIn this situation, Carlos does not have the luxury of gathering more information\nabout the policy. Carlos may wonder if the friends actually represent prospective\nclients for the company but may find it difficult to question his colleagues further.\nAs a result of the orientation, Carlos is concerned that charging the meal to the\ncard may be in violation of the company policy and be unethical.\n4. Identify applicable ethical principles\nWhat are the fundamental ethical principles involved in the situation?\nCarlos is expected to act with integrity in using the resources of his employer. He\nshould use reasonable care in determining whether the friends actually represent\nprospective clients. He should use independent judgement. He should treat his\ncolleagues with respect, but this does not mean he cannot question their guidance.\n5. Consider factors that could be affecting judgement\nWhat factors are affecting judgement?\nOutside factors, such as authority figures, a vocal group, and incentives, can\naffect judgement. Internal factors, such as overconfidence and rationalization,\ncan also affect judgement. Carlos may be influenced by his more experienced\ncolleagues. He may rationalize that it is just one dinner and thus unimportant. He\nshould pause and think through his decision before acting.\n6. Consider and evaluate alternative actions\nWhat are the options? Have creative options been identified?\nCarlos’s options include the following:\na. Complying with his colleagues’ request and charging the dinner to the\ncompany card.\nb. Complying with his colleagues’ request and charging the dinner to the\ncompany card but indicating that he will speak to the boss about it the next\nday."},{"page":151,"text":"c. Charging the dinner to his personal card.\nd. Charging the dinner to his personal card and indicating that he will speak\nto the boss about it the next day.\ne. Declining and suggesting that it is better for a more senior colleague to\ncharge the dinner.\nf. Declining and suggesting that those in attendance split the bill.\nWhat criteria affect choosing among the options? How should conflicts of interest be\nmanaged? How will an alternative affect the relevant parties identified in Step 1?\nCarlos wants to behave ethically and abide by company policy. He also wants to\nbe on good terms with his colleagues. If Carlos chooses to pay with either the\ncompany card or his personal credit card and talk to the boss, he may end up\npaying the entire bill personally. He may not be willing or able to do this.\nFurthermore, if he ends up paying the entire bill personally, he may distrust his\ncolleagues and their advice in future. If he indicates that he is going to speak with\nthe boss or declines to pay, it has consequences for his relationships with his\ncolleagues. They may not view him as a trusted member of the team. Speaking to\nthe boss may affect his colleagues.\nPaying also has consequences for his relationships. The colleagues may lose\nrespect for him, and his boss may disapprove. This consequence may result in\ncensure or even dismissal.\nIf a particular alternative were shared with a respected individual or reported to a\nwider audience, what might be the expected response?\nThe orientation should lead Carlos to understand that using the company card is\nunacceptable and would reflect poorly on him. Carlos might be uncomfortable\nsharing the decision to charge the company card.\n7. Consider seeking additional guidance\nWould discussing the issues with a supervisor, colleagues, or legal (compliance)\npersonnel be appropriate or helpful?\nSeeking guidance to gather more facts about company policy or discussing the\nissue with a supervisor, colleague, or compliance officer would be helpful but is\nnot possible in this case. Carlos has to make a decision and act now based on\nthe information available."},{"page":152,"text":"8. Act and review the outcome\nAfter making his decision, Carlos should take the time to reflect on how his\ndecision turned out and what he has learned from this specific situation. He\nshould also apply what he learned to future dilemmas he will experience in the\ncourse of his work.\nLesson 10 Knowledge Check\nThe following knowledge check is designed to reinforce your understanding of the\nconcepts taught in this lesson. It is ungraded, but you are strongly encouraged to\ncomplete it.\nThe last step in an ethical decision-making process should be to:\na. assess how a decision turned out and learn from it.\nb. assess how others might view a possible course of action.\nc. determine whether the decision is affected by outside factors."}]},{"id":"m5-summary","moduleId":"m5","label":"Summary","title":"Module 5 Summary","pages":[{"page":153,"text":"Module 5 Summary\nIn this module, we discussed professionalism and its impact on the industry and\ninvesting.\nProfessions are occupational groups that have specific education, expert knowledge,\nand a framework of practice and behavior that underpins community trust, respect, and\nrecognition. Most professions emphasize an ethical approach, the importance of good\nservice, and empathy with the client\n● For a profession to be deemed credible, it must be viewed as trustworthy by\nclients, participants, and society in general. Professions can establish trust\nthrough a variety of activities, including the following:\n○ Developing codes of ethics and standards of conduct designed to\nnormalize practitioner behavior and encourage high educational and\nethical standards. Regulators typically support professional ethics and\nrecognize the framework for ethics that professions can provide.\n○ Providing a service to society by widening access to services and\nsupporting economic activity by encouraging trust in both the industry at\nlarge and the professionals within it.\n○ Encouraging professionals to place the integrity of their profession and the\ninterests of their clients above their own personal interests.\n○ Ensuring high entry standards for professionals and that future\nprofessionals are equipped to be competent in their knowledge, technical\nskills, and ethics.\n○ Encouraging the development and dissemination of a professional body of\nexpert knowledge.\n○ Encouraging and facilitating the continuing professional development of its\nprofessionals.\n○ Holding professionals accountable for their conduct through self-regulatory\nactions, including monitoring and imposing sanctions in instances of\nmisconduct.\n○ Encouraging a collegial and respectful environment among professionals\nwithin the workplace."},{"page":154,"text":"We then explored some specific elements in the CFA Institute Code of Ethics and\nStandards of Professional Conduct, to which its membership is held accountable,\nincluding the following:\n● Understanding the laws and rules that govern the industry.\n● Consistently maintaining independence and objectivity in work practices.\n● Never knowingly making misrepresentations in analysis, recommendations, or\nother activities.\n● Avoiding the perception of misconduct by not engaging in any dishonest,\nfraudulent, or deceitful activity that can reflect adversely on the individual’s\nreputation, integrity, or competence.\n● Staying up-to-date by completing compliance-related training provided by or\nrequired in organizations and conducting regular reviews of corporate\ncompliance procedures to ensure they reflect current law and provide\nguidance on permissible conduct.\n● Ensuring that objectivity is not compromised by inclusion of personal opinions\nin investment analysis, reports, client notes, and other activities, such as\nacceptance of gratuities and gifts that could create or be perceived as a\nconflict of interest.\nWe explored the benefits of ethical conduct, consequences of unethical or\nunprofessional conduct, and a framework that can be used for making ethical decisions.\n● Unethical behavior, whether legal or not, can have significant consequences\nfor the financial system and the economy. Compliance with ethical standards\nis important to prevent financial crises that can affect economic development\nand society’s welfare.\n● The liquidity, profitability, and efficiency of markets and economies are rooted in\ntrust. Trustworthy behavior increases investor trust, strengthens the fairness of\nthe markets, and encourages and supports market participation and efficiency.\n● The establishment of ethical cultures within organizations can help to better\nalign the goals of companies and employees and decrease misconduct and\npotential for conflicts of interest.\n● When ethical and professional standards are violated, there can be significant\nconsequences, including failure to achieve goals on behalf of a client or an\nemployer, negative effects on the entire investment industry through reduced\nmarket participation, and a loss of trust in the integrity of financial markets and\nthe investment profession."},{"page":155,"text":"● Laws, regulations, codes of ethics, and professional standards of conduct can\nguide ethical behavior, but individual judgement is a critical ingredient in\nmaking principled choices and engaging in appropriate conduct.\n● When faced with ethical dilemmas and decisions that can affect multiple\nstakeholders, investment professionals must have a well-developed set of\nprinciples. Establishing an ethical decision-making framework is a crucial step\nin engaging in ethical conduct.\n● Using an ethical decision-making framework consistently can help investment\nprofessionals develop sound judgement and avoid making decisions that have\nunanticipated ethical consequences.\n● The CFA Institute Ethical Decision-Making Framework presents four key\nphases of ethical decision making, which may be done in an iterative process:\n○ Identify the important facts or additional information needed to make an\ninformed decision, the fundamental ethical principle potentially at issue,\nto whom a duty is owed, and any potential conflicts of interest at play.\n○ Consider situational influences or biases that may affect decision-\nmaking, brainstorm alternative actions and solutions at an individual\nlevel, and seek objective feedback and perspective from others.\n○ Determine the most appropriate course of action (which may also include\nnot taking an action or elevating concerns to a higher authority), and act.\n○ Reflect on what was learned in the process, regardless of outcome, and\nuse the lessons learned to improve future ethical decision making.\nFinally, we looked at how ethics and regulation are key forces driving the investment\nindustry. Trust, the importance of rules and regulations, and the benefits that ethical\ndecision-making bring to the investment industry and society at large were significant\nthemes we covered.\nTrust is essential to the functioning of the investment industry as well as to the broader\nfinancial services industry. Trust depends on participants complying with rules and\nacting ethically. Increased trust in the fairness of financial markets and the ethical\nconduct of market participants leads to increased market participation. Increased market\nparticipation leads to increased liquidity, market efficiency, and availability of capital at a\nreduced cost. As a result, the overall economy thrives.\n●\nRegulations are rules carrying the force of law that are set and enforced by\nlegislative bodies and other entities authorized by legislative bodies. It is\nimportant that all investment industry participants comply with relevant\nregulations. Those that fail to do so face sanctions that can be severe."},{"page":156,"text":"●\nFinancial services and products are highly regulated because a failure or\ndisruption in the financial services industry, which includes the investment\nindustry, can have catastrophic consequences for individuals, companies, and\nthe economy.\n●\nRegulation is necessary for many reasons, including to protect consumers; to\nfoster capital formation and economic growth; to support economic stability; to\npromote fair, efficient, and transparent financial markets; and to improve society.\n●\nThe types of regulations that have been developed in response to perceived\nneeds include rules on gatekeeping, operations, disclosure, sales practice,\ntrading, anti-money-laundering, and business continuity planning."}]}],"exercises":[{"id":"m1-l1-q1","moduleId":"m1","sectionId":"m1-l1","title":"Lesson 1 Knowledge Check · Question 1","level":1,"type":"single","page":9,"question":"GlobalBank credits Krause’s account for USD100,000 and makes a USD50,000 loan to a new customer. This means that GlobalBank is a:","options":[["a","provider of capital"],["b","user of capital"],["c","both"]],"answer":["c"],"feedback":"GlobalBank is a user of capital when it credits Krause’s account and a provider of capital when it makes a loan to the new customer."},{"id":"m1-l2-q1","moduleId":"m1","sectionId":"m1-l2","title":"Lesson 2 Knowledge Check · Question 1","level":1,"type":"multiple","page":14,"question":"The investment industry benefits the economy by providing: Select all that apply.","options":[["a","Liquidity"],["b","Relevant financial information"],["c","Capital gains"]],"answer":["a","b"],"feedback":"The reading identifies market liquidity and access to financial data needed to evaluate investment opportunities as benefits; capital gains are a potential outcome of investing, not a structural feature of markets."},{"id":"m1-l3-q1","moduleId":"m1","sectionId":"m1-l3","title":"Lesson 3 Knowledge Check · Question 1","level":1,"type":"single","page":18,"question":"Investors benefit in many ways from a well-functioning investment industry. Which of the following is not a benefit?","options":[["a","Access to a diverse range of investment products structured to meet investor needs"],["b","Availability of investment management and advisory services"],["c","Low market volatility"],["d","Access to financial and economic data"],["e","Fair competitive pricing in liquid markets"]],"answer":["c"],"feedback":"The reading explains that market volatility is not necessarily low in a well-functioning investment industry."},{"id":"m1-l4-q1","moduleId":"m1","sectionId":"m1-l4","title":"Lesson 4 Knowledge Check · Question 1","level":2,"type":"single","page":24,"question":"Primo Company needs to raise capital by issuing stock.","options":[["a","Buy-side analyst"],["b","Investment bank"],["c","Financial planner"],["d","Broker/dealer"],["e","Custodian"]],"answer":["b"],"feedback":"The Primo Company needs the assistance of an investment bank to issue new stock."},{"id":"m1-l4-q2","moduleId":"m1","sectionId":"m1-l4","title":"Lesson 4 Knowledge Check · Question 2","level":2,"type":"single","page":25,"question":"Zhang Li, a retail investor, needs to invest assets now to cover future expenses, such as her son’s college tuition and her retirement.","options":[["a","Investment bank"],["b","Broker/dealer"],["c","Custodian"],["d","Buy-side analyst"],["e","Financial planner"]],"answer":["e"],"feedback":"Zhang Li needs a financial planner to assist with the investment of her assets for her financial future."},{"id":"m1-l4-q3","moduleId":"m1","sectionId":"m1-l4","title":"Lesson 4 Knowledge Check · Question 3","level":2,"type":"single","page":25,"question":"Peter Robinson, asset manager for Aus Ltd., needs the latest market research to decide which investments to make on behalf of his clients.","options":[["a","Custodian"],["b","Investment bank"],["c","Broker/dealer"],["d","Financial planner"],["e","Buy-side analyst"]],"answer":["e"],"feedback":"Peter Robinson needs a buy-side analyst to provide the information and advice needed to invest on behalf of his clients."},{"id":"m1-l4-q4","moduleId":"m1","sectionId":"m1-l4","title":"Lesson 4 Knowledge Check · Question 4","level":2,"type":"single","page":25,"question":"Mike Smith, a high-net-worth investor, needs various advisory and trading-related services.","options":[["a","Buy-side analyst"],["b","Investment bank"],["c","Financial planner"],["d","Broker/dealer"],["e","Custodian"]],"answer":["d"],"feedback":"Mike Smith needs the help of a broker or dealer for advisory and trading-related services."},{"id":"m1-l4-q5","moduleId":"m1","sectionId":"m1-l4","title":"Lesson 4 Knowledge Check · Question 5","level":2,"type":"single","page":25,"question":"Anna Huber, an investor at Euro Pension Fund, needs to have her firm’s securities held with accompanying account statements for their records.","options":[["a","Investment bank"],["b","Broker/dealer"],["c","Custodian"],["d","Buy-side analyst"],["e","Financial planner"]],"answer":["c"],"feedback":"Anna Huber needs a custodian to safeguard her firm's securities and account statements."},{"id":"m2-l1-q1","moduleId":"m2","sectionId":"m2-l1","title":"Lesson 1 Knowledge Check · Question 1","level":1,"type":"multiple","page":37,"question":"Which of the following are considered sell-side firms? Select all that apply.","options":[["a","Front office brokers"],["b","Investment banks"],["c","Sovereign funds"]],"answer":["a","b"],"feedback":"Brokers and investment banks primarily provide investment products and services and are examples of sell-side firms. Sovereign wealth funds are buy-side institutional investors."},{"id":"m2-l1-q2","moduleId":"m2","sectionId":"m2-l1","title":"Lesson 1 Knowledge Check · Question 2","level":2,"type":"single","page":38,"question":"Categorize the following activity as taking place in the front office, middle office, or back office: The account manager discusses a tax issue with a client’s tax accountant (who works for another firm).","options":[["A","Front office"],["B","Middle office"],["C","Back office"]],"answer":["A"],"feedback":"Because the tax accountant represents the client’s interests, this is a client-facing activity and is considered front office."},{"id":"m2-l1-q3","moduleId":"m2","sectionId":"m2-l1","title":"Lesson 1 Knowledge Check · Question 3","level":2,"type":"single","page":38,"question":"Categorize the following activity as taking place in the front office, middle office, or back office: The firm’s risk manager prepares a quarterly assessment of the client’s exposure to risk factors.","options":[["A","Front office"],["B","Middle office"],["C","Back office"]],"answer":["B"],"feedback":"Internal risk management is generally invisible to the client but is a core activity of the firm, so it is middle office."},{"id":"m2-l1-q4","moduleId":"m2","sectionId":"m2-l1","title":"Lesson 1 Knowledge Check · Question 4","level":2,"type":"single","page":38,"question":"Categorize the following activity as taking place in the front office, middle office, or back office: Thanks to efficient administrative and operational controls, the firm experiences very few losses due to errors.","options":[["A","Front office"],["B","Middle office"],["C","Back office"]],"answer":["C"],"feedback":"Administration and operational controls are housed in the back office."},{"id":"m2-l2-q1","moduleId":"m2","sectionId":"m2-l2","title":"Lesson 2 Knowledge Check · Question 1","level":1,"type":"single","page":42,"question":"To fulfill orders given to them by portfolio managers, buy-side traders work with sell-side traders to arrange and execute trades.","options":[["a","True"],["b","False"]],"answer":["a"],"feedback":"The reading gives the example of a buy-side trading desk contacting a sell-side brokerage house; sell-side traders find a buyer and execute the trade."},{"id":"m2-l3-q1","moduleId":"m2","sectionId":"m2-l3","title":"Lesson 3 Knowledge Check","level":1,"type":"single","page":48,"question":"Banks take deposits from their customers and then use the funds to make loans. From a bank’s perspective, deposits represent:","options":[["a","debt obligations that the bank must repay."],["b","a source of exposure to default risk."],["c","proof of financial stability."]],"answer":["a"],"feedback":"The bank’s customers are essentially making loans to the bank; deposits are therefore debt obligations the bank must repay."},{"id":"m2-l3-moral","moduleId":"m2","sectionId":"m2-l3","title":"Source activity · Insurance risks","level":2,"type":"single","page":48,"question":"Based on the above list of insurable risks, which of these is Jon guilty of committing: fraud, moral hazard, or adverse selection?","options":[["a","Fraud"],["b","Moral hazard"],["c","Adverse selection"]],"answer":["b"],"feedback":"The source defines moral hazard as being less careful about avoiding losses after purchasing insurance. Jon changes from safe sports to scuba diving and skydiving after buying life insurance."},{"id":"m3-l1-q1","moduleId":"m3","sectionId":"m3-l1","title":"Lesson 1 Knowledge Check · Question 1","level":1,"type":"matching","page":56,"question":"Match the active and passive investment managers with their investment objective.","pairs":[{"key":"passive","label":"Passive managers","answer":"b"},{"key":"active","label":"Active managers","answer":"a"}],"matchOptions":[["a","Seek to outperform a benchmark by analyzing the securities it tracks and investing in them selectively."],["b","Seek simply to match the return of a benchmark."]],"feedback":"Passive managers seek simply to match the return of a benchmark. Active managers seek to outperform a benchmark by analyzing the securities it tracks and investing in them selectively."},{"id":"m3-l1-q2","moduleId":"m3","sectionId":"m3-l1","title":"Lesson 1 Knowledge Check · Question 2","level":2,"type":"single","page":56,"question":"After analyzing the risk and return characteristics of appropriate asset classes, investment managers construct client portfolios that reflect the relative attractiveness of current pricing and:","options":[["a","provide maximum income."],["b","correctly represent client goals and constraints."],["c","offer downside protection."]],"answer":["b"],"feedback":"Client goals and constraints determine how analysis of asset classes and securities is applied to construct the investment portfolio."},{"id":"m3-l2-q1","moduleId":"m3","sectionId":"m3-l2","title":"Lesson 2 Knowledge Check","level":1,"type":"single","page":61,"question":"Which of the following research reports have no obvious conflicts of interest?","options":[["a","Reports written by internal brokerage house analysts and provided at no charge to brokerage customers"],["b","Research reports sold directly to investors by independent research firms"],["c","Credit reports written by credit rating agencies that charge the company being rated for the research and rating"]],"answer":["b"],"feedback":"The reading identifies no obvious conflict of interest for independent research firms because they are economically motivated to deliver quality reports clients will pay for."},{"id":"m3-l3-q1","moduleId":"m3","sectionId":"m3-l3","title":"Lesson 3 Knowledge Check · Question 1","level":1,"type":"single","page":70,"question":"Which of the following services is not performed by a broker?","options":[["a","Finding counterparties for clients who want to buy or sell a security"],["b","Routing small trades in highly liquid securities to an exchange"],["c","Using a proprietary portfolio to transact directly with the client when it is in the client’s best interest."]],"answer":["c"],"feedback":"Dealers use proprietary portfolios and act as principals; brokers act as agents and arrange trades."},{"id":"m3-l3-q2","moduleId":"m3","sectionId":"m3-l3","title":"Lesson 3 Knowledge Check · Question 2","level":1,"type":"single","page":70,"question":"Which of the following services are not provided by custodians and depositories?","options":[["a","Safekeeping and recordkeeping"],["b","Trade settlement"],["c","Dividend collection"],["d","Credit rating analysis"]],"answer":["d"],"feedback":"Custodians and depositories do not provide credit ratings or investment analysis; they provide safekeeping, recordkeeping, settlement, and process cash flows such as dividends."},{"id":"m4-l1-q1","moduleId":"m4","sectionId":"m4-l1","title":"Lesson 1 Knowledge Check","level":1,"type":"single","page":76,"question":"True or False: Most investors seek professional assistance when they lack the necessary expertise, information, and systems support to do their own financial planning and asset management.","options":[["a","True"],["b","False"]],"answer":["a"],"feedback":"The reading explains that financial skills and systems support can take considerable time and money to acquire, and lists planning, analysis, portfolio construction, risk management, and performance services."},{"id":"m4-l2-q1","moduleId":"m4","sectionId":"m4-l2","title":"Lesson 2 Knowledge Check","level":1,"type":"multiple","page":78,"question":"Which of the following inputs do financial planners use to help investors anticipate future expenditures and develop appropriate saving and investment strategies that reinforce financial security in retirement? Select all that apply.","options":[["a","Life expectancy"],["b","Educational attainment"],["c","Inflation"],["d","Investment returns"]],"answer":["a","c","d"],"feedback":"The reading identifies life expectancy, inflation, and investment returns as inputs in financial planning models; educational attainment does not directly influence savings and investment decisions."},{"id":"m4-l3-q1","moduleId":"m4","sectionId":"m4-l3","title":"Lesson 3 Knowledge Check","level":1,"type":"multiple","page":81,"question":"Which of the following are served by fintech or AI applications? Select all that apply.","options":[["a","Automation of routine functions"],["b","Portfolio construction"],["c","Loan credit analysis"],["d","Implementation of trading strategies"]],"answer":["a","b","c","d"],"feedback":"All listed processes are served by fintech and AI applications according to the reading."},{"id":"m4-l4-coffee","moduleId":"m4","sectionId":"m4-l4","title":"Source activity · Big Data","level":2,"type":"matrix","page":84,"question":"If a financial analyst is trying to determine the likely profitability of a chain of coffee shops, what data could be useful? Review each form of data and select “Yes,” “No,” or “Unlikely.”","matrixRows":[["r1","Structured data from the firm’s financial statements","Yes"],["r2","Management expertise","Yes"],["r3","The volume of pedestrian traffic past the shops","Yes"],["r4","The demographics of those pedestrians","Yes"],["r5","The height of the pedestrians","Unlikely"],["r6","Voting habits of the pedestrians","Unlikely"]],"matrixOptions":["Yes","No","Unlikely"],"feedback":"The source treats financial statements, management expertise, pedestrian volume, and demographics as useful; height and voting habits are marked “Unlikely.”"},{"id":"m4-l4-ai","moduleId":"m4","sectionId":"m4-l4","title":"Source activity · AI and complex relationships","level":2,"type":"single","page":85,"question":"Is AI valuable when dealing with complex and nonlinear relationships that are beyond the scope of traditional quantitative methods and statistical analysis?","options":[["a","Yes"],["b","No"]],"answer":["a"],"feedback":"Yes. The reading states that AI-based techniques enable new data-analysis approaches, including sorting large amounts of filing, report, and earnings-call data to uncover trends and sentiment."},{"id":"m4-l4-q1","moduleId":"m4","sectionId":"m4-l4","title":"Lesson 4 Knowledge Check","level":2,"type":"single","page":92,"question":"Decentralized finance refers to financial products and services that promise to eliminate what are seen as inefficiencies in centralized financial systems. Which of the following criticisms is not associated with traditional, centralized financial systems?","options":[["a","Centralized controls can lead to complex and costly operational infrastructure."],["b","In some markets, the high costs associated with building and staffing physical banks result in limited access to banking services."],["c","Money laundering regulations impede small cash transactions."],["d","Interoperability—the ability of service providers to interact smoothly across their various financial platforms—is constrained when institutions have different software systems and accounting protocols."]],"answer":["c"],"feedback":"The reading says money laundering is illegal and that small cash transactions are not normally considered unusual activity; the other choices are associated with centralized systems."},{"id":"m5-l1-q1","moduleId":"m5","sectionId":"m5-l1","title":"Lesson 1 Knowledge Check","level":1,"type":"multiple","page":101,"question":"Laws and regulations that promote integrity, transparency, and fairness in financial markets are necessary for which of the following reasons? Select all the correct choices that apply.","options":[["a","Regulations are needed to assure investors that they will be treated fairly."],["b","Investors who lack confidence in the financial markets will be reluctant to invest, raising the costs for seekers of capital to find providers."],["c","Regulations create global standards for determining fair prices."]],"answer":["a","b"],"feedback":"The reading states that regulations help assure fair treatment and sustain confidence; fair pricing is determined by willing buyers and sellers in liquid, well-functioning markets, not by regulation."},{"id":"m5-l2-q1","moduleId":"m5","sectionId":"m5-l2","title":"Lesson 2 Knowledge Check","level":1,"type":"single","page":103,"question":"True or False: Regulations are rules that set standards for conduct and carry the force of law. They can be used as effective tools to reinforce ethical principles and professional standards.","options":[["a","True"],["b","False"]],"answer":["a"],"feedback":"Financial regulations reinforce ethical behavior and attach a cost to unethical practices."},{"id":"m5-l3-q1","moduleId":"m5","sectionId":"m5-l3","title":"Lesson 3 Knowledge Check","level":1,"type":"single","page":107,"question":"In addition to reinforcing ethical principles and standards, regulations are needed when market solutions are not sufficient to meet economic and societal goals. Which of the following is not a broad objective of regulation?","options":[["a","Consumer protection"],["b","Capital formation and economic growth"],["c","Population growth"],["d","Economic stability"]],"answer":["c"],"feedback":"Population growth is not a broad objective of financial regulation; the reading identifies consumer protection, capital formation/economic growth, and economic stability as objectives."},{"id":"m5-l4-q1","moduleId":"m5","sectionId":"m5-l4","title":"Lesson 4 Knowledge Check · Question 1","level":2,"type":"single","page":113,"question":"Regulatory failures undermine investor confidence in the financial system and the willingness to engage in transactions. Which of the following is not an example of regulatory failure?","options":[["a","For an extended period of time, margin deposits at a futures exchange remain below the minimum levels required by regulators. Failure to identify and correct the inadequate capital levels results in a major loss to the exchange."],["b","A bank whose net capital has fallen below regulatory minimums continues to make high-risk loans. When the economy slows and borrowers’ default, the bank announces that it will be unable to fully repay its depositors."],["c","A brokerage firm is confronted by clients who believe that the firm should have advised them to sell their holdings of Deepdive Corporation before the stock market dropped."]],"answer":["c"],"feedback":"Brokers act as agents and are not responsible for subsequent portfolio performance or the timing of purchases and sales."},{"id":"m5-l4-q2","moduleId":"m5","sectionId":"m5-l4","title":"Lesson 4 Knowledge Check · Question 2","level":2,"type":"single","page":114,"question":"Regulations that attempt to prevent market manipulation are examples of:","options":[["a","trading rules."],["b","operational rules."],["c","sales practice rules."]],"answer":["a"],"feedback":"Trading rules focus on trading practices and activity to ensure fair, organized, and efficient markets; market manipulation involves actions intended to move a stock price for short-term profit."},{"id":"m5-l5-q1","moduleId":"m5","sectionId":"m5-l5","title":"Lesson 5 Knowledge Check","level":1,"type":"single","page":117,"question":"The consequences of failure to comply with regulations and corporate policies and procedures:","options":[["a","include costs to only the firm and employees."],["b","range from individual costs to damage to the global economy."],["c","are borne by the employee who failed to comply and not by the employee’s supervisor or employer."]],"answer":["b"],"feedback":"The reading explains that consequences can be far-reaching, affecting individuals, firms, customers, the industry, and the economy."},{"id":"m5-l6-q1","moduleId":"m5","sectionId":"m5-l6","title":"Lesson 6 Knowledge Check","level":1,"type":"single","page":122,"question":"Regulations cannot anticipate every situation in which questions of integrity or fairness will arise. For this reason, individuals and institutions should be guided by ethical principles and a culture of ethical behavior. Which of the following should not be considered a reliable source of guidance for the application of ethical principles?","options":[["a","Professional standards addressing activities specific to the financial industry"],["b","Financial regulations carrying the force of law"],["c","Peer group behavior"],["d","Corporate policies and procedures designed to promote ethical behavior"]],"answer":["c"],"feedback":"Peer-group behavior can influence decision-making but may not be aligned with ethical conduct or professional standards."},{"id":"m5-l7-q1","moduleId":"m5","sectionId":"m5-l7","title":"Lesson 7 Knowledge Check","level":1,"type":"single","page":126,"question":"According to fundamental ethical and professional principles applicable to the investment industry, which group should have their interests ranked first?","options":[["a","Clients"],["b","Employers"],["c","Coworkers"]],"answer":["a"],"feedback":"Individuals working in the investment industry have the obligation to place client interests ahead of personal interests or the interests of employers."},{"id":"m5-l8-q1","moduleId":"m5","sectionId":"m5-l8","title":"Lesson 8 Knowledge Check","level":2,"type":"single","page":135,"question":"The fundamental ethical principle to act with independence and objectivity is best upheld when:","options":[["a","client confidentiality is maintained."],["b","personal education and professional development are undertaken."],["c","work and opinions are unaffected by any potential conflict of interest."]],"answer":["c"],"feedback":"Conflicts of interest can adversely affect objectivity and independence by creating a bias that may affect judgement."},{"id":"m5-l9-q1","moduleId":"m5","sectionId":"m5-l9","title":"Lesson 9 Knowledge Check · Question 1","level":2,"type":"single","page":142,"question":"Which of the following outcomes of acting with high ethical standards will most likely directly benefit both clients and investment professionals?","options":[["a","Enhanced employment security"],["b","Reduced risk of adverse legal consequences"],["c","Increased trust in the fairness of financial markets"]],"answer":["c"],"feedback":"High ethical standards increase clients’ trust in fair financial markets and promote efficiency; greater trust also makes clients more likely to seek professional advice."},{"id":"m5-l9-q2","moduleId":"m5","sectionId":"m5-l9","title":"Lesson 9 Knowledge Check · Question 2","level":2,"type":"single","page":142,"question":"Which of the following is most likely a potential effect of unethical behavior by people in the investment industry?","options":[["a","Increased employment"],["b","Decreased economic output"],["c","Decreased regulatory scrutiny"]],"answer":["b"],"feedback":"Unethical behavior can reduce investor confidence and the availability of capital to companies, leading to decreased economic output."},{"id":"m5-l10-q1","moduleId":"m5","sectionId":"m5-l10","title":"Lesson 10 Knowledge Check","level":2,"type":"single","page":152,"question":"The last step in an ethical decision-making process should be to:","options":[["a","assess how a decision turned out and learn from it."],["b","assess how others might view a possible course of action."],["c","determine whether the decision is affected by outside factors."]],"answer":["a"],"feedback":"The last step should be to assess how the decision turned out and learn from it."}],"glossary":[{"term":"Active investment managers","definition":"Investment managers who try to predict which securities and assets will outperform or underperform comparable securities and assets and who act on their opinions by buying the securities and assets that they expect to outperform and selling (or simply not buying) the securities and assets that they expect to underperform.","glossaryPage":1,"origin":{"sectionId":"m3-l1","moduleId":"m3","sectionTitle":"Investment Management Services","page":55},"example":"Active Investment Managers Active investment managers try to predict which securities and assets will outperform or underperform comparable securities and assets."},{"term":"Adverse selection","definition":"Tendency of people who are most at risk to buy insurance, causing insured losses to be greater than average losses.","glossaryPage":1,"origin":{"sectionId":"m2-l3","moduleId":"m2","sectionTitle":"Types of Financial Institutions","page":47},"example":"Adverse Selection Adverse selection occurs when only those who are most at risk buy insurance, causing insured losses to be greater than average losses."},{"term":"Ask price","definition":"Prices at which a dealer is willing to sell an asset or a security, typically qualified by a maximum quantity (ask size). Also called offer price.","glossaryPage":1,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":66},"example":"Dealers profit when they can buy securities for less than they sell them—that is, when the price at which they buy securities (the bid price) is lower than the price at which they sell them (the ask price or offer price)."},{"term":"Asset allocation","definition":"The process to determine the proportion of a portfolio to hold in various asset classes or the proportion of a portfolio held in various asset classes.","glossaryPage":1,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":37},"example":"Taking into consideration her clients’ risk tolerance, their financial needs, their goals, and any portfolio constraints (including taxes), Jenna constructs individual portfolios that are consistent with each client’s circumstances and Primrose’s strategies for asset allocation and security selection."},{"term":"Assets","definition":"Items that have value and include real assets and financial assets.","glossaryPage":1,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":5},"example":"In this lesson, you will explore the meaning and function of “savers” and “spenders” in the financial services industry, as well as different forms of assets."},{"term":"Back office","definition":"Administrative and support functions necessary to run the firm, including accounting, human resources, payroll, and operations.","glossaryPage":1,"origin":{"sectionId":"m2-overview","moduleId":"m2","sectionTitle":"Module overview","page":32},"example":"Module 2: Structure of the Investment Industry Sell-side, buy-side, and front, middle, and back office are terms you may have come across without much clarity on what they mean."},{"term":"Banks","definition":"Financial institutions that collect deposits from savers and transform them into loans to borrowers.","glossaryPage":1,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":19},"example":"Investment banks, also known as merchant banks, are financial intermediaries that have expertise in assisting companies and governments with raising capital, often by organizing the sale of shares and bonds to the public."},{"term":"Bid price","definition":"Price at which a dealer is willing to buy an asset or a security, typically qualified by a maximum quantity (bid size).","glossaryPage":1,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":66},"example":"Dealers profit when they can buy securities for less than they sell them—that is, when the price at which they buy securities (the bid price) is lower than the price at which they sell them (the ask price or offer price)."},{"term":"Block brokers","definition":"Brokers who help investors who want to trade large blocks of securities.","glossaryPage":1,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":65},"example":"Following is some insight into block brokers and prime brokerage."},{"term":"Blockchain","definition":"A system of record-keeping that is maintained by independent computers in a peer-to-peer (decentralised) network.","glossaryPage":1,"origin":{"sectionId":"m4-l4","moduleId":"m4","sectionTitle":"Fintech Applications","page":88},"example":"By using smart contracts on public blockchains, DeFi platforms allow people to lend or borrow funds from others, insure against risks, earn interest in savings-like accounts, and trade crypto currencies."},{"term":"Brokerage services","definition":"Trading services provided to clients who want to buy and sell securities; they include not only execution services (that is, processing orders on behalf of clients) but also investment advice and research.","glossaryPage":1,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":64},"example":"Brokers Brokerage services are provided to clients who want to buy and sell securities; they include not only execution services—that is, processing buy and sell orders on behalf of clients—but also investment advice and research."},{"term":"Brokers","definition":"Trading services providers who act as agents and, in exchange for a commission, arrange trades by finding sellers for their clients who want to buy and buyers for their clients who want to sell.","glossaryPage":1,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"Brokers and dealers are trading service providers that facilitate this trading."},{"term":"Buy-side analysts","definition":"Analysts who work for organisations, typically a type of institutional investor, that buy securities. They analyse data about companies and the markets in which they operate and review potential investments.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"These analysts are called buy-side analysts because they work for the organization buying the securities."},{"term":"Buy-side firms","definition":"Institutional investors and investment managers who purchase investment products and services from sell-side firms.","glossaryPage":2,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":33},"example":"Buy-side firms include firms that manage portfolios for clients, themselves, or both."},{"term":"Capitalism","definition":"An economic system that promotes private ownership as the means of production and markets as the means of allocating scarce resources.","glossaryPage":2,"origin":{"sectionId":"m1-l2","moduleId":"m1","sectionTitle":"How Economies Benefit from the Existence of the Investment Industry","page":11},"example":"Economic systems can take many forms, from pure capitalism with free markets to planned economies with centralized authorities."},{"term":"Clearing","definition":"All activities that occur from the arrangement of the trade to its settlement.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"Also providing trading services are clearing houses and settlement agents, which confirm and settle trades after they have been agreed on."},{"term":"Clearing houses","definition":"Trading services providers that arrange for final settlement of trades.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"Also providing trading services are clearing houses and settlement agents, which confirm and settle trades after they have been agreed on."},{"term":"Credit rating agencies","definition":"Investment research service providers that specialise in providing opinions about the credit quality of bonds and of their issuers.","glossaryPage":2,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":34},"example":"They are not relevant for firms providing investment information services, such as investment research providers, data vendors, or credit rating agencies."},{"term":"Cryptocurrency","definition":"A digital currency composed of encrypted data that acts as a medium of exchange.","glossaryPage":2,"origin":{"sectionId":"m4-l4","moduleId":"m4","sectionTitle":"Fintech Applications","page":88},"example":"By using smart contracts on public blockchains, DeFi platforms allow people to lend or borrow funds from others, insure against risks, earn interest in savings-like accounts, and trade crypto currencies."},{"term":"Custodians","definition":"Typically, banks and brokerage firms that hold money and securities for safekeeping on behalf of their clients.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"Custodians and depositories hold money and securities on behalf of their clients."},{"term":"Data vendors","definition":"Investment research service providers of historical and real-time data about companies and market conditions.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"To gather data about a company and the markets in which it operates, analysts often rely on investment information providers, such as data vendors, or investment research and report providers."},{"term":"Dealers","definition":"Trading services providers who participate in their clients’ trades and stand ready to buy or sell when their clients want to sell or buy, providing liquidity and profiting when they can buy securities for less than they sell them. Also called market makers.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"Brokers and dealers are trading service providers that facilitate this trading."},{"term":"Depositories","definition":"Typically, banks and brokerage firms that are regulated and act not only as custodians but also as monitors, playing an important role in preventing investment fraud.","glossaryPage":2,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"Custodians and depositories hold money and securities on behalf of their clients."},{"term":"Deposit-taking institutions","definition":"Financial institutions that take deposits, such as banks; also called depository institutions.","glossaryPage":2,"origin":{"sectionId":"m2-l3","moduleId":"m2","sectionTitle":"Types of Financial Institutions","page":44},"example":"Banks are also called deposit-taking institutions or depository institutions."},{"term":"Direct finance","definition":"When providers and users of capital interact, the providers usually have a direct claim on the users (e.g., right to certain assets and earnings generated by the user). See also direct investments.","glossaryPage":2,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":8},"example":"This process is indirect finance because financial intermediaries sit between savers and spenders; the former do not have direct claims on the latter."},{"term":"Endowment funds","definition":"Long-term funds owned by non-profit institutions.","glossaryPage":3,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"• Endowment funds: Endowment funds are long-term funds belonging to not-for- profit institutions, such as universities, colleges, schools, museums, theaters, opera companies, hospitals, and clinics."},{"term":"Ethical dilemmas","definition":"Situations in which values, interests, and/or rules potentially conflict.","glossaryPage":3,"origin":{"sectionId":"m5-l6","moduleId":"m5","sectionTitle":"Ethics and the Investment Industry","page":118},"example":"Because of the growth of the financial markets, there is an increase in the complexity of ethical dilemmas, especially in business conducted across borders under different regulatory and cultural frameworks."},{"term":"Ethical standards","definition":"Principles that support and promote desired values or behaviours.","glossaryPage":3,"origin":{"sectionId":"m5-l6","moduleId":"m5","sectionTitle":"Ethics and the Investment Industry","page":119},"example":"It is important to recognize that ethics and rules are interlinked: Ethical standards help guide the development of rules, and equally, rules help individuals think about and form ethical standards."},{"term":"Ethics","definition":"A set of moral principles, or the principles of conduct governing an individual or a group.","glossaryPage":3,"origin":{"sectionId":"m1-l3","moduleId":"m1","sectionTitle":"How Investors Benefit from the Existence of the Investment Industry","page":15},"example":"Such confidence arises from a feeling of trust that all parties are adhering to a code of ethics and standards for professional conduct, and that trust must be earned and verified consistently."},{"term":"Financial assets","definition":"Claims on other assets; for example, a share of stock represents ownership in a company or a claim to some of the company’s assets and earnings.","glossaryPage":3,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":6},"example":"Real and Financial Assets Savings can be invested in a wide range of assets."},{"term":"Financial capital","definition":"Money provided to individuals, companies, and governments to finance their needs.","glossaryPage":3,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":5},"example":"When spenders have received the money they need and start using it, they become users of financial capital."},{"term":"Financial institutions","definition":"Financial intermediaries, such as banks and insurance companies, whose role is to collect money from savers and to invest it in financial assets.","glossaryPage":3,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"Institutional investors that invest on behalf of others include investment firms and financial institutions, such as banks and insurance companies."},{"term":"Financial intermediaries","definition":"Organisations that act as middlemen between those who have money and those who need money.","glossaryPage":3,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":8},"example":"Providers and users of capital often rely on financial intermediaries to find each other and to channel funds between each other."},{"term":"Financial markets","definition":"Places where buyers and sellers can trade securities; also called securities markets or capital markets.","glossaryPage":3,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":7},"example":"Buyers and sellers trade securities in securities markets or financial markets."},{"term":"Financial planners","definition":"Investment professionals who help their clients set their financial goals and determine how much money they should save for future expenses and/or how much money they can spend on current expenses while still preserving their capital.","glossaryPage":3,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"Financial planners help clients to define their investment goals and understand their future needs."},{"term":"Financial services industry","definition":"Industry that offers a range of products and services to those who have money to invest and those who need money and help channel funds between them.","glossaryPage":3,"origin":{"sectionId":"m1-overview","moduleId":"m1","sectionTitle":"Module overview","page":4},"example":"Module 1: Industry Overview and Structure Have you ever wondered why the financial services industry exists and how it operates?"},{"term":"Fintech","definition":"Refers to technology-driven innovation in the financial services industry, and can also refer to companies — often new, start-up companies — involved in developing these technologies and to the wider sector they are a part of.","glossaryPage":3,"origin":{"sectionId":"m3-summary","moduleId":"m3","sectionTitle":"Module 3 Summary","page":73},"example":"Up Next In the next module, you will learn how investment professionals organize their efforts to help clients meet their financial goals and explore how fintech is transforming the world of finance."},{"term":"Foundations","definition":"Grant-making institutions funded by gifts and by the investment income that they produce.","glossaryPage":3,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"(In this context, “funds” refers to formal financial entities with dedicated investment criteria, rather than functioning as a synonym for money or capital.) • Foundations: Foundations are grant-making institutions funded by financial gifts and by the investment income that they produce."},{"term":"Fraud","definition":"Intentional deception, such as deliberately causing or falsely reporting losses to collect insurance settlements.","glossaryPage":3,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":34},"example":"Risk management is also critical because it seeks to ensure that the firm and its clients are not intentionally, inadvertently, or fraudulently exposed to excessive risk."},{"term":"Front office","definition":"Client-facing activities that provide direct revenue generation, such as sales, marketing, and customer service activities.","glossaryPage":3,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":34},"example":"Activities are classified by whether they are in the front office, the middle office, or the back office."},{"term":"Front-running","definition":"The act of placing an order ahead of a customer’s order to take advantage of the price impact that the customer’s order will have.","glossaryPage":4,"origin":{"sectionId":"m5-l4","moduleId":"m5","sectionTitle":"Types of Regulation","page":112},"example":"Front-Running Front-running is the act of placing a personal order ahead of a customer’s order to take advantage of the price impact that the customer’s order will have."},{"term":"High-net-worth investors","definition":"Individual investors with a higher amount of investable assets relative to retail investors.","glossaryPage":4,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":20},"example":"Generally, retail investors have the least investible assets and high-net-worth investors have substantial investible assets."},{"term":"Indirect finance","definition":"The use of financial intermediaries to find and channel funds between providers and users of capital. Because financial intermediaries sit between providers and users, the former do not have direct claims on the latter. See also indirect investments.","glossaryPage":4,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":8},"example":"This process is indirect finance because financial intermediaries sit between savers and spenders; the former do not have direct claims on the latter."},{"term":"Insider trading","definition":"Trading while in possession of material non-public information.","glossaryPage":4,"origin":{"sectionId":"m5-l1","moduleId":"m5","sectionTitle":"Key Forces Driving the Investment Industry","page":99},"example":"Promote and maintain the integrity, transparency, and fairness of financial markets For example, trading based on non-public information that could affect a security’s price, known as insider trading, is forbidden in most jurisdictions."},{"term":"Insurance companies","definition":"Financial institutions that help individuals and companies offset the risks they face; also among the largest investors.","glossaryPage":4,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"Institutional investors that invest on behalf of others include investment firms and financial institutions, such as banks and insurance companies."},{"term":"Investment banks","definition":"Financial intermediaries that assist companies and governments raise capital and can provide other services, such as strategic advisory services, brokerage and dealing services, and research services; also known as merchant banks.","glossaryPage":4,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":19},"example":"Investment banks, also known as merchant banks, are financial intermediaries that have expertise in assisting companies and governments with raising capital, often by organizing the sale of shares and bonds to the public."},{"term":"Investment industry","definition":"Subset of the financial services industry that comprises all the participants that are instrumental in helping savers invest their money and spenders raise capital in financial markets.","glossaryPage":4,"origin":{"sectionId":"m1-overview","moduleId":"m1","sectionTitle":"Module overview","page":4},"example":"In this module, you will be introduced to the structure of the financial services industry at large, the investment industry in particular, and the types and functions of industry participants."},{"term":"Investment managers","definition":"Investment professionals who receive authority from their clients to trade securities and assets on their behalf. Also called asset managers.","glossaryPage":4,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":36},"example":"Professionals who perform these types of tasks can also be referred to as investment managers, wealth managers, or advisers."},{"term":"Market manipulation","definition":"Abusive trading practice that involves taking actions intended to move the price of a stock to make a short-term profit.","glossaryPage":4,"origin":{"sectionId":"m5-l4","moduleId":"m5","sectionTitle":"Types of Regulation","page":112},"example":"Market Manipulation Regulators attempt to prevent and prosecute market manipulation."},{"term":"Middle office","definition":"Core activities of a firm, such as risk management, information technology, corporate finance, portfolio management, and research.","glossaryPage":4,"origin":{"sectionId":"m2-l1","moduleId":"m2","sectionTitle":"Structure of Investment Firms","page":34},"example":"Activities are classified by whether they are in the front office, the middle office, or the back office."},{"term":"Money laundering","definition":"A process in which criminals use financial services to transfer money from illegal operations to other legal activities; the money becomes “clean” in the process.","glossaryPage":4,"origin":{"sectionId":"m4-l3","moduleId":"m4","sectionTitle":"Introduction to Fintech","page":80},"example":"Preventing cyber fraud and identifying money laundering are important AI applications."},{"term":"Moral hazard","definition":"Tendency of people to be less careful about avoiding losses once they have purchased insurance, potentially leading to losses occurring more often when they are insured than when they are not.","glossaryPage":4,"origin":{"sectionId":"m2-l3","moduleId":"m2","sectionTitle":"Types of Financial Institutions","page":47},"example":"On top of the insurable risks they take on, insurance companies are exposed to price competition from other insurers, the effect of market volatility on their invested reserves, and other business risks, including the following examples Fraud Fraud occurs when people deliberately cause or falsely report losses in order to collect insurance settlements Moral Hazard Moral hazard"},{"term":"Passive investment managers","definition":"Managers who follow a buy-and-hold approach and seek to match the return and risk of a benchmark.","glossaryPage":5,"origin":{"sectionId":"m3-l1","moduleId":"m3","sectionTitle":"Investment Management Services","page":54},"example":"Passive Investment Managers Passive investment managers seek to match the return and risk of an appropriate benchmark."},{"term":"Payout policies","definition":"Guiding principles that specify how much money an institution, such as a foundation or an endowment fund, can take from long-term funds to use for current spending.","glossaryPage":5,"origin":{"sectionId":"m4-l2","moduleId":"m4","sectionTitle":"Financial Planning Services","page":78},"example":"For example, foundations and endowment funds, which are not-for-profit institutions with long-term investment objectives, hire financial planners to create payout policies."},{"term":"Pension plans","definition":"Institutional investors who hold investment portfolios for the benefit of future and current retirees.","glossaryPage":5,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":20},"example":"Institutional investors come in different forms, such as the following: • Pension plans: Pension plans hold and manage investment assets for the benefit of current and future retired individuals, called beneficiaries."},{"term":"Physical capital","definition":"The means of production; tangible goods such as equipment, tools, and buildings.","glossaryPage":5,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":6},"example":"A company’s production may depend on them, and they are sometimes referred to as physical capital."},{"term":"Portfolio","definition":"The group of assets in which savings are invested.","glossaryPage":5,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":6},"example":"An investor’s total holdings of financial assets is usually called a portfolio or investment portfolio."},{"term":"Primary dealers","definition":"Dealers with which central banks trade when conducting monetary policy.","glossaryPage":5,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":67},"example":"Primary dealers are dealers that central banks trade with when conducting monetary policy."},{"term":"Prime brokerage","definition":"Bundle of services that brokers provide some of their clients, including typical brokerage services and financing of their clients’ positions.","glossaryPage":5,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":65},"example":"Following is some insight into block brokers and prime brokerage."},{"term":"Professional standards","definition":"Guidelines set by professional associations based on fundamental ethical principles to guide the behaviour of individuals within the profession.","glossaryPage":5,"origin":{"sectionId":"m5-l1","moduleId":"m5","sectionTitle":"Key Forces Driving the Investment Industry","page":100},"example":"The Need for Ethical Behavior The adoption and successful application of ethical and professional standards, regulations, and corporate policies create trust."},{"term":"Proprietary traders","definition":"Traders who trade directly with their clients rather than by arranging trades with others on behalf of their clients.","glossaryPage":5,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"(Proprietary traders will be expanded on in the Trading Services lesson in Module 3, Introduction to Investment Services)."},{"term":"Real assets","definition":"Physical assets, such as land, buildings, machinery, cattle, and gold.","glossaryPage":5,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":6},"example":"Assets are items that have value and include real assets and financial assets."},{"term":"Regulations","definition":"Rules that set standards for conduct and carry the force of law. They are set and enforced by legislative bodies and by other entities authorised by legislative bodies.","glossaryPage":5,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":20},"example":"When Primo becomes a public company, it will have to comply both with the stock exchange rules where its shares are listed and with relevant national regulations."},{"term":"Retail investors","definition":"Individual investors with the least amount of investable assets.","glossaryPage":5,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":20},"example":"Generally, retail investors have the least investible assets and high-net-worth investors have substantial investible assets."},{"term":"Securities","definition":"Financial assets that can be traded, such as shares and bonds.","glossaryPage":5,"origin":{"sectionId":"m1-l1","moduleId":"m1","sectionTitle":"What Is the Financial Services Industry?","page":6},"example":"Financial assets that can be traded are called securities."},{"term":"Sell-side analysts","definition":"Analysts who work for the organisations, typically an investment bank, that sell securities. They collect and analyse information about a company and its competitors and then prepare a report that is shared with potential investors.","glossaryPage":5,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":20},"example":"The investment bank’s analysts, often called sell-side analysts because they work for the organization selling the securities, collect and analyze information about the company and its competitors, and then prepare a report that is shared with potential investors."},{"term":"Sell-side firms","definition":"Typically, investment banks, brokers, and dealers that provide investment products and services.","glossaryPage":5,"origin":{"sectionId":"m2-overview","moduleId":"m2","sectionTitle":"Module overview","page":32},"example":"By the end of this module, you will be able to: ● Distinguish between buy-side and sell-side firms and front-, middle-, and back- office functions in the investment industry ● Identify positions and responsibilities within firms in the investment industry ● Identify types of financial institutions, including banks and insurance companies Let's get started!"},{"term":"Settlement","definition":"Activity that consists of the final exchange of cash for securities following a trade.","glossaryPage":6,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":22},"example":"Also providing trading services are clearing houses and settlement agents, which confirm and settle trades after they have been agreed on."},{"term":"Settlement risk","definition":"The risk that when settling a transaction, a firm performs one side of the deal but the counterparty does not complete its side of the deal as agreed, often because it has declared bankruptcy.","glossaryPage":6,"origin":{"sectionId":"m3-l3","moduleId":"m3","sectionTitle":"Trading Services","page":68},"example":"Reliable trade settlement through a clearinghouse reduces settlement risk—the risk that counterparties will not settle their trades—for both buyers and sellers."},{"term":"Sovereign wealth funds","definition":"Funds created by governments to invest surpluses for the benefit of current and future generations of their citizens.","glossaryPage":6,"origin":{"sectionId":"m1-l4","moduleId":"m1","sectionTitle":"Investment Industry Participants","page":21},"example":"• Sovereign wealth funds: Sovereign wealth funds are overseen by governments, which may gather more tax than they intend to spend by selling natural resources or by financing the trade of goods and services."},{"term":"Systemic failure","definition":"Failure of the financial system as a whole, including loss of access to credit and collapse of capital markets.","glossaryPage":6,"origin":{"sectionId":"m5-l3","moduleId":"m5","sectionTitle":"Objectives of Regulation","page":105},"example":"Support Economic Stability The increasingly complex interconnections among global financial institutions may increase the consequences, if not the risk, of a systemic failure, which is a failure of the entire financial system."}],"sourceNotes":{"mainTitle":"Investment Foundations — Course 1: Industry Overview and Structure","mainPages":157,"glossaryTitle":"IF Course 1 Glossary","glossaryPages":6,"mainPacketIntro":"Introduction to This Reading Material\nThank you for purchasing/downloading the reading packet for DNU-02-23 M-IF1:\nIndustry Overview and Structure.\nBegin your online course by reading the syllabus; it contains the information you need to\nsuccessfully complete the course. As you begin, you will notice that each module\nincludes a brief introduction, learning objectives for the module, and reading\nassignments. The reading material for each module is included in this packet, as well as\nin the online course.\nIn addition to the readings, the modules have computer-graded assignments and self-\ncheck exercises associated with them. These assignments and other interactive\nactivities, such as videos, are available only through the online course.\nThis packet is designed to give you the best experience for reading the detailed lesson\ncontent and taking notes. To complete the course, you will need access to the online\nassignments and exams.\nBest wishes for your success in this course!"}};;

/*
  Translation configuration
  -------------------------
  Leave TRANSLATION_API_URL empty to use the clearly marked fallback.
  For real use, point this to your own server-side proxy. A static HTML file cannot
  securely hide a provider API key, so do not put a production key in this code.
  Expected generic request: POST JSON { q, source: "en", target: "es", format: "text" }.
  Accepted generic response shapes include:
  { translatedText: "..." }, { translation: "..." }, or
  { data: { translations: [{ translatedText: "..." }] } }.
*/
const TRANSLATION_CONFIG = {
  TRANSLATION_API_URL: "",
  API_KEY: "",
  SOURCE_LANGUAGE: "en",
  TARGET_LANGUAGE: "es"
};

const STORAGE_KEY = "course1StudyReader.v1";
const sectionById = new Map(COURSE_DATA.sections.map((section) => [section.id, section]));
const moduleById = new Map(COURSE_DATA.modules.map((module) => [module.id, module]));
const exerciseById = new Map(COURSE_DATA.exercises.map((exercise) => [exercise.id, exercise]));

const DEFAULT_STATE = {
  lastSection: "m1-overview",
  readProgress: {},
  favorites: [],
  notes: {},
  highlights: [],
  personalWords: [],
  exerciseProgress: {},
  glossaryProgress: {},
  translations: {},
  theme: "light",
  fontSize: 18
};

let state = loadState();
const ui = {
  activeView: "bookView",
  bookMode: "read",
  currentSection: sectionById.has(state.lastSection) ? state.lastSection : "m1-overview",
  pendingSelection: null,
  noteEditing: null,
  practiceLevel: "1",
  practiceModule: "all",
  practiceFocusSection: null,
  practiceFeedback: {},
  activeExam: null,
  examFeedback: {},
  glossaryMode: "entries",
  glossarySearch: "",
  glossaryModule: "all",
  glossaryStatus: "all",
  flashIndex: 0,
  flashOrder: [],
  flashRevealed: false,
  personalSectionFilter: "all"
};

const $ = (selector, parent = document) => parent.querySelector(selector);
const $$ = (selector, parent = document) => Array.from(parent.querySelectorAll(selector));

function loadState() {
  try {
    const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
    if (!saved || typeof saved !== "object") return structuredClone(DEFAULT_STATE);
    return {
      ...structuredClone(DEFAULT_STATE),
      ...saved,
      readProgress: saved.readProgress || {},
      notes: saved.notes || {},
      highlights: Array.isArray(saved.highlights) ? saved.highlights : [],
      favorites: Array.isArray(saved.favorites) ? saved.favorites : [],
      personalWords: Array.isArray(saved.personalWords) ? saved.personalWords : [],
      exerciseProgress: saved.exerciseProgress || {},
      glossaryProgress: saved.glossaryProgress || {},
      translations: saved.translations || {}
    };
  } catch {
    return structuredClone(DEFAULT_STATE);
  }
}

function persistState() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function normalizeText(value) {
  return String(value ?? "").replace(/\s+/g, " ").trim();
}

function sourcePageRange(section) {
  const pages = section.pages.map((page) => page.page);
  if (!pages.length) return "";
  return pages.length === 1 ? `Fuente: paquete principal, p. ${pages[0]}` : `Fuente: paquete principal, pp. ${pages[0]}–${pages.at(-1)}`;
}

function moduleName(moduleId) {
  const module = moduleById.get(moduleId);
  return module ? `${module.number}: ${module.title}` : "";
}

function sectionName(sectionId) {
  const section = sectionById.get(sectionId);
  return section ? section.title : "";
}

function getSectionProgress(sectionId) {
  return Math.max(0, Math.min(1, Number(state.readProgress[sectionId] || 0)));
}

function totalProgress() {
  const values = COURSE_DATA.sections.map((section) => getSectionProgress(section.id));
  return values.length ? values.reduce((sum, value) => sum + value, 0) / values.length : 0;
}

function studiedCount() {
  return COURSE_DATA.sections.filter((section) => getSectionProgress(section.id) >= 1).length;
}

function isFavorite(sectionId) {
  return state.favorites.includes(sectionId);
}

function updateProgressUi() {
  const percent = Math.round(totalProgress() * 100);
  $("#sidebarProgressValue").textContent = `${percent}%`;
  $("#sidebarProgressBar").style.width = `${percent}%`;
  $("#sidebarProgressText").textContent = `${studiedCount()} de ${COURSE_DATA.sections.length} secciones marcadas como estudiadas`;

  const sectionPercent = Math.round(getSectionProgress(ui.currentSection) * 100);
  $("#currentSectionProgress").textContent = `${sectionPercent}%`;
}

function renderBookNav() {
  const nav = $("#bookNav");
  nav.innerHTML = COURSE_DATA.modules.map((module) => {
    const sections = COURSE_DATA.sections.filter((section) => section.moduleId === module.id);
    return `
      <div class="module-nav-group">
        <button type="button" class="module-nav-title" data-module-nav="${module.id}" aria-label="Ir a ${escapeHtml(module.number)}">
          <span>${escapeHtml(module.number)}</span>
          <small>${sections.filter((section) => getSectionProgress(section.id) >= 1).length}/${sections.length}</small>
        </button>
        ${sections.map((section) => {
          const favorite = isFavorite(section.id);
          const marker = getSectionProgress(section.id) >= 1 ? "✓" : favorite ? "★" : "•";
          return `
            <button type="button" class="section-nav-button ${section.id === ui.currentSection ? "is-active" : ""} ${favorite ? "is-favorite" : ""}"
              data-section-id="${section.id}" title="${escapeHtml(section.title)}">
              <span class="nav-marker" aria-hidden="true">${marker}</span>
              <span>${escapeHtml(section.label)} · ${escapeHtml(section.title)}</span>
            </button>`;
        }).join("")}
      </div>`;
  }).join("");
}

function getStoredHighlights(sectionId) {
  return state.highlights
    .filter((highlight) => highlight.sectionId === sectionId && highlight.text)
    .map((highlight) => highlight.text)
    .filter((text, index, array) => array.indexOf(text) === index)
    .sort((a, b) => b.length - a.length);
}

function renderInlineText(text, sectionId) {
  let output = escapeHtml(text);
  for (const highlight of getStoredHighlights(sectionId)) {
    const escapedHighlight = escapeHtml(highlight);
    if (escapedHighlight && output.includes(escapedHighlight)) {
      output = output.replaceAll(
        escapedHighlight,
        `<mark class="selection-highlight">${escapedHighlight}</mark>`
      );
    }
  }
  return output;
}

function mergeLines(lines) {
  return lines.reduce((merged, line) => {
    const clean = line.trim();
    if (!clean) return merged;
    if (!merged) return clean;
    if (merged.endsWith("-")) return `${merged.slice(0, -1)}${clean}`;
    return `${merged} ${clean}`;
  }, "");
}

function isHeading(line) {
  const headingPatterns = [
    /^(Module|Lesson)\s+\d+:/,
    /^Exhibit\s+\d+:/,
    /^(Terminology|Introduction|Up Next|Conclusion|Summary|Financial Institutions|Banks|Insurance Companies|Brokers|Dealers|Clearinghouses|Custodians and Depositories|Passive Investment Managers|Active Investment Managers|Front Office|Middle Office|Back Office|Big Data|Natural Language Processing \(NLP\)|High-Frequency Trading|Automated Advice and Robo-Advisors|Mobile Banking|Decentralized Finance \(DeFi\)|Crypto Assets|The Need for Ethical Behavior|The CFA Institute Ethical Decision-Making Framework|Application of an Ethical Decision-Making Framework|Case Study: Applying an Ethical Decision-Making Framework)$/,
    /^[A-Z][A-Za-zÀ-ÿ0-9&/()'’.,—–\-]+(?: [A-Z][A-Za-zÀ-ÿ0-9&/()'’.,—–\-]+){0,10}$/
  ];
  return headingPatterns.some((pattern) => pattern.test(line.trim()));
}

function isQuestionBlock(text) {
  return /^(Question\b|Lesson \d+ Knowledge Check\b|True or False:|Which of the following\b|Match the\b|Based on the above\b|Decentralized finance\b|Laws and regulations\b|In addition to reinforcing\b|Regulatory failures\b|The consequences of failure\b|According to fundamental\b|The fundamental ethical principle\b|The last step\b)/i.test(text.trim());
}

function formatTextBlock(rawBlock, sectionId) {
  const lines = rawBlock.split("\n").map((line) => line.trim()).filter(Boolean);
  if (!lines.length) return "";

  const first = lines[0];
  const plain = mergeLines(lines);

  if (/^Exhibit\s+\d+:/i.test(first)) {
    const rest = lines.slice(1);
    return `
      <div class="source-exhibit">
        <div>${renderInlineText(first, sectionId)}</div>
        ${rest.length ? `<p>${renderInlineText(mergeLines(rest), sectionId)}</p>` : ""}
      </div>`;
  }

  if (isQuestionBlock(plain) || /^Question\s*\d*/i.test(first)) {
    return `<div class="source-question">${lines.map((line) => `<p>${renderInlineText(line, sectionId)}</p>`).join("")}</div>`;
  }

  if (isHeading(first) && lines.length === 1) {
    return `<h3>${renderInlineText(first, sectionId)}</h3>`;
  }

  if (isHeading(first) && lines.length > 1) {
    const bodyLines = lines.slice(1);
    if (bodyLines.every((line) => /^([•●]|[oο]|\d+\.)\s*/.test(line))) {
      const listItems = bodyLines.map((line) => line.replace(/^([•●]|[oο]|\d+\.)\s*/, ""));
      return `<h3>${renderInlineText(first, sectionId)}</h3><ul>${listItems.map((item) => `<li>${renderInlineText(item, sectionId)}</li>`).join("")}</ul>`;
    }
    return `<h3>${renderInlineText(first, sectionId)}</h3><p>${renderInlineText(mergeLines(bodyLines), sectionId)}</p>`;
  }

  if (lines.every((line) => /^([•●]|[oο])\s*/.test(line))) {
    const listItems = lines.map((line) => line.replace(/^([•●]|[oο])\s*/, ""));
    return `<ul>${listItems.map((item) => `<li>${renderInlineText(item, sectionId)}</li>`).join("")}</ul>`;
  }

  // Preserve data-rich rows that are likely to originate from a table without pretending
  // to reconstruct its original column layout.
  const tableLike = lines.length >= 5 && (
    /^(Title|Responsibility|Category|Categories|Participant|Participants|Problem|Traditional|DeFi|Investor|Goals, Needs, and Roles|Circumstance|Description)$/i.test(lines[0]) ||
    lines.filter((line) => line.length < 48 && !/[.!?]$/.test(line)).length >= 4
  );
  if (tableLike) {
    return `<div class="source-table">${lines.map((line) => renderInlineText(line, sectionId)).join("\n")}</div>`;
  }

  return `<p>${renderInlineText(mergeLines(lines), sectionId)}</p>`;
}

function renderReaderContent(section) {
  return section.pages.map((page) => {
    const blocks = page.text.split(/\n\s*\n/).map((block) => block.trim()).filter(Boolean);
    return `
      <section class="source-page" data-source-page="${page.page}">
        <p class="source-page-label">Paquete principal · página ${page.page}</p>
        ${blocks.map((block) => formatTextBlock(block, section.id)).join("")}
      </section>`;
  }).join("");
}

function renderNotes() {
  const notes = Array.isArray(state.notes[ui.currentSection]) ? state.notes[ui.currentSection] : [];
  const list = $("#notesList");
  if (!notes.length) {
    list.innerHTML = `<p class="empty-notes">Aún no hay notas para esta sección.</p>`;
    return;
  }
  list.innerHTML = notes.map((note) => `
    <article class="note-card">
      <h4>${escapeHtml(note.title)}</h4>
      <p>${escapeHtml(note.body)}</p>
      <div class="note-actions">
        <button type="button" data-note-action="edit" data-note-id="${note.id}" aria-label="Editar nota">✎</button>
        <button type="button" data-note-action="delete" data-note-id="${note.id}" aria-label="Eliminar nota">×</button>
      </div>
    </article>
  `).join("");
}

function renderReader() {
  const section = sectionById.get(ui.currentSection);
  if (!section) return;
  const module = moduleById.get(section.moduleId);
  $("#sectionMeta").textContent = `${module.number} · ${section.label}`;
  $("#sectionTitle").textContent = section.title;
  $("#sectionPageRange").textContent = sourcePageRange(section);
  $("#readerContent").innerHTML = renderReaderContent(section);

  const favoriteButton = $("#favoriteSectionButton");
  const favorite = isFavorite(section.id);
  favoriteButton.classList.toggle("is-favorite", favorite);
  favoriteButton.setAttribute("aria-pressed", String(favorite));
  favoriteButton.textContent = favorite ? "★ Guardado" : "☆ Guardar";

  const studied = getSectionProgress(section.id) >= 1;
  $("#markStudiedButton").textContent = studied ? "✓ Sección estudiada" : "Marcar como estudiado";
  renderNotes();
  renderBookNav();
  updateProgressUi();
}

function setCurrentSection(sectionId, { scroll = true } = {}) {
  if (!sectionById.has(sectionId)) return;
  ui.currentSection = sectionId;
  state.lastSection = sectionId;
  state.readProgress[sectionId] = Math.max(getSectionProgress(sectionId), 0.08);
  persistState();
  ui.bookMode = "read";
  showView("bookView");
  setBookMode("read");
  renderReader();
  if (scroll) window.scrollTo({ top: 0, behavior: "smooth" });
}

function markCurrentSectionStudied() {
  state.readProgress[ui.currentSection] = 1;
  persistState();
  renderReader();
  showToast("Sección marcada como estudiada.", "success");
}

function toggleCurrentFavorite() {
  const index = state.favorites.indexOf(ui.currentSection);
  if (index >= 0) state.favorites.splice(index, 1);
  else state.favorites.push(ui.currentSection);
  persistState();
  renderReader();
}

function openNoteDialog(noteId = null) {
  const dialog = $("#noteDialog");
  const notes = state.notes[ui.currentSection] || [];
  const note = noteId ? notes.find((item) => item.id === noteId) : null;
  ui.noteEditing = note ? note.id : null;
  $("#noteDialogTitle").textContent = note ? "Editar nota" : "Nueva nota";
  $("#noteTitleInput").value = note ? note.title : "";
  $("#noteBodyInput").value = note ? note.body : "";
  if (typeof dialog.showModal === "function") dialog.showModal();
}

function saveNote() {
  const title = $("#noteTitleInput").value.trim();
  const body = $("#noteBodyInput").value.trim();
  if (!title || !body) return;
  const notes = state.notes[ui.currentSection] || [];
  if (ui.noteEditing) {
    const note = notes.find((item) => item.id === ui.noteEditing);
    if (note) {
      note.title = title;
      note.body = body;
      note.updatedAt = Date.now();
    }
  } else {
    notes.unshift({
      id: `note-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      title,
      body,
      createdAt: Date.now()
    });
  }
  state.notes[ui.currentSection] = notes;
  persistState();
  $("#noteDialog").close();
  renderNotes();
  showToast("Nota guardada.", "success");
}

function deleteNote(noteId) {
  const notes = state.notes[ui.currentSection] || [];
  state.notes[ui.currentSection] = notes.filter((note) => note.id !== noteId);
  persistState();
  renderNotes();
  showToast("Nota eliminada.");
}

function showView(viewId) {
  ui.activeView = viewId;
  $$(".view-panel").forEach((panel) => {
    panel.hidden = panel.id !== viewId;
  });
  $$(".nav-tab").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.viewTarget === viewId);
  });
  const bookNavWrap = $("#bookNavWrap");
  bookNavWrap.hidden = viewId !== "bookView";
  if (viewId === "bookView") {
    $("#viewKicker").textContent = "MÓDULO LIBRO";
    $("#topbarTitle").textContent = ui.bookMode === "practice" ? "Práctica" : "Lectura";
  } else {
    $("#viewKicker").textContent = "MÓDULO GLOSARIO";
    $("#topbarTitle").textContent = ui.glossaryMode === "flashcards" ? "Tarjetas" : "Glosario";
    renderGlossary();
  }
  $("#searchResults").innerHTML = "";
  $("#globalSearch").value = "";
  closeMobileSidebar();
}

function setBookMode(mode) {
  ui.bookMode = mode;
  $("#readMode").hidden = mode !== "read";
  $("#practiceMode").hidden = mode !== "practice";
  $$(".subnav-button[data-book-mode]").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.bookMode === mode);
  });
  $("#topbarTitle").textContent = mode === "practice" ? "Práctica" : "Lectura";
  if (mode === "practice") renderPractice();
}

function setGlossaryMode(mode) {
  ui.glossaryMode = mode;
  $("#glossaryEntriesMode").hidden = mode !== "entries";
  $("#flashcardsMode").hidden = mode !== "flashcards";
  $("#personalWordsMode").hidden = mode !== "personal";
  $$(".subnav-button[data-glossary-mode]").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.glossaryMode === mode);
  });
  $("#topbarTitle").textContent = mode === "flashcards" ? "Tarjetas" : mode === "personal" ? "Mis palabras" : "Glosario";
  renderGlossary();
}

function openPracticeForSection(sectionId) {
  const section = sectionById.get(sectionId);
  if (!section) return;
  ui.practiceModule = section.moduleId;
  ui.practiceFocusSection = sectionId;
  ui.practiceLevel = "1";
  ui.practiceFeedback = {};
  setBookMode("practice");
  showView("bookView");
  renderPractice();
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function getExerciseProgress(exerciseId) {
  return state.exerciseProgress[exerciseId] || { attempts: 0, correct: false, wrongAttempts: 0 };
}

function getExerciseStats() {
  const total = COURSE_DATA.exercises.length;
  const complete = COURSE_DATA.exercises.filter((exercise) => getExerciseProgress(exercise.id).correct).length;
  const errors = COURSE_DATA.exercises.reduce((sum, exercise) => sum + Number(getExerciseProgress(exercise.id).wrongAttempts || 0), 0);
  return { total, complete, pending: total - complete, errors };
}

function populatePracticeModuleFilter() {
  const select = $("#practiceModuleFilter");
  const selected = ui.practiceModule;
  select.innerHTML = `<option value="all">Todas las unidades</option>${COURSE_DATA.modules.map((module) =>
    `<option value="${module.id}">${escapeHtml(module.number)} · ${escapeHtml(module.title)}</option>`
  ).join("")}`;
  select.value = selected;
}

function renderPracticeStats() {
  const stats = getExerciseStats();
  $("#practiceStats").innerHTML = `
    <div class="practice-stat"><strong>${stats.pending}</strong><small>Pendientes</small></div>
    <div class="practice-stat"><strong>${stats.complete}</strong><small>Completados</small></div>
    <div class="practice-stat"><strong>${stats.errors}</strong><small>Intentos con error</small></div>`;
}

function getPracticeBaseExercises() {
  let list = COURSE_DATA.exercises.filter((exercise) => ui.practiceModule === "all" || exercise.moduleId === ui.practiceModule);
  if (ui.practiceFocusSection) {
    list = list.filter((exercise) => exercise.sectionId === ui.practiceFocusSection);
  }
  return list;
}

function sourceRef(exercise) {
  const module = moduleById.get(exercise.moduleId);
  const section = sectionById.get(exercise.sectionId);
  return `${module.number} · ${section.title} · p. ${exercise.page}`;
}

function renderExerciseCard(exercise, { inExam = false } = {}) {
  const feedback = inExam ? ui.examFeedback[exercise.id] : ui.practiceFeedback[exercise.id];
  const inputName = `${inExam ? "exam" : "practice"}-${exercise.id}`;

  let content = "";
  if (exercise.type === "single" || exercise.type === "multiple") {
    const inputType = exercise.type === "multiple" ? "checkbox" : "radio";
    content = `<div class="exercise-options">
      ${exercise.options.map(([key, text]) => `
        <label class="exercise-option">
          <input type="${inputType}" name="${inputName}" value="${escapeHtml(key)}" />
          <span><strong>${escapeHtml(key)}.</strong> ${escapeHtml(text)}</span>
        </label>`).join("")}
    </div>`;
  } else if (exercise.type === "matching") {
    content = `<div class="match-grid">
      ${exercise.pairs.map((pair) => `
        <label class="match-row">
          <span><strong>${escapeHtml(pair.label)}</strong></span>
          <select data-match-key="${escapeHtml(pair.key)}" aria-label="Objetivo para ${escapeHtml(pair.label)}">
            <option value="">Selecciona un objetivo</option>
            ${exercise.matchOptions.map(([key, text]) => `<option value="${escapeHtml(key)}">${escapeHtml(key)}. ${escapeHtml(text)}</option>`).join("")}
          </select>
        </label>`).join("")}
    </div>`;
  } else if (exercise.type === "matrix") {
    content = `<div class="matrix-grid">
      ${exercise.matrixRows.map(([key, text]) => `
        <label class="matrix-row">
          <span>${escapeHtml(text)}</span>
          <select data-matrix-key="${escapeHtml(key)}" aria-label="Respuesta para ${escapeHtml(text)}">
            <option value="">Selecciona una opción</option>
            ${exercise.matrixOptions.map((option) => `<option value="${escapeHtml(option)}">${escapeHtml(option)}</option>`).join("")}
          </select>
        </label>`).join("")}
    </div>`;
  }

  const feedbackHtml = feedback ? `
    <div class="exercise-feedback ${feedback.correct ? "is-correct" : "is-wrong"}">
      <strong>${feedback.correct ? "Correcto" : "Todavía no"}</strong>
      <p>${escapeHtml(exercise.feedback)}</p>
      <p class="helper-text">Referencia: <button type="button" class="inline-link" data-go-section="${exercise.sectionId}">${escapeHtml(sectionName(exercise.sectionId))}</button>, p. ${exercise.page}.</p>
    </div>` : "";

  return `
    <article class="exercise-card" data-exercise-id="${exercise.id}" data-in-exam="${inExam}">
      <div class="exercise-card-head">
        <h4>${escapeHtml(exercise.title)}</h4>
        <span class="source-reference">${escapeHtml(sourceRef(exercise))}</span>
      </div>
      <p class="exercise-question">${escapeHtml(exercise.question)}</p>
      ${content}
      <div class="card-actions">
        <button type="button" class="primary-button" data-exercise-action="verify" data-exercise-id="${exercise.id}" data-in-exam="${inExam}">Verificar respuesta</button>
        ${feedback ? `<button type="button" class="secondary-button" data-exercise-action="retry" data-exercise-id="${exercise.id}" data-in-exam="${inExam}">Intentar nuevamente</button>` : ""}
      </div>
      ${feedbackHtml}
    </article>`;
}

function describePracticeLevel() {
  const moduleTitle = ui.practiceModule === "all" ? "todas las unidades" : moduleName(ui.practiceModule);
  const focus = ui.practiceFocusSection ? ` Se está mostrando la sección relacionada: <strong>${escapeHtml(sectionName(ui.practiceFocusSection))}</strong>.` : "";
  const descriptions = {
    "1": `Nivel 1 · Preguntas de identificación y lectura inicial procedentes de los controles del PDF para ${escapeHtml(moduleTitle)}.${focus}`,
    "2": `Nivel 2 · Preguntas de comprensión, relaciones y actividades originales del PDF para ${escapeHtml(moduleTitle)}.${focus}`,
    "3": `Nivel 3 · Repaso acumulativo: vuelve a resolver preguntas originales ya vistas de ${escapeHtml(moduleTitle)}. No se crean preguntas nuevas.${focus}`,
    "4": `Nivel 4 · Evaluación: genera un conjunto de preguntas originales del PDF. Se calcula el resultado al verificar todas.`
  };
  return descriptions[ui.practiceLevel];
}

function renderEvaluation(exercises) {
  const candidates = exercises.length ? exercises : COURSE_DATA.exercises;
  if (!ui.activeExam || ui.activeExam.module !== ui.practiceModule || ui.activeExam.focus !== ui.practiceFocusSection) {
    return `
      <section class="evaluation-panel">
        <h4>Evaluación basada en ejercicios existentes</h4>
        <p>Se seleccionarán hasta 5 preguntas originales del material. No se añadirá contenido académico nuevo.</p>
        <button type="button" class="primary-button" data-practice-action="generate-exam">Generar evaluación</button>
      </section>`;
  }
  const selected = ui.activeExam.ids.map((id) => exerciseById.get(id)).filter(Boolean);
  const checked = Object.keys(ui.activeExam.verified || {}).length;
  const correct = Object.values(ui.activeExam.verified || {}).filter(Boolean).length;
  const finished = checked === selected.length && selected.length > 0;
  const score = selected.length ? Math.round((correct / selected.length) * 100) : 0;
  return `
    <section class="evaluation-panel">
      <h4>Evaluación en curso</h4>
      <p>Resultado: <span class="exam-score">${correct}/${selected.length}${finished ? ` · ${score}%` : ` · ${checked} respondidas`}</span></p>
      <button type="button" class="secondary-button" data-practice-action="generate-exam">Generar una nueva evaluación</button>
    </section>
    ${selected.map((exercise) => renderExerciseCard(exercise, { inExam: true })).join("")}`;
}

function renderPractice() {
  populatePracticeModuleFilter();
  $$(".level-tab").forEach((button) => button.classList.toggle("is-active", button.dataset.practiceLevel === ui.practiceLevel));
  $("#practiceDescription").innerHTML = describePracticeLevel();
  renderPracticeStats();

  let exercises = getPracticeBaseExercises();
  if (ui.practiceLevel === "1" || ui.practiceLevel === "2") {
    exercises = exercises.filter((exercise) => String(exercise.level) === ui.practiceLevel);
  } else if (ui.practiceLevel === "3") {
    // A cumulative review reuses original questions. Prefer questions with an error, then remaining source questions.
    const errored = exercises.filter((exercise) => getExerciseProgress(exercise.id).wrongAttempts > 0);
    exercises = errored.length ? errored : exercises;
  }

  const list = $("#practiceList");
  if (ui.practiceLevel === "4") {
    list.innerHTML = renderEvaluation(getPracticeBaseExercises());
    return;
  }
  if (!exercises.length) {
    list.innerHTML = `<div class="empty-state">No hay ejercicios del tipo seleccionado para este filtro. Cambia de nivel o unidad para revisar el resto del material.</div>`;
    return;
  }
  list.innerHTML = exercises.map((exercise) => renderExerciseCard(exercise)).join("");
}

function getSubmittedAnswer(exercise, card) {
  if (exercise.type === "single" || exercise.type === "multiple") {
    return $$(`input[name="${card.querySelector("input")?.name || ""}"]:checked`, card).map((input) => input.value);
  }
  if (exercise.type === "matching") {
    return exercise.pairs.map((pair) => card.querySelector(`[data-match-key="${pair.key}"]`)?.value || "");
  }
  if (exercise.type === "matrix") {
    return exercise.matrixRows.map(([key]) => card.querySelector(`[data-matrix-key="${key}"]`)?.value || "");
  }
  return [];
}

function hasCompleteAnswer(exercise, answer) {
  if (!Array.isArray(answer) || !answer.length) return false;
  if (exercise.type === "single" || exercise.type === "multiple") return answer.length > 0;
  return answer.every(Boolean);
}

function isCorrectAnswer(exercise, answer) {
  if (exercise.type === "single" || exercise.type === "multiple") {
    const chosen = [...answer].sort();
    const correct = [...exercise.answer].sort();
    return chosen.length === correct.length && chosen.every((value, index) => value === correct[index]);
  }
  if (exercise.type === "matching") {
    return exercise.pairs.every((pair, index) => answer[index] === pair.answer);
  }
  if (exercise.type === "matrix") {
    return exercise.matrixRows.every((row, index) => answer[index] === row[2]);
  }
  return false;
}

function verifyExercise(exerciseId, inExam) {
  const exercise = exerciseById.get(exerciseId);
  const card = $(`.exercise-card[data-exercise-id="${exerciseId}"][data-in-exam="${inExam}"]`);
  if (!exercise || !card) return;
  const answer = getSubmittedAnswer(exercise, card);
  if (!hasCompleteAnswer(exercise, answer)) {
    showToast("Selecciona una respuesta antes de verificar.", "warning");
    return;
  }

  const correct = isCorrectAnswer(exercise, answer);
  if (inExam === "true") {
    ui.examFeedback[exerciseId] = { correct };
    ui.activeExam.verified[exerciseId] = correct;
  } else {
    const progress = getExerciseProgress(exerciseId);
    state.exerciseProgress[exerciseId] = {
      attempts: Number(progress.attempts || 0) + 1,
      correct: Boolean(progress.correct || correct),
      wrongAttempts: Number(progress.wrongAttempts || 0) + (correct ? 0 : 1)
    };
    ui.practiceFeedback[exerciseId] = { correct };
    persistState();
  }
  renderPractice();
}

function retryExercise(exerciseId, inExam) {
  if (inExam === "true") {
    delete ui.examFeedback[exerciseId];
    if (ui.activeExam?.verified) delete ui.activeExam.verified[exerciseId];
  } else {
    delete ui.practiceFeedback[exerciseId];
  }
  renderPractice();
}

function shuffle(array) {
  const copy = [...array];
  for (let index = copy.length - 1; index > 0; index -= 1) {
    const swap = Math.floor(Math.random() * (index + 1));
    [copy[index], copy[swap]] = [copy[swap], copy[index]];
  }
  return copy;
}

function generateExam() {
  const candidates = getPracticeBaseExercises();
  const pool = candidates.length ? candidates : COURSE_DATA.exercises;
  ui.activeExam = {
    module: ui.practiceModule,
    focus: ui.practiceFocusSection,
    ids: shuffle(pool.map((exercise) => exercise.id)).slice(0, Math.min(5, pool.length)),
    verified: {}
  };
  ui.examFeedback = {};
  renderPractice();
}

function glossaryKey(entry) {
  return entry.term;
}

function glossaryStatus(entry) {
  return state.glossaryProgress[glossaryKey(entry)] || "new";
}

function setGlossaryStatus(entry, status) {
  state.glossaryProgress[glossaryKey(entry)] = status;
  persistState();
}

function filteredGlossaryEntries() {
  const term = ui.glossarySearch.toLowerCase().trim();
  return COURSE_DATA.glossary.filter((entry) => {
    const originModule = entry.origin?.moduleId || "unknown";
    const status = glossaryStatus(entry);
    const matchesSearch = !term || `${entry.term} ${entry.definition} ${entry.example || ""}`.toLowerCase().includes(term);
    const matchesModule = ui.glossaryModule === "all" || originModule === ui.glossaryModule;
    const matchesStatus = ui.glossaryStatus === "all" || status === ui.glossaryStatus;
    return matchesSearch && matchesModule && matchesStatus;
  });
}

function populateGlossaryModuleFilter() {
  const select = $("#glossaryModuleFilter");
  select.innerHTML = `<option value="all">Todos los capítulos</option>${COURSE_DATA.modules.map((module) =>
    `<option value="${module.id}">${escapeHtml(module.number)}</option>`
  ).join("")}`;
  select.value = ui.glossaryModule;
  $("#glossaryStatusFilter").value = ui.glossaryStatus;
}

function sourceOriginHtml(entry) {
  if (!entry.origin) return `Glosario complementario · p. ${entry.glossaryPage}`;
  return `
    Glosario complementario · p. ${entry.glossaryPage} · Primera mención:
    <button type="button" data-go-section="${entry.origin.sectionId}">${escapeHtml(moduleById.get(entry.origin.moduleId).number)} · ${escapeHtml(entry.origin.sectionTitle)}, p. ${entry.origin.page}</button>`;
}

function renderGlossaryCard(entry, index) {
  const status = glossaryStatus(entry);
  const translation = state.translations[`glossary:${entry.term}`];
  return `
    <article class="glossary-card" data-glossary-index="${index}">
      <h3>${escapeHtml(entry.term)}</h3>
      <p class="entry-translation">${translation ? `ES: ${escapeHtml(translation)}` : "ES: traducción disponible al configurar la API"}</p>
      <p class="entry-definition">${escapeHtml(entry.definition)}</p>
      <p class="entry-source">${sourceOriginHtml(entry)}</p>
      <div class="entry-actions">
        <button type="button" class="small-action" data-gloss-action="translate" data-glossary-index="${index}">Traducir</button>
        <button type="button" class="small-action" data-gloss-action="pronounce" data-glossary-index="${index}">Escuchar</button>
        <button type="button" class="small-action ${status === "learned" ? "is-learned" : ""}" data-gloss-action="learned" data-glossary-index="${index}">
          ${status === "learned" ? "✓ Aprendida" : "Marcar aprendida"}
        </button>
        <button type="button" class="small-action ${status === "review" ? "is-review" : ""}" data-gloss-action="review" data-glossary-index="${index}">
          ${status === "review" ? "↻ En repaso" : "Repasar después"}
        </button>
      </div>
      ${entry.example ? `
        <details class="example-details">
          <summary>Ver uso original en el libro</summary>
          <p>${escapeHtml(entry.example)}</p>
        </details>` : ""}
    </article>`;
}

function renderGlossaryStats() {
  const learned = COURSE_DATA.glossary.filter((entry) => glossaryStatus(entry) === "learned").length;
  const review = COURSE_DATA.glossary.filter((entry) => glossaryStatus(entry) === "review").length;
  $("#glossaryStats").innerHTML = `
    <div class="glossary-stat"><strong>${COURSE_DATA.glossary.length}</strong><small>Términos</small></div>
    <div class="glossary-stat"><strong>${learned}</strong><small>Aprendidas</small></div>
    <div class="glossary-stat"><strong>${review}</strong><small>En repaso</small></div>`;
}

function renderGlossaryEntries() {
  populateGlossaryModuleFilter();
  $("#glossarySearch").value = ui.glossarySearch;
  const list = filteredGlossaryEntries();
  $("#glossaryList").innerHTML = list.length
    ? list.map((entry) => renderGlossaryCard(entry, COURSE_DATA.glossary.indexOf(entry))).join("")
    : `<div class="empty-state">No hay entradas que coincidan con estos filtros.</div>`;
}

function getFlashEntries() {
  const entries = filteredGlossaryEntries();
  if (!ui.flashOrder.length || ui.flashOrder.some((term) => !entries.some((entry) => entry.term === term))) {
    ui.flashOrder = entries.map((entry) => entry.term);
    ui.flashIndex = 0;
  }
  return ui.flashOrder.map((term) => entries.find((entry) => entry.term === term)).filter(Boolean);
}

function renderFlashcard() {
  const entries = getFlashEntries();
  $("#flashcardCount").textContent = entries.length ? `Tarjeta ${(ui.flashIndex % entries.length) + 1} de ${entries.length}` : "Sin tarjetas para estos filtros";
  if (!entries.length) {
    $("#flashcardStage").innerHTML = `<div class="empty-state">Ajusta los filtros de entradas para crear tarjetas.</div>`;
    return;
  }
  const entry = entries[ui.flashIndex % entries.length];
  const translation = state.translations[`glossary:${entry.term}`];
  const answer = ui.flashRevealed ? `
    <div class="flashcard-answer">
      <p><strong>Definición original:</strong> ${escapeHtml(entry.definition)}</p>
      <p><strong>Español:</strong> ${translation ? escapeHtml(translation) : "Sin traducción local. Usa “Traducir término” tras configurar la API."}</p>
    </div>` : `<p class="flash-hint">Intenta recordar la definición o traducción antes de revelar la respuesta.</p>`;

  $("#flashcardStage").innerHTML = `
    <article class="flashcard">
      <div>
        <p class="eyebrow">TÉRMINO EN INGLÉS</p>
        <h3 class="flash-term">${escapeHtml(entry.term)}</h3>
      </div>
      <div>${answer}</div>
      <div class="flashcard-actions">
        ${ui.flashRevealed
          ? `<button type="button" class="secondary-button" data-flash-action="translate">Traducir término</button>
             <button type="button" class="primary-button" data-flash-action="learned">La sé</button>
             <button type="button" class="secondary-button" data-flash-action="review">Necesito repasar</button>
             <button type="button" class="secondary-button" data-flash-action="pending">No la sé</button>`
          : `<button type="button" class="primary-button" data-flash-action="reveal">Revelar definición</button>
             <button type="button" class="secondary-button" data-flash-action="pronounce">Escuchar</button>`}
      </div>
    </article>`;
}

function populatePersonalSectionFilter() {
  const select = $("#personalWordsSectionFilter");
  select.innerHTML = `<option value="all">Todas las secciones</option>${COURSE_DATA.sections.map((section) =>
    `<option value="${section.id}">${escapeHtml(moduleById.get(section.moduleId).number)} · ${escapeHtml(section.title)}</option>`
  ).join("")}`;
  select.value = ui.personalSectionFilter;
}

function personalWordStatus(word) {
  return state.glossaryProgress[`personal:${word.id}`] || "new";
}

function renderPersonalWords() {
  populatePersonalSectionFilter();
  let words = [...state.personalWords];
  if (ui.personalSectionFilter !== "all") words = words.filter((word) => word.sectionId === ui.personalSectionFilter);
  $("#personalWordsList").innerHTML = words.length ? words.map((word) => {
    const translation = state.translations[`personal:${word.id}`];
    const status = personalWordStatus(word);
    return `
      <article class="glossary-card">
        <h3>${escapeHtml(word.text)}</h3>
        <p class="entry-translation">${translation ? `ES: ${escapeHtml(translation)}` : "ES: traducción disponible al configurar la API"}</p>
        <p class="entry-definition">Fragmento guardado desde la sección de lectura.</p>
        <p class="entry-source">Origen: <button type="button" data-go-section="${word.sectionId}">${escapeHtml(sectionName(word.sectionId))}</button></p>
        <div class="entry-actions">
          <button type="button" class="small-action" data-personal-action="translate" data-personal-id="${word.id}">Traducir</button>
          <button type="button" class="small-action" data-personal-action="pronounce" data-personal-id="${word.id}">Escuchar</button>
          <button type="button" class="small-action ${status === "learned" ? "is-learned" : ""}" data-personal-action="learned" data-personal-id="${word.id}">
            ${status === "learned" ? "✓ Aprendida" : "Marcar aprendida"}
          </button>
          <button type="button" class="small-action ${status === "review" ? "is-review" : ""}" data-personal-action="review" data-personal-id="${word.id}">
            ${status === "review" ? "↻ En repaso" : "Repasar después"}
          </button>
          <button type="button" class="small-action" data-personal-action="delete" data-personal-id="${word.id}">Eliminar</button>
        </div>
      </article>`;
  }).join("") : `<div class="empty-state">No hay palabras o fragmentos guardados para este filtro.</div>`;
}

function renderGlossary() {
  renderGlossaryStats();
  if (ui.glossaryMode === "entries") renderGlossaryEntries();
  if (ui.glossaryMode === "flashcards") renderFlashcard();
  if (ui.glossaryMode === "personal") renderPersonalWords();
}

function cacheTranslation(cacheKey, translation) {
  state.translations[cacheKey] = translation;
  persistState();
}

async function requestTranslation(text) {
  if (!TRANSLATION_CONFIG.TRANSLATION_API_URL) {
    return {
      translatedText: "",
      mode: "fallback",
      message: "Modo de prueba: no hay una API de traducción configurada. El texto original se mantiene sin alteraciones. Configura TRANSLATION_API_URL con un proxy propio para obtener la traducción al español."
    };
  }
  try {
    const headers = { "Content-Type": "application/json" };
    if (TRANSLATION_CONFIG.API_KEY) headers.Authorization = `Bearer ${TRANSLATION_CONFIG.API_KEY}`;
    const response = await fetch(TRANSLATION_CONFIG.TRANSLATION_API_URL, {
      method: "POST",
      headers,
      body: JSON.stringify({
        q: text,
        source: TRANSLATION_CONFIG.SOURCE_LANGUAGE,
        target: TRANSLATION_CONFIG.TARGET_LANGUAGE,
        format: "text"
      })
    });
    if (!response.ok) throw new Error(`Translation request failed (${response.status})`);
    const data = await response.json();
    const translatedText = data.translatedText || data.translation || data.data?.translations?.[0]?.translatedText;
    if (!translatedText) throw new Error("The translation response did not contain a recognized translated text field.");
    return { translatedText, mode: "api", message: "Traducción obtenida desde la API configurada." };
  } catch (error) {
    return {
      translatedText: "",
      mode: "fallback",
      message: `No se pudo obtener la traducción configurada. Modo de prueba activo. ${error.message}`
    };
  }
}

async function openTranslationDialog(text) {
  const dialog = $("#translationDialog");
  $("#translationOriginal").textContent = text;
  $("#translationResult").textContent = "Preparando traducción…";
  $("#translationStatus").textContent = "";
  if (typeof dialog.showModal === "function") dialog.showModal();
  const result = await requestTranslation(text);
  $("#translationResult").textContent = result.translatedText || "No se generó una traducción. El modo de prueba conserva el original.";
  $("#translationStatus").textContent = result.message;
}

async function translateGlossaryEntry(entry, cacheKey) {
  const result = await requestTranslation(entry.term);
  if (result.translatedText) {
    cacheTranslation(cacheKey, result.translatedText);
    showToast("Traducción guardada para esta sesión local.", "success");
  } else {
    showToast("No hay API de traducción configurada. Revisa README.md.", "warning");
  }
  renderGlossary();
}

function speak(text) {
  if (!("speechSynthesis" in window)) {
    showToast("Tu navegador no ofrece síntesis de voz.", "warning");
    return;
  }
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = "en-US";
  utterance.rate = 0.9;
  window.speechSynthesis.speak(utterance);
}

async function copyText(text) {
  try {
    await navigator.clipboard.writeText(text);
    showToast("Texto copiado.", "success");
  } catch {
    const helper = document.createElement("textarea");
    helper.value = text;
    helper.style.position = "fixed";
    helper.style.opacity = "0";
    document.body.appendChild(helper);
    helper.select();
    document.execCommand("copy");
    helper.remove();
    showToast("Texto copiado.", "success");
  }
}

function showSelectionToolbar() {
  const selection = window.getSelection();
  const text = normalizeText(selection?.toString());
  if (!text || text.length > 3000) {
    $("#selectionToolbar").hidden = true;
    return;
  }
  const range = selection.getRangeAt?.(0);
  if (!range || !$("#readerContent").contains(range.commonAncestorContainer)) {
    $("#selectionToolbar").hidden = true;
    return;
  }
  const rect = range.getBoundingClientRect();
  ui.pendingSelection = { text, sectionId: ui.currentSection };
  const toolbar = $("#selectionToolbar");
  toolbar.hidden = false;
  const maxLeft = window.innerWidth - toolbar.offsetWidth - 8;
  toolbar.style.left = `${Math.max(8, Math.min(rect.left, maxLeft))}px`;
  toolbar.style.top = `${Math.max(8, rect.top - toolbar.offsetHeight - 8)}px`;
}

function hideSelectionToolbar() {
  $("#selectionToolbar").hidden = true;
}

function addSelectionToPersonalGlossary() {
  const selected = ui.pendingSelection;
  if (!selected?.text) return;
  const duplicate = state.personalWords.some((word) => word.text === selected.text && word.sectionId === selected.sectionId);
  if (!duplicate) {
    state.personalWords.unshift({
      id: `word-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      text: selected.text,
      sectionId: selected.sectionId,
      createdAt: Date.now()
    });
    persistState();
    showToast("Guardado en Mis palabras.", "success");
  } else {
    showToast("Ese texto ya está guardado en esta sección.");
  }
}

function highlightSelectedText() {
  const selected = ui.pendingSelection;
  if (!selected?.text) return;
  const exists = state.highlights.some((item) => item.sectionId === selected.sectionId && item.text === selected.text);
  if (!exists) {
    state.highlights.push({ id: `highlight-${Date.now()}`, sectionId: selected.sectionId, text: selected.text });
    persistState();
    renderReader();
    showToast("Texto resaltado.", "success");
  } else {
    showToast("Ese texto ya estaba resaltado.");
  }
}

function showToast(message, tone = "") {
  const region = $("#toastRegion");
  const toast = document.createElement("div");
  toast.className = `toast ${tone}`.trim();
  toast.textContent = message;
  region.appendChild(toast);
  window.setTimeout(() => toast.remove(), 3300);
}

function updateTheme() {
  document.body.dataset.theme = state.theme === "dark" ? "dark" : "light";
}

function updateFontSize() {
  document.documentElement.style.setProperty("--font-size", `${Math.max(15, Math.min(24, Number(state.fontSize || 18)))}px`);
}

function updateReadingProgressFromScroll() {
  const section = sectionById.get(ui.currentSection);
  if (!section || ui.activeView !== "bookView" || ui.bookMode !== "read") return;
  const scrollable = document.documentElement.scrollHeight - window.innerHeight;
  if (scrollable <= 0) return;
  const pagePosition = window.scrollY + window.innerHeight;
  const reader = $(".reader-paper");
  if (!reader) return;
  const top = reader.getBoundingClientRect().top + window.scrollY;
  const bottom = top + reader.offsetHeight;
  if (pagePosition < top || window.scrollY > bottom) return;
  const ratio = Math.max(0, Math.min(0.95, (pagePosition - top) / Math.max(1, bottom - top)));
  if (ratio > getSectionProgress(section.id)) {
    state.readProgress[section.id] = ratio;
    persistState();
    updateProgressUi();
  }
}

function renderSearchResults(query) {
  const container = $("#searchResults");
  const term = normalizeText(query).toLowerCase();
  if (term.length < 2) {
    container.innerHTML = "";
    return;
  }
  const results = COURSE_DATA.sections
    .map((section) => {
      const content = normalizeText(section.pages.map((page) => page.text).join(" "));
      const position = content.toLowerCase().indexOf(term);
      return position >= 0 ? { section, snippet: content.slice(Math.max(0, position - 80), position + term.length + 120) } : null;
    })
    .filter(Boolean)
    .slice(0, 8);

  container.innerHTML = results.length ? results.map(({ section, snippet }) => `
    <button type="button" class="search-result" data-search-section="${section.id}">
      <strong>${escapeHtml(moduleById.get(section.moduleId).number)} · ${escapeHtml(section.title)}</strong>
      <small>${escapeHtml(snippet)}…</small>
    </button>
  `).join("") : `<div class="search-result">No se encontraron coincidencias.</div>`;
}

function closeMobileSidebar() {
  $("#sidebar").classList.remove("is-open");
  $("#mobileMenuButton").setAttribute("aria-expanded", "false");
}

function toggleMobileSidebar() {
  const sidebar = $("#sidebar");
  sidebar.classList.toggle("is-open");
  $("#mobileMenuButton").setAttribute("aria-expanded", String(sidebar.classList.contains("is-open")));
}

function handleGlossaryAction(button) {
  const index = Number(button.dataset.glossaryIndex);
  const entry = COURSE_DATA.glossary[index];
  if (!entry) return;
  const action = button.dataset.glossAction;
  if (action === "translate") translateGlossaryEntry(entry, `glossary:${entry.term}`);
  if (action === "pronounce") speak(entry.term);
  if (action === "learned") {
    setGlossaryStatus(entry, glossaryStatus(entry) === "learned" ? "new" : "learned");
    renderGlossary();
  }
  if (action === "review") {
    setGlossaryStatus(entry, glossaryStatus(entry) === "review" ? "new" : "review");
    renderGlossary();
  }
}

function handlePersonalAction(button) {
  const word = state.personalWords.find((item) => item.id === button.dataset.personalId);
  if (!word) return;
  const action = button.dataset.personalAction;
  const key = `personal:${word.id}`;
  if (action === "translate") {
    requestTranslation(word.text).then((result) => {
      if (result.translatedText) {
        cacheTranslation(key, result.translatedText);
        showToast("Traducción guardada.", "success");
      } else {
        showToast("No hay API de traducción configurada. Revisa README.md.", "warning");
      }
      renderPersonalWords();
    });
  }
  if (action === "pronounce") speak(word.text);
  if (action === "learned") {
    state.glossaryProgress[key] = personalWordStatus(word) === "learned" ? "new" : "learned";
    persistState();
    renderPersonalWords();
  }
  if (action === "review") {
    state.glossaryProgress[key] = personalWordStatus(word) === "review" ? "new" : "review";
    persistState();
    renderPersonalWords();
  }
  if (action === "delete") {
    state.personalWords = state.personalWords.filter((item) => item.id !== word.id);
    delete state.translations[key];
    delete state.glossaryProgress[key];
    persistState();
    renderPersonalWords();
    showToast("Palabra eliminada.");
  }
}

function handleFlashAction(action) {
  const entries = getFlashEntries();
  const entry = entries[ui.flashIndex % entries.length];
  if (!entry) return;
  if (action === "reveal") {
    ui.flashRevealed = true;
  } else if (action === "pronounce") {
    speak(entry.term);
  } else if (action === "translate") {
    translateGlossaryEntry(entry, `glossary:${entry.term}`);
    return;
  } else {
    setGlossaryStatus(entry, action);
    ui.flashRevealed = false;
    ui.flashIndex = (ui.flashIndex + 1) % Math.max(1, entries.length);
  }
  renderGlossary();
}

function bindEvents() {
  $("#bookNav").addEventListener("click", (event) => {
    const sectionButton = event.target.closest("[data-section-id]");
    if (sectionButton) setCurrentSection(sectionButton.dataset.sectionId);
    const moduleButton = event.target.closest("[data-module-nav]");
    if (moduleButton && !sectionButton) {
      const first = COURSE_DATA.sections.find((section) => section.moduleId === moduleButton.dataset.moduleNav);
      if (first) setCurrentSection(first.id);
    }
  });

  $$(".nav-tab").forEach((button) => {
    button.addEventListener("click", () => showView(button.dataset.viewTarget));
  });

  $$(".subnav-button[data-book-mode]").forEach((button) => {
    button.addEventListener("click", () => setBookMode(button.dataset.bookMode));
  });
  $$(".subnav-button[data-glossary-mode]").forEach((button) => {
    button.addEventListener("click", () => setGlossaryMode(button.dataset.glossaryMode));
  });

  $("#markStudiedButton").addEventListener("click", markCurrentSectionStudied);
  $("#favoriteSectionButton").addEventListener("click", toggleCurrentFavorite);
  $("#addNoteButton").addEventListener("click", () => openNoteDialog());
  $("#addNoteInlineButton").addEventListener("click", () => openNoteDialog());
  $("#showSectionWordsButton").addEventListener("click", () => {
    ui.personalSectionFilter = ui.currentSection;
    showView("glossaryView");
    setGlossaryMode("personal");
  });
  $("#reviewSectionExercisesButton").addEventListener("click", () => openPracticeForSection(ui.currentSection));

  $("#notesList").addEventListener("click", (event) => {
    const button = event.target.closest("[data-note-action]");
    if (!button) return;
    if (button.dataset.noteAction === "edit") openNoteDialog(button.dataset.noteId);
    if (button.dataset.noteAction === "delete") deleteNote(button.dataset.noteId);
  });

  $("#noteForm").addEventListener("submit", (event) => {
    event.preventDefault();
    saveNote();
  });
  $("#cancelNoteButton").addEventListener("click", () => $("#noteDialog").close());
  $("#closeNoteDialogButton").addEventListener("click", () => $("#noteDialog").close());

  $("#practiceModuleFilter").addEventListener("change", (event) => {
    ui.practiceModule = event.target.value;
    ui.practiceFocusSection = null;
    ui.activeExam = null;
    ui.examFeedback = {};
    renderPractice();
  });
  $$(".level-tab").forEach((button) => {
    button.addEventListener("click", () => {
      ui.practiceLevel = button.dataset.practiceLevel;
      ui.activeExam = null;
      ui.examFeedback = {};
      ui.practiceFeedback = {};
      renderPractice();
    });
  });
  $("#practiceList").addEventListener("click", (event) => {
    const actionButton = event.target.closest("[data-exercise-action]");
    if (actionButton) {
      const inExam = actionButton.dataset.inExam;
      if (actionButton.dataset.exerciseAction === "verify") verifyExercise(actionButton.dataset.exerciseId, inExam);
      if (actionButton.dataset.exerciseAction === "retry") retryExercise(actionButton.dataset.exerciseId, inExam);
      return;
    }
    const practiceAction = event.target.closest("[data-practice-action]");
    if (practiceAction?.dataset.practiceAction === "generate-exam") {
      generateExam();
      return;
    }
    const sourceButton = event.target.closest("[data-go-section]");
    if (sourceButton) setCurrentSection(sourceButton.dataset.goSection);
  });

  $("#glossarySearch").addEventListener("input", (event) => {
    ui.glossarySearch = event.target.value;
    ui.flashOrder = [];
    renderGlossaryEntries();
  });
  $("#glossaryModuleFilter").addEventListener("change", (event) => {
    ui.glossaryModule = event.target.value;
    ui.flashOrder = [];
    renderGlossary();
  });
  $("#glossaryStatusFilter").addEventListener("change", (event) => {
    ui.glossaryStatus = event.target.value;
    ui.flashOrder = [];
    renderGlossary();
  });
  $("#glossaryList").addEventListener("click", (event) => {
    const button = event.target.closest("[data-gloss-action]");
    if (button) {
      handleGlossaryAction(button);
      return;
    }
    const sourceButton = event.target.closest("[data-go-section]");
    if (sourceButton) setCurrentSection(sourceButton.dataset.goSection);
  });

  $("#shuffleFlashcardsButton").addEventListener("click", () => {
    ui.flashOrder = shuffle(getFlashEntries().map((entry) => entry.term));
    ui.flashIndex = 0;
    ui.flashRevealed = false;
    renderGlossary();
  });
  $("#flashcardStage").addEventListener("click", (event) => {
    const button = event.target.closest("[data-flash-action]");
    if (button) handleFlashAction(button.dataset.flashAction);
  });

  $("#personalWordsSectionFilter").addEventListener("change", (event) => {
    ui.personalSectionFilter = event.target.value;
    renderPersonalWords();
  });
  $("#personalWordsList").addEventListener("click", (event) => {
    const button = event.target.closest("[data-personal-action]");
    if (button) {
      handlePersonalAction(button);
      return;
    }
    const sourceButton = event.target.closest("[data-go-section]");
    if (sourceButton) setCurrentSection(sourceButton.dataset.goSection);
  });

  $("#globalSearch").addEventListener("input", (event) => renderSearchResults(event.target.value));
  $("#globalSearch").addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      const first = $("[data-search-section]", $("#searchResults"));
      if (first) setCurrentSection(first.dataset.searchSection);
    }
    if (event.key === "Escape") $("#searchResults").innerHTML = "";
  });
  $("#searchResults").addEventListener("click", (event) => {
    const button = event.target.closest("[data-search-section]");
    if (button) setCurrentSection(button.dataset.searchSection);
  });

  $("#readerContent").addEventListener("mouseup", () => window.setTimeout(showSelectionToolbar, 0));
  $("#readerContent").addEventListener("touchend", () => window.setTimeout(showSelectionToolbar, 0));
  $("#selectionToolbar").addEventListener("click", (event) => {
    const button = event.target.closest("[data-selection-action]");
    if (!button || !ui.pendingSelection) return;
    const action = button.dataset.selectionAction;
    const text = ui.pendingSelection.text;
    if (action === "translate") openTranslationDialog(text);
    if (action === "glossary") addSelectionToPersonalGlossary();
    if (action === "listen") speak(text);
    if (action === "highlight") highlightSelectedText();
    if (action === "copy") copyText(text);
    hideSelectionToolbar();
    window.getSelection()?.removeAllRanges();
  });
  document.addEventListener("mousedown", (event) => {
    if (!$("#selectionToolbar").contains(event.target)) hideSelectionToolbar();
  });

  $("#increaseFontButton").addEventListener("click", () => {
    state.fontSize = Math.min(24, Number(state.fontSize || 18) + 1);
    persistState();
    updateFontSize();
  });
  $("#decreaseFontButton").addEventListener("click", () => {
    state.fontSize = Math.max(15, Number(state.fontSize || 18) - 1);
    persistState();
    updateFontSize();
  });
  $("#themeButton").addEventListener("click", () => {
    state.theme = state.theme === "dark" ? "light" : "dark";
    persistState();
    updateTheme();
  });

  $("#continueButton").addEventListener("click", () => setCurrentSection(state.lastSection || "m1-overview"));
  $("#clearDataButton").addEventListener("click", () => {
    if (window.confirm("¿Restablecer progreso, notas, resaltados y respuestas guardadas solo en este navegador?")) {
      localStorage.removeItem(STORAGE_KEY);
      state = structuredClone(DEFAULT_STATE);
      ui.currentSection = "m1-overview";
      ui.practiceFeedback = {};
      ui.activeExam = null;
      ui.examFeedback = {};
      ui.flashOrder = [];
      updateTheme();
      updateFontSize();
      renderBookNav();
      renderReader();
      renderGlossary();
      showToast("Datos locales restablecidos.");
    }
  });
  $("#mobileMenuButton").addEventListener("click", toggleMobileSidebar);
  $("#sourceCoverageButton").addEventListener("click", () => $("#coverageDialog").showModal());

  window.addEventListener("scroll", updateReadingProgressFromScroll, { passive: true });
  window.addEventListener("resize", hideSelectionToolbar);
}

function initialize() {
  updateTheme();
  updateFontSize();
  renderBookNav();
  renderReader();
  renderPractice();
  renderGlossary();
  bindEvents();
}

initialize();
